-- Poems batch 276
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('ffc40eb9-f3ca-423f-b157-9afb66124b6a','再次前韻呈吳天遊居士','丘葵','宋','宋诗','song-poetry','','[]','心在江湖身在城，暫分禪座覺神清。',64,'全唐诗/poet.song.244000.json','["心在江湖身在城，暫分禪座覺神清。", "秋深竹葉敲窗響，晝靜蕉花照眼明。", "吟罷燈前窺佛偈，夢回枕上數鐘聲。", "未能參透龐居士，安得師門掉臂行。"]'),
('b0b31dfe-7ad2-4307-8fb7-5162394ac0a4','呂所盤以詩送茅柴酒與紅螺用韻以謝','丘葵','宋','宋诗','song-poetry','','[]','玉液新篘徹底清，瓊肌脫殻有餘馨。',64,'全唐诗/poet.song.244000.json','["玉液新篘徹底清，瓊肌脫殻有餘馨。", "嗜茶枉自爲搜攪，食蛤空憐有典刑。", "脈脈客愁閒白晝，紛紛雨脚下青冥。", "此時一領仙家味，應使靈均悔獨醒。"]'),
('d2f147ee-b1c0-4e75-b785-afb7791b5470','與汝翔池頭清坐','丘葵','宋','宋诗','song-poetry','','[]','主人發興在林泉，故鑿方池翠竹邊。',64,'全唐诗/poet.song.244000.json','["主人發興在林泉，故鑿方池翠竹邊。", "波動日光翻素壁，水涵雲影倒青天。", "蛙浮成字出復出，鳬沒有紋圓又圓。", "却意盤翁初到此，共看楊柳碧絲懸。"]'),
('8e87343b-b8ca-4798-ab12-ef3de73913f8','自湖尾至歐崎村一丘松竹步入其間乃白蓮堂有一老嫗揖客而坐道人云此師長娘也堂前有兩樹梅青腴可愛徘徊久之不覺日暮','丘葵','宋','宋诗','song-poetry','','[]','笑踏冬晴過一村，誰家松竹護柴門。',64,'全唐诗/poet.song.244000.json','["笑踏冬晴過一村，誰家松竹護柴門。", "初來猶似行婆室，良久方知鹿苑園。", "煮茗相邀論白業，據梧不覺到黄昏。", "娟娟梅樹梢頭月，不待開花已斷魂。"]'),
('2569de2f-6c25-4861-b9c9-c46b134196de','夜卧中庭','丘葵','宋','宋诗','song-poetry','','[]','一榻清風不用錢，卧看萬里泬寥天。',64,'全唐诗/poet.song.244000.json','["一榻清風不用錢，卧看萬里泬寥天。", "明星落落纔數十，孤月亭亭照大千。", "但見衣襟如潑水，不知身世是何年。", "可憐玉兔空辛苦，搗藥終宵那得眠。"]'),
('95079d1e-7b4b-4072-8be0-d09de1944890','和所盤風字韻','丘葵','宋','宋诗','song-poetry','','[]','二十四番花信風，到頭誰白又誰紅。',64,'全唐诗/poet.song.244000.json','["二十四番花信風，到頭誰白又誰紅。", "尋春不用苦多感，有酒且須時一中。", "吾輩於人長落落，浮生雖夢亦匆匆。", "未知今歲滄浯上，握手論心幾度同。"]'),
('6e15ae60-d4b2-4eea-aaa1-b476d8a6100c','懷玉巖先生謫廣州忽自古杭有書至','丘葵','宋','宋诗','song-poetry','','[]','十二年前舊師友，書來欲拆淚成行。',64,'全唐诗/poet.song.244000.json','["十二年前舊師友，書來欲拆淚成行。", "幾回相憶人千里，往事追思夢一場。", "琴劍知辭南國久，干戈尚任北方强。", "傷心吾道秋容冷，遥憶師門數仞牆。"]'),
('05a83eea-6023-40a8-9163-ff9fac4a5217','與所盤諸君會石幡還和杜老曲江韻  其一','丘葵','宋','宋诗','song-poetry','','[]','絮雲初擘未成衣，笑踏青莎橋上歸。',64,'全唐诗/poet.song.244000.json','["絮雲初擘未成衣，笑踏青莎橋上歸。", "詩酒堪過春日永，鶑花却恨海山稀。", "竹間弄笛留人住，麥外遊絲絆鳥飛。", "滿院東風不收拾，山僧何事苦相違。"]'),
('c1cf0c56-000a-4bc6-9c96-a118db1277f0','與所盤諸君會石幡還和杜老曲江韻  其二','丘葵','宋','宋诗','song-poetry','','[]','青禽竹上弄毛衣，飛上簷頭喚不歸。',64,'全唐诗/poet.song.244000.json','["青禽竹上弄毛衣，飛上簷頭喚不歸。", "清景每於詩裏見，羈愁惟到海邊稀。", "僧回古殿山礬落，客散空齋蝙蝠飛。", "獨對青山已惆悵，此情猶是月時違。"]'),
('d156606d-8564-45e4-be8a-2fc62c186423','天陰','丘葵','宋','宋诗','song-poetry','','[]','天陰盡日黯無光，白骨縱縱橫地霜。',64,'全唐诗/poet.song.244000.json','["天陰盡日黯無光，白骨縱縱橫地霜。", "真韃未多多僞韃，拒王不罪罪勤王。", "昔持耒耜今兵革，人食糟糠馬稻粱。", "正似鑊湯無冷處，年三十六死爲長。"]'),
('c2e463d1-65f0-4c73-b765-0b9fa63b1b02','聞吳丞圖漳倅','丘葵','宋','宋诗','song-poetry','','[]','黄屋南巡去不回，乾坤舉目是塵埃。',64,'全唐诗/poet.song.244000.json','["黄屋南巡去不回，乾坤舉目是塵埃。", "風輕山鳥猶啼恨，露重園花亦濺哀。", "隻影獨看西日落，滿城爭喜北人來。", "先生莫爲浮雲動，憂國雙眉皺未開。"]'),
('1552d1dd-b227-4e2f-b075-1fa0c7918bc8','吳丞遠寄和章','丘葵','宋','宋诗','song-poetry','','[]','今古興亡凡幾回，垂芳遺臭等浮埃。',64,'全唐诗/poet.song.244000.json','["今古興亡凡幾回，垂芳遺臭等浮埃。", "蝶飛荒徑趨時樂，燕宿頹梁爲主哀。", "周粟不堪夷叔飽，漢車特載綺園來。", "書生恐被山靈誚，牢把柴門閉不開。"]'),
('d255ae73-1344-4bdd-be9a-c4ac20e701cc','信步','丘葵','宋','宋诗','song-poetry','','[]','榻上殘書已倦攤，幅巾藜杖出柴關。',64,'全唐诗/poet.song.244000.json','["榻上殘書已倦攤，幅巾藜杖出柴關。", "卜居宿鷺眠牛處，覓句殘蘆敗葦間。", "心逐閒雲橫碧落，眼隨飛鳥度青山。", "忽然信步苔磯上，又得漁翁作伴還。"]'),
('68d50901-4d55-44ff-9885-5b1effa79705','西興寺值雨次吳警齋先生韻','丘葵','宋','宋诗','song-poetry','','[]','松風一道作秋聲，閲盡山僧相送迎。',64,'全唐诗/poet.song.244000.json','["松風一道作秋聲，閲盡山僧相送迎。", "佛法西來隨處見，梅花老去爲誰清。", "亦知身是客中客，試問朝來晴未晴。", "一笑大雄山下路，幽人携手每同行。"]'),
('4d1ca142-856b-4e92-ba58-97006a7680d7','七月望日再遊彌陀巖','丘葵','宋','宋诗','song-poetry','','[]','彌陀巖下蒼榕樹，借我今年兩度游。',64,'全唐诗/poet.song.244000.json','["彌陀巖下蒼榕樹，借我今年兩度游。", "客思凄凉無奈老，水光瀲灩最宜秋。", "便思乘興歸滄海，却恨知心遠白鷗。", "日暮强隨年少去，溪山好處盡成愁。"]'),
('8bfbeed3-e9fa-4167-afef-607689c98c45','晚道過鏡山寺借憩未及曙而返','丘葵','宋','宋诗','song-poetry','','[]','晚風殘照岸烏巾，小借禪床憩旅身。',64,'全唐诗/poet.song.244000.json','["晚風殘照岸烏巾，小借禪床憩旅身。", "坐對新花忘故我，行看古月照今人。", "聊爲江畔騎馿客，難會雲間駕鶴賓。", "泡沫風燈成一笑，近來東海又揚塵。"]'),
('3d3004b8-d187-4d7a-b2c4-e034a33d2eb8','九日','丘葵','宋','宋诗','song-poetry','','[]','亂後黄花空滿籬，驚心節序屢推移。',64,'全唐诗/poet.song.244000.json','["亂後黄花空滿籬，驚心節序屢推移。", "微吟聊續潘邠老，一笑難逢杜牧之。", "浮蟻共伴今日醉，食糕空憶太平時。", "牛山淚落龍山宴，付與西風一樣吹。"]'),
('c271eafc-b876-4afb-8553-bcaf9a922c2c','次吳文之韻','丘葵','宋','宋诗','song-poetry','','[]','江湖漫浪兩狂生，別後相思月一庭。',64,'全唐诗/poet.song.244000.json','["江湖漫浪兩狂生，別後相思月一庭。", "期子未來燈是伴，逐貧不去筆無靈。", "詩書東閣頭空白，勢利迷人眼孰青。", "安得世無黄口輩，遍遊天下作蜻蜓。"]'),
('9484815e-f5f0-4cd8-a123-6756ac821ff8','呈梅林顔宗之','丘葵','宋','宋诗','song-poetry','','[]','陽峰一別十餘載，今日南關始見君。',64,'全唐诗/poet.song.244000.json','["陽峰一別十餘載，今日南關始見君。", "龜範馬圖俱寂寂，獸蹄鳥跡正紛紛。", "官名已逸歸郯子，竹紀終須入汲墳。", "造物無情余輩老，後生誰可托斯文。"]'),
('fc084c82-f162-4e0f-82c5-476e03c9238d','江風','丘葵','宋','宋诗','song-poetry','','[]','江風淅淅日將暮，庭葉紛紛天已秋。',64,'全唐诗/poet.song.244000.json','["江風淅淅日將暮，庭葉紛紛天已秋。", "對酒欲消今夕恨，挑燈又動昔年愁。", "月如有意穿窗罅，蟲故移聲近枕頭。", "百感關心不能寐，起開塵匣看吳鈎。"]'),
('3cc5d560-267a-40ad-a0e8-dd06a0f9a4bc','贈浮曦柳秀才','丘葵','宋','宋诗','song-poetry','','[]','家在浮曦江上住，胡爲來此市廛中。',64,'全唐诗/poet.song.244000.json','["家在浮曦江上住，胡爲來此市廛中。", "殘盃冷炙成何味，隻研孤燈盍固窮。", "我本持竿釣魚客，子緣識字入儒宮。", "何當共把絲綸去，明月磯頭坐晚風。"]'),
('5dd124d5-43de-4a03-a16e-0e54e3567a06','讀楚詞','丘葵','宋','宋诗','song-poetry','','[]','鶗鴂一聲天地閉，誰知風月有遺音。',64,'全唐诗/poet.song.244000.json','["鶗鴂一聲天地閉，誰知風月有遺音。", "清醒已脫塵中蛻，枯槁何妨澤畔吟。", "漁父不來湘水闊，重華一去楚雲深。", "青鐙半夜書幃冷，照破三閭萬古心。"]'),
('67e89288-c36e-44c5-bb97-2dd4fbaeb611','讀易徹章呈濠樂主人','丘葵','宋','宋诗','song-poetry','','[]','儂是寒江獨釣人，曾偕樵叟見羲文。',64,'全唐诗/poet.song.244000.json','["儂是寒江獨釣人，曾偕樵叟見羲文。", "當時也似吞三畫，今日翻難說七分。", "萱草不堪瀕外望，梅花豈是野中群。", "解頤一笑明年事，未別先愁日暮雲。"]'),
('4cb10015-5be4-413f-9af8-fe1b9d0843ae','次韻答必大','丘葵','宋','宋诗','song-poetry','','[]','越雪從來招犬吠，平生獨欠是爲師。',64,'全唐诗/poet.song.244000.json','["越雪從來招犬吠，平生獨欠是爲師。", "早知窮達皆天賦，晚覺文章與道虧。", "萬斛客愁吾老矣，一生心事子知之。", "殘盃冷炙成何事，空過人間五十期。"]'),
('f828355b-e46f-41eb-8a83-b1adb262322a','雨後','丘葵','宋','宋诗','song-poetry','','[]','雨後溪虛有斷雲，綠陰擁出絳榴裙。',64,'全唐诗/poet.song.244000.json','["雨後溪虛有斷雲，綠陰擁出絳榴裙。", "一枝强續春餘景，數點初收水上紋。", "今日高堂會賓客，去時此際避官軍。", "人生若得長無事，莫遣匆匆別袂分。"]'),
('fa3b03ec-e769-48df-b0a4-b93aa0203c2c','別濠樂主人','丘葵','宋','宋诗','song-poetry','','[]','客中四月衣猶裌，桐下今年米似金。',64,'全唐诗/poet.song.244000.json','["客中四月衣猶裌，桐下今年米似金。", "惘惘江山歸興動，悠悠歲月主恩深。", "三春已過仍淫雨，百事無緣空苦心。", "五十三年堪一笑，白頭底用覓知音。"]'),
('f30dca5c-bd2c-4ef6-bddd-3bfc15264bd5','次韻寄蘇仲質','丘葵','宋','宋诗','song-poetry','','[]','十年前事付流水，清夢悠悠何處尋。',64,'全唐诗/poet.song.244000.json','["十年前事付流水，清夢悠悠何處尋。", "老去誰憐三獻玉，生來不受四知金。", "窮途頼有陳雷友，大雅應殊鄭衛音。", "俗子紛紛敗人意，何時握手再論心。"]'),
('89b6b5ff-7023-4ade-bad2-cb16ee65d164','呈劉秋圃','丘葵','宋','宋诗','song-poetry','','[]','十年江上理絲綸，此日桐城喜見君。',64,'全唐诗/poet.song.244000.json','["十年江上理絲綸，此日桐城喜見君。", "造化由來窮我輩，俗儒安得與斯文。", "人間腥腐荃俱化，圃內寬閒菊自芬。", "萬里秋天愁不盡，取將風月與誰分。"]'),
('336984bc-e6ee-4cd6-a3c2-559e6ae48c1e','古藤','丘葵','宋','宋诗','song-poetry','','[]','古藤屈曲似龍蛇，飛上梢頭故故遮。',64,'全唐诗/poet.song.244000.json','["古藤屈曲似龍蛇，飛上梢頭故故遮。", "煙密真成一翠幄，風清不入五侯家。", "忽看落葉知秋早，偶坐吟詩到日斜。", "恐有飛仙林杪過，呼童爲我整烏紗。"]'),
('cceaaf2c-2333-4474-b5fc-345dbe3f99e7','與所盤行溪邊有一小屋可愛問之乃爲南山主人盤翁欲買居越日詩來有孟光到老不曉事剛道還山活計非之句用韻以勉之','丘葵','宋','宋诗','song-poetry','','[]','相逢海上不須歸，兩鳥天教一處飛。',64,'全唐诗/poet.song.244000.json','["相逢海上不須歸，兩鳥天教一處飛。", "何必盤中爲子所，苟堪釣處是吾磯。", "主人合讓泉邊屋，吟友來敲月下扉。", "聞道山陽曾好隠，此回休道孟光非。"]'),
('029d6b96-ef4a-40e3-a0a9-941171973c98','寓浯江識老魏秀才  其一','丘葵','宋','宋诗','song-poetry','','[]','衡茅蕭索泣寒蟲，獨自吟詩句未工。',64,'全唐诗/poet.song.244000.json','["衡茅蕭索泣寒蟲，獨自吟詩句未工。", "敗葉能令溝水黑，亂雲不放夕陽紅。", "半生辛苦空儒服，一歲蹉跎又朔風。", "不意窮鄉有奇事，暮年得拜鹿門翁。"]'),
('e5ab7860-66f0-41bf-95a4-2e2a95cd9099','寓浯江識老魏秀才  其二','丘葵','宋','宋诗','song-poetry','','[]','月澹蓬門揜候蟲，窮通何必問天工。',64,'全唐诗/poet.song.244000.json','["月澹蓬門揜候蟲，窮通何必問天工。", "茶烹粟面紛紛白，燈吐花心灼灼紅。", "屢改新吟添硯水，密翻舊稿護窗風。", "相逢莫道龐公老，覽鏡先慙似老翁。"]'),
('15ebf5b8-8488-482a-b4a0-9d5c0e9341da','小春','丘葵','宋','宋诗','song-poetry','','[]','落盡千林秋又冬，慙無生意歲將窮。',64,'全唐诗/poet.song.244000.json','["落盡千林秋又冬，慙無生意歲將窮。", "是誰借得三春力，爲我敷施十月中。", "種種草根含暖氣，鱗鱗水面發和風。", "江梅剩放南枝蕊，欲策陽回第一功。"]'),
('5ed0bfe6-b960-4aad-a0f5-de39e6a5e5f5','梅','丘葵','宋','宋诗','song-poetry','','[]','歷盡風霜不受埃，始知渠是歲寒材。',64,'全唐诗/poet.song.244000.json','["歷盡風霜不受埃，始知渠是歲寒材。", "孤芳獨潔無由俗，百卉爭嬌未敢開。", "江驛傾欹留月伴，雪山凝沍带春來。", "樗翁忘了桂花白，誤道柴桑不詠梅。"]'),
('4127d703-c767-4418-a51a-8b2ad6f92822','和心泉問柳','丘葵','宋','宋诗','song-poetry','','[]','初曉晴曦爲寫真，嫣然一笑換千顰。',64,'全唐诗/poet.song.244000.json','["初曉晴曦爲寫真，嫣然一笑換千顰。", "緣誰青眼終無語，學得黄金不濟貧。", "生怕蠻腰來習舞，取爲蟬翳去瞞人。", "無端飛作漫天絮，撩亂東風祇自塵。"]'),
('0cb687b4-88d9-47f7-8d0c-44f8350d5e01','題心泉所贈李白畫像','丘葵','宋','宋诗','song-poetry','','[]','太白仙人紫綺裘，千年遺像尚風流。',64,'全唐诗/poet.song.244000.json','["太白仙人紫綺裘，千年遺像尚風流。", "狂來踏月共吟詠，醉後呼天與唱酬。", "唐室已無一抔土，潯陽今見幾回秋。", "後身定是青霞老，何日分騎鯨背遊。"]'),
('40ff8f5e-e267-487e-8e44-5d0a47f5be3d','初夏','丘葵','宋','宋诗','song-poetry','','[]','當春一脈生生意，直到如今始潔齊。',64,'全唐诗/poet.song.244000.json','["當春一脈生生意，直到如今始潔齊。", "千樹向榮知靖節，一庭交翠見濂溪。", "柳塘花塢心應懶，葵扇桃笙手自携。", "猶自清和未蒸溽，可人日日竹亭西。"]'),
('4561004b-0721-482b-9301-f1561f7f7022','寓石鐘院作','丘葵','宋','宋诗','song-poetry','','[]','托身蕭寺已踰年，獨掩山門守我元。',64,'全唐诗/poet.song.244000.json','["托身蕭寺已踰年，獨掩山門守我元。", "醉旭一生耽草聖，老叉幾度發詩顛。", "雨中裹飯無嘉客，月下携瓶有老禪。", "自笑五窮挨不去，縛船未了又燒船。"]'),
('093453eb-5f71-4975-88e5-b1d50efec2dd','村學','丘葵','宋','宋诗','song-poetry','','[]','矛頭淅米末途難，活計僧梳刖屨間。',64,'全唐诗/poet.song.244000.json','["矛頭淅米末途難，活計僧梳刖屨間。", "老去歡悰如潑水，向來愚見欲移山。", "身穿犢鼻朝朝冷，眼見蠅頭字字艱。", "扶病來爲村學究，始知窮乏累清閒。"]'),
('ea7e0776-f0ba-4ba5-ab3d-88d14b285414','和呂之壽寄伯章韻','丘葵','宋','宋诗','song-poetry','','[]','一片閒雲自在眠，人依乎地地依天。',64,'全唐诗/poet.song.244000.json','["一片閒雲自在眠，人依乎地地依天。", "六經不朽道吾道，獨學無成年又年。", "鄉里小兒皆富貴，山川大海盡風煙。", "乾坤無著吾儕處，子在禪房我亦禪。"]'),
('6e249b7e-c6c8-4261-aa94-fa3625802325','和張原齋見寄','丘葵','宋','宋诗','song-poetry','','[]','昔磨鐵硯已成空，今掉孤舟作釣翁。',64,'全唐诗/poet.song.244000.json','["昔磨鐵硯已成空，今掉孤舟作釣翁。", "百丈依依牽夜月，一絲裊裊弄秋風。", "夢回牧笛樵歌裏，身寄鷗沙犢草中。", "獨把新詩輕萬戶，故人相問有張公。"]'),
('6bc582d8-fb29-448f-82be-ab13198521b8','東歸擬再訪呂所盤不果所盤有詩因次韻','丘葵','宋','宋诗','song-poetry','','[]','何處啼鵑送落暉，江山信美不如歸。',64,'全唐诗/poet.song.244000.json','["何處啼鵑送落暉，江山信美不如歸。", "子期死矣今安有，元亮來兮昨已非。", "世事悠悠春夢斷，人才落落曉星稀。", "白頭老伴惟君在，安得相隨繞樹飛。"]'),
('e60814c9-b18b-4f56-af6b-161f8bb51849','賞梅分韻得殊字','丘葵','宋','宋诗','song-poetry','','[]','梅是花中先覺者，天才迥與衆芳殊。',64,'全唐诗/poet.song.244000.json','["梅是花中先覺者，天才迥與衆芳殊。", "朔風如鐵爲寒骨，暖日投金作細鬚。", "吐出奇芬春意思，描成疏影月工夫。", "玉容清潤豐腴甚，無限詩人錯道癯。"]'),
('f5db78c5-9d06-4f09-941f-d96f7c60e9ff','破屋','丘葵','宋','宋诗','song-poetry','','[]','數間破屋住陳人，八尺空牀卧病身。',64,'全唐诗/poet.song.244000.json','["數間破屋住陳人，八尺空牀卧病身。", "赤脚婢沽深巷酒，蒼頭奴買對江鱗。", "匣中菱鏡難藏老，階下苔錢不濟貧。", "百念已灰何自苦，邇來喜與孟家鄰。"]'),
('b3843d0d-ae75-455d-a136-e2c6ead70436','晚步','丘葵','宋','宋诗','song-poetry','','[]','片月黄昏挂客愁，杖藜閒過水西頭。',64,'全唐诗/poet.song.244000.json','["片月黄昏挂客愁，杖藜閒過水西頭。", "嬋娟正喜臨清沼，菡萏無端枕碧流。", "入暮江山渾似畫，向南門巷已先秋。", "稻田盡處爲滄海，時見乘風萬斛舟。"]'),
('25999491-802a-4f87-9560-8f77b420414a','次韻徐學正九日','丘葵','宋','宋诗','song-poetry','','[]','秋逢重九亦將闌，換得黄花青草顔。',64,'全唐诗/poet.song.244000.json','["秋逢重九亦將闌，換得黄花青草顔。", "節物只能催我老，人生那得似雲閒。", "有心采菊非知菊，無意看山却見山。", "欲識淵明得真趣，夕陽倦鳥正飛還。"]'),
('6687ad10-d742-4514-81ef-1e7271e540f5','寄題朱推官竹齋','丘葵','宋','宋诗','song-poetry','','[]','萬紫千紅轉眼非，高齋惟與竹相宜。',64,'全唐诗/poet.song.244000.json','["萬紫千紅轉眼非，高齋惟與竹相宜。", "自從出地有清節，直至參天無曲枝。", "六月高標寒凜凜，三冬秀色綠猗猗。", "此君妙處無心得，道在虛中人不知。"]'),
('6004958d-fc88-4041-a3dc-b0482a659d0f','章法院中作','丘葵','宋','宋诗','song-poetry','','[]','一入紫雲深更深，游僧亦喜不相尋。',64,'全唐诗/poet.song.244000.json','["一入紫雲深更深，游僧亦喜不相尋。", "已無塵事敗人意，時有書聲雜梵音。", "浩氣養成天地小，欲心掃盡鬼神欽。", "人生能有幾七十，自愛當如百煉金。"]'),
('70c4614c-2be4-4a5f-a7f3-77a363d415d7','御史馬伯庸與達魯花赤徵幣不出','丘葵','宋','宋诗','song-poetry','','[]','皇帝書徵老秀才，秀才懶下讀書臺。',64,'全唐诗/poet.song.244000.json','["皇帝書徵老秀才，秀才懶下讀書臺。", "張良本爲韓仇出，黄石特因漢祚來。", "太守枉勞階下拜，使臣空向日邊回。", "牀頭一卷春秋筆，斧鉞胸中獨自裁。"]'),
('cb1ad47f-4e63-4e1e-b2a0-b8c59f47a2e8','極目','丘葵','宋','宋诗','song-poetry','','[]','羣形寂無聲，四野澹將夕。',24,'全唐诗/poet.song.244000.json','["羣形寂無聲，四野澹將夕。", "中庭聊極目，一鳥渡空碧。"]'),
('3ce7c448-7e2d-461b-9cb8-23494f6210f5','梅影','丘葵','宋','宋诗','song-poetry','','[]','冷蘂疏疏密密，老枝怪怪奇奇。',28,'全唐诗/poet.song.244000.json','["冷蘂疏疏密密，老枝怪怪奇奇。", "孤高不得春力，雅淡惟應月知。"]'),
('2be3071f-0fa0-4e1c-b32c-520ad1a22ff9','六月初二日作','丘葵','宋','宋诗','song-poetry','','[]','萬古青天萬古山，頹然形氣太虛間。',32,'全唐诗/poet.song.244000.json','["萬古青天萬古山，頹然形氣太虛間。", "氤氳開門無窮妙，只見飛雲日往還。"]'),
('171f5677-8ac8-49ae-8ebc-91585e9cd7d8','客中  其一','丘葵','宋','宋诗','song-poetry','','[]','孤客思家坐似瘖，溪風吹樹爲悲吟。',32,'全唐诗/poet.song.244000.json','["孤客思家坐似瘖，溪風吹樹爲悲吟。", "溪中流水深千尺，未扺慈親憶子心。"]'),
('0820a628-ccc4-4aab-9795-0506b4d0625f','客中  其二','丘葵','宋','宋诗','song-poetry','','[]','曉起征衫瘦漸寬，可堪秋入鬢絲寒。',32,'全唐诗/poet.song.244000.json','["曉起征衫瘦漸寬，可堪秋入鬢絲寒。", "客中萬葉皆歸本，自把牀頭易卷看。"]'),
('7445e73f-33c5-4f84-8e2c-259daf535f79','秋夜前韻','丘葵','宋','宋诗','song-poetry','','[]','觸事嫌猜只一瘖，出門固羨砌蟲吟。',32,'全唐诗/poet.song.244000.json','["觸事嫌猜只一瘖，出門固羨砌蟲吟。", "無情河漢西流去，惟有白雲知此心。"]'),
('70755600-1dd1-477d-9000-1d3b6a5cc053','章法院堂中清坐','丘葵','宋','宋诗','song-poetry','','[]','到此人空法亦空，跏趺獨坐夜方中。',32,'全唐诗/poet.song.244000.json','["到此人空法亦空，跏趺獨坐夜方中。", "清還風去明還月，自己清明只在躬。"]'),
('de0c4b6f-7af6-4a5d-a7ba-b9611e3f773f','鰲山閣','丘葵','宋','宋诗','song-poetry','','[]','閣上南薰聲作秋，俯看木末翠光浮。',32,'全唐诗/poet.song.244000.json','["閣上南薰聲作秋，俯看木末翠光浮。", "倚窗忽見金雞落，滾出前溪一線流。"]'),
('a23af917-a79d-491a-885f-ff9c56dba71e','下洞','丘葵','宋','宋诗','song-poetry','','[]','天香亭下影婆娑，四畔高林結綠蘿。',32,'全唐诗/poet.song.244000.json','["天香亭下影婆娑，四畔高林結綠蘿。", "雲外飛仙不曾見，唯應翠樹閲人多。"]'),
('98913a60-5dcc-46ce-b041-df3af11ac6f7','百丈石','丘葵','宋','宋诗','song-poetry','','[]','北風吹我過崢嶸，片石中間水一泓。',32,'全唐诗/poet.song.244000.json','["北風吹我過崢嶸，片石中間水一泓。", "世事由來總如此，枉教辛苦爲虛名。"]'),
('5b19a661-eb4d-494d-aba0-a9cfd7b5f712','臘月二十九日陳萬石石室呂潜心三兄相訪夜來分韻得年字','丘葵','宋','宋诗','song-poetry','','[]','一年一度一除夜，趲得世人霜滿顛。',32,'全唐诗/poet.song.244000.json','["一年一度一除夜，趲得世人霜滿顛。", "七十三年除過了，未知除盡是何年。"]'),
('e4c9402d-0e1a-42cf-8bf5-ddd6754f5e43','歸憩澗亭橋','丘葵','宋','宋诗','song-poetry','','[]','雨後溪流深更深，倚欄照見一生心。',32,'全唐诗/poet.song.244000.json','["雨後溪流深更深，倚欄照見一生心。", "青山只在橋南北，枉自穿雲渡水尋。"]'),
('64c89f09-6ff6-4b92-8bf0-c8e9a6da3531','溪西李家','丘葵','宋','宋诗','song-poetry','','[]','秧鍼初出未全青，昨夜岡頭冷雨晴。',32,'全唐诗/poet.song.244000.json','["秧鍼初出未全青，昨夜岡頭冷雨晴。", "日暮採樵人去後，一痕淡月亂蛙鳴。"]'),
('a4b00dae-5939-4ca0-aeae-334f4ed0595b','觀湖  其一','丘葵','宋','宋诗','song-poetry','','[]','潮來沙石沒，潮去沙石露。',24,'全唐诗/poet.song.244000.json','["潮來沙石沒，潮去沙石露。", "士生那無學，學則詞章富。"]'),
('f064421f-d951-49ee-876c-cb60a3522a3d','觀湖  其二','丘葵','宋','宋诗','song-poetry','','[]','潮來舴艋正，潮去舴艋欹。',24,'全唐诗/poet.song.244000.json','["潮來舴艋正，潮去舴艋欹。", "士生那無學，學則氣習移。"]'),
('87476b27-ec05-4934-8335-84355931f30c','觀湖  其三','丘葵','宋','宋诗','song-poetry','','[]','潮來魚網設，潮去魚網收。',24,'全唐诗/poet.song.244000.json','["潮來魚網設，潮去魚網收。", "士生那無學，學則德業優。"]'),
('f4324989-ce02-4784-bbfc-b65afd5ba61a','觀湖  其四','丘葵','宋','宋诗','song-poetry','','[]','飛飛洲上禽，亦能戾于天。',24,'全唐诗/poet.song.244000.json','["飛飛洲上禽，亦能戾于天。", "聖域尚能臻，吾車安敢旋。"]'),
('2077dcce-f138-416d-b3ff-da29c10b4172','太陽  其一','丘葵','宋','宋诗','song-poetry','','[]','太陽一入地，亦足蒸成霞。',24,'全唐诗/poet.song.244000.json','["太陽一入地，亦足蒸成霞。", "老學儻能勉，聲績豈不華。"]'),
('ab532802-8ef3-44dc-b8d5-34bcf29721c9','太陽  其二','丘葵','宋','宋诗','song-poetry','','[]','太陽一入地，尚能掣成電。',24,'全唐诗/poet.song.244000.json','["太陽一入地，尚能掣成電。", "老學儻能勉，氣質豈不變。"]'),
('82e69792-3fde-431b-ae84-e690e64f5eea','太陽  其三','丘葵','宋','宋诗','song-poetry','','[]','太陽一入地，照月還生光。',24,'全唐诗/poet.song.244000.json','["太陽一入地，照月還生光。", "老學儻能勉，繕性豈不臧。"]'),
('b0199cd6-aca2-4952-8b0c-edf490ace4e4','太陽  其四','丘葵','宋','宋诗','song-poetry','','[]','太陽一入地，經天返復返。',24,'全唐诗/poet.song.244000.json','["太陽一入地，經天返復返。", "老學儻能勉，去聖豈云遠。"]'),
('a44770ed-e4e8-480a-8d1d-6a394f144938','太陽  其五','丘葵','宋','宋诗','song-poetry','','[]','君子之於學，沒身而後已。',24,'全唐诗/poet.song.244000.json','["君子之於學，沒身而後已。", "苟未至隕越，敢不湛攸止。"]'),
('effde294-723a-4707-af8f-107bb03583e3','石榴花','丘葵','宋','宋诗','song-poetry','','[]','莫峙而匪山，莫流而匪川。',36,'全唐诗/poet.song.244000.json','["莫峙而匪山，莫流而匪川。", "人生有懿德，萬性同此天。", "云胡不自責，聽此六賊牽。"]'),
('7c0bc8f1-c7f0-4a8d-acdb-2cb08117ba21','觀物  其一','丘葵','宋','宋诗','song-poetry','','[]','太虛寂無朕，妙感何絪緼。',48,'全唐诗/poet.song.244000.json','["太虛寂無朕，妙感何絪緼。", "清濁一浮沈，二儀奠乾坤。", "客形與客感，萬變日紛紛。", "形感本來無，志誠諒斯存。"]'),
('32d2f8ce-3fec-4af2-8674-2232b983d9e1','觀物  其二','丘葵','宋','宋诗','song-poetry','','[]','氣聚則明施，氣散則明匿。',48,'全唐诗/poet.song.244000.json','["氣聚則明施，氣散則明匿。", "孰能知其妙，聚散乃爲客。", "法象乃糟糠，真機乃虛寂。", "大哉無方體，是謂神與易。"]'),
('31f6bd69-2ed3-4a83-9b44-8e1c23f5a514','觀物  其三','丘葵','宋','宋诗','song-poetry','','[]','萬物即一物，一物即一身。',48,'全唐诗/poet.song.244000.json','["萬物即一物，一物即一身。", "妙合氣與靈，知覺日以新。", "物物爲過化，性性爲存神。", "踐形者惟肖，其斯之謂人。"]'),
('ba15258e-d94f-4f80-b3cd-58b1cacac27a','觀物  其四','丘葵','宋','宋诗','song-poetry','','[]','春蒲發華滋，潮漲失沙嘴。',48,'全唐诗/poet.song.244000.json','["春蒲發華滋，潮漲失沙嘴。", "好風自西來，吹皺一江水。", "何人掉孤舟，撐入春浦裏。", "不見舟中人，一陣鷗飛起。"]'),
('4bce28d0-6ecc-4c29-a14c-faa64b9e40d5','釣魚','丘葵','宋','宋诗','song-poetry','','[]','釣魚如之何，亦惟釣與絲。',72,'全唐诗/poet.song.244000.json','["釣魚如之何，亦惟釣與絲。", "爲學如之何，亦惟行與知。", "擇善必固執，誠意毋自欺。", "博我復約我，至之而終之。", "先民莫不然，予曷敢有虧。", "但恐寒者至，莊敬以自持。"]'),
('4b69e854-b437-40f7-a4ef-7c01278a1dbb','勉呂之壽','丘葵','宋','宋诗','song-poetry','','[]','汎汎水中舟，有紼以麗維。',84,'全唐诗/poet.song.244000.json','["汎汎水中舟，有紼以麗維。", "蕩蕩人之情，有禮以執持。", "武公年九十，猶思慎其儀。", "吾儕未耄老，盍亦相箴規。", "云胡工誦說，志行乃有虧。", "此病當自省，所差只毫釐。", "勉哉爲己學，先民不我欺。"]'),
('233f0d7b-bd8a-49be-8503-cb3873dc8e2e','雀','丘葵','宋','宋诗','song-poetry','','[]','雀在在屋上，雀在在屋下。',72,'全唐诗/poet.song.244000.json','["雀在在屋上，雀在在屋下。", "喧啾各有聲，食息同晨夜。", "所以異者何，仁義非外假。", "云胡不自養，乃至爲物化。", "嗟余雖老倦，亦少知取舍。", "凜然保厥衷，貴富直土苴。"]'),
('c12907cc-06dd-48b0-b0e8-b383569a2622','怡園先生','丘葵','宋','宋诗','song-poetry','','[]','三朝秉樞要，鉅文飾皇猷。',36,'全唐诗/poet.song.244000.json','["三朝秉樞要，鉅文飾皇猷。", "中原爭一髮，忘却君父讎。", "暮年玉和堂，抱膝空隠憂。"]'),
('4ab6fc20-3d8e-401d-9c50-3216800d0921','閉戶','丘葵','宋','宋诗','song-poetry','','[]','芝蘭豈是爲人香，濁世紛紛貴自藏。',64,'全唐诗/poet.song.244000.json','["芝蘭豈是爲人香，濁世紛紛貴自藏。", "閉戶不求如意事，讀書自得養心方。", "卓然有見如參倚，操則常存勿助忘。", "但使天根常活潑，小園花卉亦相羊。"]'),
('c09e3650-b048-4ccf-8c8a-b151a316329e','養氣','丘葵','宋','宋诗','song-poetry','','[]','養氣須令四體充，饑寒不動是英雄。',64,'全唐诗/poet.song.244000.json','["養氣須令四體充，饑寒不動是英雄。", "常羞仲子徒三咽，稍似顔淵只屢空。", "舉動未嘗爲物碍，精神若可與天通。", "氤氳開闔無窮妙，祇在綿綿一息中。"]'),
('c232843b-ed83-447f-93bf-abdbe0c6f1d8','亦足軒中試墨','丘葵','宋','宋诗','song-poetry','','[]','濴河無復見龍馬，車子鉏商乃獲麟。',64,'全唐诗/poet.song.244000.json','["濴河無復見龍馬，車子鉏商乃獲麟。", "虞夏不存暴易暴，詩書何罪秦又秦。", "古來尚有拏舟者，今世那無伐木人。", "天地閉時應且隠，確乎不拔爲潜鱗。"]'),
('9ef4ee86-c368-49be-a5a1-2c8a01d6801b','理欲','丘葵','宋','宋诗','song-poetry','','[]','理欲分明有兩途，何爲捷徑世爭趨。',64,'全唐诗/poet.song.244000.json','["理欲分明有兩途，何爲捷徑世爭趨。", "豈愁今古無公論，長恨乾坤有腐儒。", "甘與徂徠爲鬼怪，肯猶介甫接浮圖。", "從來逆迪分凶吉，於穆昭昭不可誣。"]'),
('568aa0b7-3ed6-4f52-8e66-52591a549638','六十六歲吟','丘葵','宋','宋诗','song-poetry','','[]','維天於穆命無殊，人性皆由氣與虛。',64,'全唐诗/poet.song.244000.json','["維天於穆命無殊，人性皆由氣與虛。", "貴賤何須爲物役，芳菲祇合返吾初。", "讀書自覺年年誤，學道惟應念念除。", "輔世長民今已矣，某丘某水且樵漁。"]'),
('8a673600-9704-4bc0-880a-a52e9e078a72','次晦庵先生韻自警','丘葵','宋','宋诗','song-poetry','','[]','我非欠缺聖非餘，此性皆由氣與虛。',64,'全唐诗/poet.song.244000.json','["我非欠缺聖非餘，此性皆由氣與虛。", "欲認存亡爲出入，莫嫌粗糲慕膏腴。", "仰鑽未得有門入，酬酢方知講學疏。", "一息猶存毋敢懈，從今要下死工夫。"]'),
('9f31ff0e-d016-4c61-acb2-29f212752196','八十','丘葵','宋','宋诗','song-poetry','','[]','一裘一葛一綸巾，包裹父生師教身。',64,'全唐诗/poet.song.244000.json','["一裘一葛一綸巾，包裹父生師教身。", "不見分毫裨世界，空遺八十有年人。", "老無聞道安可死，間得讀書惟一貧。", "四萬八千毛孔裏，從頭看得總皆仁。"]'),
('9b2450ba-1423-4262-a58a-6d3de5985155','視夜','丘葵','宋','宋诗','song-poetry','','[]','我興視夜夜未明，擡頭觀星敬自生。',64,'全唐诗/poet.song.244000.json','["我興視夜夜未明，擡頭觀星敬自生。", "萬古不動惟北極，列宿環拱俱西傾。", "天光昭回泰宇定，人欲凈盡靈臺清。", "但能勿使旦晝牿，天理觸處盡流行。"]'),
('eac4686b-800f-400d-b2d1-e74fec20d7b9','送春','丘葵','宋','宋诗','song-poetry','','[]','一物生生無盡時，落花啼鳥總天機。',64,'全唐诗/poet.song.244000.json','["一物生生無盡時，落花啼鳥總天機。", "三千界內知音少，九十日餘回首非。", "世事只今看爛熟，詩人自古愛芳菲。", "年年歲歲送春去，何日春能送我歸。"]'),
('9e79247b-43ef-4298-b18d-1123f963a6cd','老學忽有所得','丘葵','宋','宋诗','song-poetry','','[]','刊落閒枝葉，推尋到本根。',24,'全唐诗/poet.song.244000.json','["刊落閒枝葉，推尋到本根。", "始知酬酢處，無地不乾坤。"]'),
('f94f2260-dbb7-46c9-9968-2c512fcfd6c6','記先賢','丘葵','宋','宋诗','song-poetry','','[]','進學在致知，涵養須用敬。',24,'全唐诗/poet.song.244000.json','["進學在致知，涵養須用敬。", "廓然而大公，物來則順應。"]'),
('18c1ff36-c934-415a-84f9-4f20dc306764','觀物  其一','丘葵','宋','宋诗','song-poetry','','[]','雪中梅带春來，火裏麥將秋至。',28,'全唐诗/poet.song.244000.json','["雪中梅带春來，火裏麥將秋至。", "一動一靜互根，陰陽未嘗相離。"]'),
('f407e2ec-4b67-4d7f-8045-1fd808b1ba6c','觀物  其二','丘葵','宋','宋诗','song-poetry','','[]','維天於穆不已，維聖之德之純。',28,'全唐诗/poet.song.244000.json','["維天於穆不已，維聖之德之純。", "人人皆可堯舜，物物各具乾坤。"]'),
('ddd5ac5e-fc7b-443a-aa4b-0745885aca08','暗室','丘葵','宋','宋诗','song-poetry','','[]','一幾善惡未分時，善本無爲莫僞爲。',32,'全唐诗/poet.song.244000.json','["一幾善惡未分時，善本無爲莫僞爲。", "暗室休言人不見，此心纔動鬼神知。"]'),
('70b675c5-ccf2-4c8c-badf-70fc4dc38014','有感','丘葵','宋','宋诗','song-poetry','','[]','萬古有條平坦路，東西南北甚分明。',32,'全唐诗/poet.song.244000.json','["萬古有條平坦路，東西南北甚分明。", "世間多少惺惺漢，盡向荆榛裏面行。"]'),
('dc9eca65-65b2-4a59-8a25-beb23817f9c9','和晦庵啟蒙韻','丘葵','宋','宋诗','song-poetry','','[]','有人見得地中雷，三十六宮從此回。',32,'全唐诗/poet.song.244000.json','["有人見得地中雷，三十六宮從此回。", "盡太虛中俱是易，底須龍馬負圖來。"]'),
('b4f4049a-587d-41d7-92c1-07f90dd1874c','芝山','丘葵','宋','宋诗','song-poetry','','[]','牀頭枕是溪中石，井底泉通竹下池。',32,'全唐诗/poet.song.244000.json','["牀頭枕是溪中石，井底泉通竹下池。", "宿客不還過鳥語，獨聞山雨對花時。"]'),
('2e8fcffb-f822-4554-a332-bc21460b96f2','句','丘葵','宋','宋诗','song-poetry','','[]','萬機分子路，一局笑顔回。',12,'全唐诗/poet.song.244000.json','["萬機分子路，一局笑顔回。"]'),
('2320a6a4-a9e4-45a8-8bfd-149d5d7266ca','句','盤翁','宋','宋诗','song-poetry','','[]','孟光到老不曉事，剛道還山活計非。',16,'全唐诗/poet.song.244000.json','["孟光到老不曉事，剛道還山活計非。"]'),
('ec30176c-4e8b-4211-881e-c8ae64655543','春日田園雜興','劉應龜','宋','宋诗','song-poetry','','[]','獨犬寥寥晝護門，是間也自有桃源。',64,'全唐诗/poet.song.244000.json','["獨犬寥寥晝護門，是間也自有桃源。", "梅藏竹掩無多路，人語雞聲又一村。", "屋角枯藤黏樹活，田頭野水入溪渾。", "我來拾得春風句，分付沙鷗莫浪言。"]'),
('1c1f3734-64f4-4033-98b9-7309867dce20','夏日雜詠','劉應龜','宋','宋诗','song-poetry','','[]','一片閑雲墮野塘，晚風吹浪溼菰蔣。',32,'全唐诗/poet.song.244000.json','["一片閑雲墮野塘，晚風吹浪溼菰蔣。", "白鷗不受人間暑，長向荷花共雨凉。"]'),
('5b65a0a4-545a-4e35-b642-7c4f6ce0324d','悲歌','劉應炎','宋','宋诗','song-poetry','','[]','悲矣乎，杞人之憂兮天莫支，權臣秉鈞兮社稷危。',58,'全唐诗/poet.song.244000.json','["悲矣乎，杞人之憂兮天莫支，權臣秉鈞兮社稷危。", "外夷相侵民流離，大厦將傾誰設施。", "悲矣乎，吾將抱徐衍之石兮，歌箕子之黍離。"]'),
('31dd5e13-1112-4381-bef9-3650f2d07603','笑歌','劉應炎','宋','宋诗','song-poetry','','[]','笑矣乎，冰山之高兮不可恃，炙手之熱兮有時已。',58,'全唐诗/poet.song.244000.json','["笑矣乎，冰山之高兮不可恃，炙手之熱兮有時已。", "幕燕釜魚門如市，歸去來兮尋栗里。", "笑矣乎，孤松可撫菊可餐，浮雲富貴過眼矣。"]'),
('8ddaa9ca-dcf9-4ff1-8630-afe1167588b6','海邊僧寺絕筆','諸葛夢宇','宋','宋诗','song-poetry','','[]','孤臣垂死愈心傷，捲土重來豈望還。',64,'全唐诗/poet.song.244000.json','["孤臣垂死愈心傷，捲土重來豈望還。", "萬里海濤鳴戰鼓，千年靈氣結浮山。", "魚龍亦解齊殊類，犬馬誰教到此間。", "留得御風魂不散，直須號哭叩天關。"]'),
('8f4b3d7c-ba06-443d-96dc-a6241149cfec','宿黄花館','楊發','宋','宋诗','song-poetry','','[]','孤館蕭條槐葉稀，暮蟬聲隔水聲微。',64,'全唐诗/poet.song.244000.json','["孤館蕭條槐葉稀，暮蟬聲隔水聲微。", "年年爲客路無盡，日日送人身未歸。", "何處離鴻迷浦月，誰家愁婦擣霜衣。", "夜深不卧簾猶捲，數點殘螢入戶飛。"]'),
('ee969075-dbea-4a75-9926-e1ee6980579c','春','周垕','宋','宋诗','song-poetry','','[]','不論山顛與水涯，春來何處不榮華。',32,'全唐诗/poet.song.244000.json','["不論山顛與水涯，春來何處不榮華。", "野紅妖綠渾如畫，一崦人家桃杏花。"]'),
('9cf56e74-7660-4d97-bf08-1a7e4cbadce7','挽羅榷院子遠  其一','劉應鳳','宋','宋诗','song-poetry','','[]','共說門庭王謝盛，誰知骨相島郊窮。',64,'全唐诗/poet.song.244000.json','["共說門庭王謝盛，誰知骨相島郊窮。", "躬行自得前賢法，家禮猶還三代風。", "脚跡肯隨權要出，頭銜寧與濁流同。", "湖山寒食多新鬼，地下何顔見此翁。"]'),
('a4f783ae-6dcc-493e-81cb-fb8dd5044c70','挽羅榷院子遠  其二','劉應鳳','宋','宋诗','song-poetry','','[]','國亡何忍家偏活，百鬼欺淩任所遭。',64,'全唐诗/poet.song.244000.json','["國亡何忍家偏活，百鬼欺淩任所遭。", "老大伊川七分易，飄零正則九章騷。", "修持慣習甘辛苦，俯仰難容譽處高。", "日月時同來去異，雲間應歎衆生勞。"]'),
('3c1f515f-f342-4faf-9a0d-45d25cb0be6a','挽羅榷院子遠  其三','劉應鳳','宋','宋诗','song-poetry','','[]','嘗憶東華裹飯時，五千字挾海潮飛。',64,'全唐诗/poet.song.244000.json','["嘗憶東華裹飯時，五千字挾海潮飛。", "臣愚敢避權奸忤，主弱寧知國事非。", "相馬有奇堪下拜，屠龍無用只空歸。", "江南文物侵尋盡，洒淚單傳第一衣。"]'),
('2cc05db0-de0d-4bca-b17a-7e86d7a7e3e5','挽朱梧月','劉應鳳','宋','宋诗','song-poetry','','[]','早歲出山交識廣，晚年閉戶子孫單。',64,'全唐诗/poet.song.244000.json','["早歲出山交識廣，晚年閉戶子孫單。", "酒邊談笑俱成史，病後風騷尚可壇。", "直向九泉尋輩行，肯留百世說艱難。", "江空雲冷衣冠盡，猿鶴羞人指亦彈。"]'),
('1c554d2c-64f5-432d-82d4-3ee2d5a22038','送文總管朝燕  其一','劉應鳳','宋','宋诗','song-poetry','','[]','喚得嵐鄉昨夢回，東風萬里上金臺。',32,'全唐诗/poet.song.244000.json','["喚得嵐鄉昨夢回，東風萬里上金臺。", "出關曾解婆娑否，枝北枝南一種梅。"]'),
('8881ef73-9ced-4b02-8833-8b7cdfc7ecc3','送文總管朝燕  其二','劉應鳳','宋','宋诗','song-poetry','','[]','點檢桑枌淚幾行，羞和書屋總荒凉。',32,'全唐诗/poet.song.244000.json','["點檢桑枌淚幾行，羞和書屋總荒凉。", "孔明景略留遺傳，分挂當年夜雨牀。"]'),
('38ec7c87-acd0-49bf-b3a1-3d861904c2f9','送文總管朝燕  其三','劉應鳳','宋','宋诗','song-poetry','','[]','夾道紅旗駐馬蹄，鄉人將喜又將疑。',32,'全唐诗/poet.song.244000.json','["夾道紅旗駐馬蹄，鄉人將喜又將疑。", "天留中子繼孤竹，誰向西山飯伯夷。"]'),
('40486590-6fe9-4c7a-9479-d8b5bd16279b','送文總管朝燕  其四','劉應鳳','宋','宋诗','song-poetry','','[]','滿眼平疇草自春，烏鴉無數是耘丁。',32,'全唐诗/poet.song.244000.json','["滿眼平疇草自春，烏鴉無數是耘丁。", "鬼神如奉君王問，爲說東南燐火青。"]'),
('9bcbd478-530a-4bd7-91b1-8213d20d01c7','中齋歸自海上見訪','劉應鳳','宋','宋诗','song-poetry','','[]','拂石爲牀席白雲，鯨魚背上有歸人。',64,'全唐诗/poet.song.244000.json','["拂石爲牀席白雲，鯨魚背上有歸人。", "諫書檄草俱成血，野服黄冠再見身。", "麈尾悲酸渾欲死，燈前瀟洒儼如神。", "更闌萬籟收沉盡，地闊天高兩主賓。"]'),
('b03ab943-1661-45bc-af1e-02769a5f12c9','寄青山','劉應鳳','宋','宋诗','song-poetry','','[]','曾誦先生感寓詩，如今似寫我心悲。',64,'全唐诗/poet.song.244000.json','["曾誦先生感寓詩，如今似寫我心悲。", "西施貧處無鹽笑，烏獲饑來豎子朝。", "不士不農焉用彼，無齊無楚竟何之。", "光陰未老人先老，荒草斜陽泣斷碑。"]'),
('e0388ae1-db06-449b-a92d-17dd0931c160','上陳縣尹  其一','劉應李','宋','宋诗','song-poetry','','[]','舊尹龔熊負令名，至今天日共清明。',64,'全唐诗/poet.song.244000.json','["舊尹龔熊負令名，至今天日共清明。", "案頭未有人稱屈，村裏全無吏敢行。", "滿院茶香敲句穩，一簾花影韻琴清。", "後之學者誰其似，又說陳公政有聲。"]'),
('0f0a9abd-39f4-4a5a-a018-d445d48783ad','上陳縣尹  其二','劉應李','宋','宋诗','song-poetry','','[]','溫公宅子富公池，并入堯夫戶不知。',64,'全唐诗/poet.song.244000.json','["溫公宅子富公池，并入堯夫戶不知。", "百畝但添官裏賦，一編惟說橐中詩。", "自憐老去無能役，正恐兒成不了癡。", "有口尚能誇尹在，莫教白髪困行移。"]'),
('ebc4d281-5f2e-46bd-a0d7-38a27460f77a','綿  其一','王夢應','宋','宋诗','song-poetry','','[]','綿綿瓜瓞，施于中林。',20,'全唐诗/poet.song.244000.json','["綿綿瓜瓞，施于中林。", "顧于烝嘗，匪今斯今。"]'),
('c66e07fc-6eff-4328-bca2-96589fb50ef7','綿  其二','王夢應','宋','宋诗','song-poetry','','[]','既庶既繁，既多受祉。',30,'全唐诗/poet.song.244000.json','["既庶既繁，既多受祉。", "厥胤維何，宜兄宜弟。", "兄弟求矣，以燕翼子。"]'),
('7ea8dccd-0d6f-4792-8bcb-e39da0f7a3a0','綿  其三','王夢應','宋','宋诗','song-poetry','','[]','子兮子兮，繼序其皇之。',31,'全唐诗/poet.song.244000.json','["子兮子兮，繼序其皇之。", "螟蛉有子，式穀似之。", "建爾元子，勿替引之。"]'),
('441547ea-4c96-42ad-b6a5-d4c4b2219142','綿  其四','王夢應','宋','宋诗','song-poetry','','[]','穀旦于差，惠于宗公。',30,'全唐诗/poet.song.244000.json','["穀旦于差，惠于宗公。", "工祝致告，神罔時恫。", "是烝是饗，何天之寵。"]'),
('b1fe337b-690d-41c9-be12-bedd8a133d58','綿  其五','王夢應','宋','宋诗','song-poetry','','[]','酒醴維醹，殽核維旅。',30,'全唐诗/poet.song.244000.json','["酒醴維醹，殽核維旅。", "吹笙鼓篁，和樂且孺。", "式序在位，以速諸父。"]'),
('eb9a0122-f5aa-4330-aa74-a17356da13cc','綿  其六','王夢應','宋','宋诗','song-poetry','','[]','天錫公純嘏，洵美且仁。',32,'全唐诗/poet.song.244000.json','["天錫公純嘏，洵美且仁。", "如南山之壽，展也大成。", "從以孫子，繩其祖武。"]'),
('cb8ec383-2226-4ab5-9ca4-85c75a91a3a2','綿  其七','王夢應','宋','宋诗','song-poetry','','[]','自今以始，日就月將。',45,'全唐诗/poet.song.244000.json','["自今以始，日就月將。", "遹觀厥成，爲龍爲光，長發其祥。", "兄及弟矣，乃生男子。", "維其有之，是以似之。"]'),
('c952f4cf-b99f-4c9f-bb26-54867f29c872','太白仙人下岷峨謠','王夢應','宋','宋诗','song-poetry','','[]','太白仙人下岷峨，飛凌素烟紫瓊珂。',120,'全唐诗/poet.song.244000.json','["太白仙人下岷峨，飛凌素烟紫瓊珂。", "天風萬里吹銀河，手挼瑶草光逶迤。", "琅琅太清綠雲欹，下弄倒影笑羲娥。", "錦袍淋漓金叵羅，醉圍嬋娟玉顔酡。", "金庭昔日乘鸞過，不肯上天著朝靴。", "下界弱水飛塵多，公爲星精辟兵戈。", "願見瀛海秋澄波，綠鬢纚纚吞天和，後天不老公所哦。"]'),
('ddfce106-7f7c-4b30-96d2-c87af36faa43','挽曾東軒二首  其一','王夢應','宋','宋诗','song-poetry','','[]','健筆千夫畏，長才四海空。',48,'全唐诗/poet.song.244000.json','["健筆千夫畏，長才四海空。", "飛騰須掌制，危急逐乘驄。", "國事箋天疏，臣心救日弓。", "故人牛斗上，相見氣如虹。"]'),
('28444ad7-ef8b-4fdf-b083-0e1a6110467a','挽曾東軒二首  其二','王夢應','宋','宋诗','song-poetry','','[]','壯圖罹短世，野趣滿餘年。',48,'全唐诗/poet.song.244000.json','["壯圖罹短世，野趣滿餘年。", "往事堪垂史，孤蹤每畏天。", "廣文俄病酒，摩詰厭聞絃。", "遥想南州士，生芻重泫然。"]'),
('612a3ba8-67c9-40b4-8a92-7d538de494e0','呈李書史四首  其一','王夢應','宋','宋诗','song-poetry','','[]','林塘萬綠壓沈沈，雲滿吟窩足靚深。',32,'全唐诗/poet.song.244000.json','["林塘萬綠壓沈沈，雲滿吟窩足靚深。", "幾朵青山成畏友，一窗白日照初心。"]'),
('297b89a4-76de-4896-9ef1-df7d17c934ca','呈李書史四首  其二','王夢應','宋','宋诗','song-poetry','','[]','山中晝永書一帙，兵後南州健更誰。',32,'全唐诗/poet.song.244000.json','["山中晝永書一帙，兵後南州健更誰。", "君實中年陪社日，考亭無事注騷詩。"]'),
('23abb2ce-0f4e-409f-8894-9a260610fe6c','呈李書史四首  其三','王夢應','宋','宋诗','song-poetry','','[]','火龍騎日雪飛空，勁草亭亭不見風。',32,'全唐诗/poet.song.244000.json','["火龍騎日雪飛空，勁草亭亭不見風。", "臣亮南陽今未老，一鋤雲碎日猶紅。"]'),
('6fcdbc7b-5c23-4766-ac78-9928419ac678','呈李書史四首  其四','王夢應','宋','宋诗','song-poetry','','[]','水葉雪花正可人，陌頭客子劍生鱗。',32,'全唐诗/poet.song.244000.json','["水葉雪花正可人，陌頭客子劍生鱗。", "千年風致未盡歇，如此溪山有棄民。"]'),
('7f4f4264-0439-4641-af20-6e28e367440f','晚望','王夢應','宋','宋诗','song-poetry','','[]','望盡西南一隙明，荒荒野色弄微醺。',64,'全唐诗/poet.song.244000.json','["望盡西南一隙明，荒荒野色弄微醺。", "青煙白骨行人老，苦竹黄蘆細路分。", "寒雁不來秋似水，故園何處草如雲。", "高懷久爲凭闌盡，更遣西風化白紛。"]'),
('fccff7d1-a917-4f2b-9489-7e0919a36a59','和清明上冢韻','王夢應','宋','宋诗','song-poetry','','[]','酒壺花擔發雙明，陌上携扶笑語聲。',64,'全唐诗/poet.song.244000.json','["酒壺花擔發雙明，陌上携扶笑語聲。", "桑葉影稠春欲暗，楝花寒退雨初晴。", "宮官記夢曾傳燭，□客無詩定罰觥。", "老影年年霜露感，牛羊躑躅亂孤塋。"]'),
('045dd0c0-8ce2-4071-9e7b-d97b3eebe0b5','東歸','王夢應','宋','宋诗','song-poetry','','[]','一揖仍爲別，他鄉復避兵。',48,'全唐诗/poet.song.244000.json','["一揖仍爲別，他鄉復避兵。", "客隨風雨老，春著鼓鼙輕。", "宇宙關何事，艱危得此生。", "門前一溪水，幾日到江城。"]'),
('62a318f7-119e-4190-a036-b220bbf65b5a','甲申元日','王夢應','宋','宋诗','song-poetry','','[]','上日仍漂寄，尊前客又非。',48,'全唐诗/poet.song.244000.json','["上日仍漂寄，尊前客又非。", "鄉心眠聽雨，病骨晚添衣。", "街鼓春將動，簾燈寒未歸。", "梅花經一雪，幾片不曾飛。"]'),
('dfe52fb1-7db3-43b7-b878-4901e0831e09','詩一首','薛魁祥','宋','宋诗','song-poetry','','[]','霜風獵獵催寒冬，諸君馬首將欲東。',166,'全唐诗/poet.song.244000.json','["霜風獵獵催寒冬，諸君馬首將欲東。", "出門浩氣如長虹，舉手欲掛扶桑弓。", "君家渭陽蓋世功，黄沙萬里歸兵戎。", "牙旗金甲照天紅，江南草木皆春風。", "黄金築臺高巃嵷，三千珠履誇豪雄。", "君今聯轡登仙篷，綠水依依泛芙蓉。", "貂蟬出自兜鍪中，蝟鋒螳斧一掃空。", "我忝吳下舊阿蒙，鐵硯磨盡平生工。", "於山未見泰華峰，於人未見歐陽公。", "借君談天薦口爲先容，他日四方上下追逐如雲龍。"]'),
('1ed5f894-8486-486a-91cc-bc8af9d843b3','寄友人','陳觀','宋','宋诗','song-poetry','','[]','廢書開復卷，寧與世浮沉。',48,'全唐诗/poet.song.244000.json','["廢書開復卷，寧與世浮沉。", "萬事自有分，一生閑用心。", "天寒快征馬，日暮急歸禽。", "多少隆中客，空爲抱膝吟。"]'),
('2481968f-cfc1-4bd1-9613-6e507ce47d65','武夷山','陳觀','宋','宋诗','song-poetry','','[]','郵亭立溪端，上有石鼓字。',288,'全唐诗/poet.song.244000.json','["郵亭立溪端，上有石鼓字。", "回顧溪水中，石鼓安所置。", "移舟泝清流，前山鬰蒼翠。", "一曲遽停橈，尋真步幽邃。", "洞天閶闔開，殿閣儼神位。", "秦漢紀茲山，武夷君所治。", "幔亭晏曾孫，遐蹤久已祕。", "巍巍大王峰，玉女傍立侍。", "獅子西東來，昂藏不敢肆。", "我本羽衣人，憩跡昇真地。", "珍重學仙翁，命舟行厨備。", "溪山偕侶游，討論每延遲。", "二曲頓清奇，彼美宛臨水。", "三曲多仙巖，峭峙罕匹類。", "倚空架舟函，不腐亦不墜。", "小泊三杯石，坐玩逸清思。", "石上飲三杯，昔賢同一致。", "四曲入雲中，繁花方嫵媚。", "春光耀亭臺，靈草漸萌瑞。", "崖陰刻字新，往往書故事。", "五曲達平林，藹然千古意。", "精舍瞻遺容，豐碑誦遺記。", "杏壇相因依，高堂揭仁智。", "却令閩越中，居然作洙泗。"]'),
('44b63af6-6019-4d37-8f00-e8add84290af','聚奇樓','陳觀','宋','宋诗','song-poetry','','[]','世人寶珠玉，往往身殉之。',120,'全唐诗/poet.song.244000.json','["世人寶珠玉，往往身殉之。", "日遇佳山水，誰復知其奇。", "余本邱壑士，烟霞夙所怡。", "結樓清溪上，青山匝四維。", "雲宮接水殿，瑶草雜瓊枝。", "丹碧紛紛見，星河面面垂。", "陰晴多異賞，陟降窮二儀。", "離朱不易辨，繪畫空復施。", "萬狀歸目睫，百寶呈參差。", "藏珠與懷璧，娖娖徒爾爲。"]'),
('f0163216-1edd-4b19-a35c-a09ba527ee8e','閒樂堂獨坐','陳觀','宋','宋诗','song-poetry','','[]','廿年無累一閒身，卜築深源絕四鄰。',64,'全唐诗/poet.song.244000.json','["廿年無累一閒身，卜築深源絕四鄰。", "屋外桃蹊劉阮路，門前柳色義熙春。", "溪山處處從爲主，麋鹿時時不避人。", "自是頑樗非世用，敢言盛代有遺民。"]'),
('b31e2a5e-0625-4246-a178-f3d5a902a3f7','題甄氏訪山亭二首  其一','陳觀','宋','宋诗','song-poetry','','[]','水流花落石生雲，日靜風暄草欲薰。',32,'全唐诗/poet.song.244000.json','["水流花落石生雲，日靜風暄草欲薰。", "老去風流猶未減，一邱一壑尚懃懃。"]'),
('832a0fcc-9167-486e-8129-0f3af9784165','題甄氏訪山亭二首  其二','陳觀','宋','宋诗','song-poetry','','[]','雨後西山翡翠堆，結亭直欲近巖隈。',32,'全唐诗/poet.song.244000.json','["雨後西山翡翠堆，結亭直欲近巖隈。", "從今記取溪頭路，一日須來一百回。"]'),
('d3be7634-a5ed-4d9e-b791-a2e27fa07f6a','天壺道院','陳觀','宋','宋诗','song-poetry','','[]','山徑崎嶇紫翠連，白雲深處是壺天。',32,'全唐诗/poet.song.244000.json','["山徑崎嶇紫翠連，白雲深處是壺天。", "客來無物供吟笑，旋摘新茶煮石泉。"]'),
('76f462b5-6e7b-4b4f-9ad1-68c4921bb660','天遊峰','陳觀','宋','宋诗','song-poetry','','[]','山水參差六曲流，此中絕境適天游。',64,'全唐诗/poet.song.244000.json','["山水參差六曲流，此中絕境適天游。", "幾千萬類塵根淨，三十六峰雲氣浮。", "翠聳層霄巒壑勝，碧籠靜澗竹松稠。", "瓊漿可致胡麻熟，瓢笠何妨爲永留。"]'),
('61eed19b-725d-4751-bcc7-0a8ec96fb995','龜山亦好軒','梁泰來','宋','宋诗','song-poetry','','[]','人在遠堂山下居，家有遠堂堂上書。',115,'全唐诗/poet.song.244000.json','["人在遠堂山下居，家有遠堂堂上書。", "階苔簾草意自如，有書可讀山可廬。", "人於富貴不肯足，我於貧賤樂有餘。", "相逢休問我何好，亦有好處人未知。", "一池斗大泉可掬，一波掌平數叢菊。", "菊吾金，泉吾玉，何用封侯萬鍾粟。", "君不見孔門樂處無日無，疏食飲水肱常曲。"]'),
('f54e0c7b-2532-4c13-95b1-9d845d3f706a','題周坦戴氏桂林池館','梁泰來','宋','宋诗','song-poetry','','[]','地偏不受點塵侵，日涉園亭得趣深。',64,'全唐诗/poet.song.244000.json','["地偏不受點塵侵，日涉園亭得趣深。", "竹外移梅曾闢徑，月中分桂定成林。", "雲山環碧醉人眼，池水澂泓鑒此心。", "淨几明窗瀟灑儘，時携好客一凭臨。"]'),
('01028675-7d7d-4628-a3b0-f5a99d59923a','送樂安教諭周亦山  其一','何希之','宋','宋诗','song-poetry','','[]','獨佩傳家印，芹宮一線春。',48,'全唐诗/poet.song.244000.json','["獨佩傳家印，芹宮一線春。", "居然風月意，笑却簿書塵。", "溪水吾同味，簷花道固貧。", "迂寒從獻笑，肯與俗爲鄰。"]'),
('8e7fd062-b895-4232-8a2a-4b74d272358b','送樂安教諭周亦山  其二','何希之','宋','宋诗','song-poetry','','[]','垂晚相携手，飛談入理微。',48,'全唐诗/poet.song.244000.json','["垂晚相携手，飛談入理微。", "前修推大雅，晚輩際真依。", "君去紆朱紱，吾將老布衣。", "相敦各千載，別淚不須揮。"]'),
('ebf33f3d-0c12-4282-9bc9-9a147386c895','句','何希之','宋','宋诗','song-poetry','','[]','諸公錯落陽和調，贏得林間自在翁。',16,'全唐诗/poet.song.244000.json','["諸公錯落陽和調，贏得林間自在翁。"]'),
('4ef33214-b62f-4ec6-a81d-97080bcc01c0','甲戌客臨安','唐涇','宋','宋诗','song-poetry','','[]','金谷煙花醉未醒，鼾邊無夢到功名。',64,'全唐诗/poet.song.244000.json','["金谷煙花醉未醒，鼾邊無夢到功名。", "十郎腹裏長函劍，六丈胸中舊貯兵。", "天豕星沈狼有影，海鰌風緊鶴無聲。", "如聞浩浩愁相訊，何日衣冠樂太平。"]'),
('f593b807-b05e-4df1-b4d1-5bd39480c5b2','和朱以性','唐涇','宋','宋诗','song-poetry','','[]','擬駕奇肱閲四方，轉頭又是海生桑。',64,'全唐诗/poet.song.244000.json','["擬駕奇肱閲四方，轉頭又是海生桑。", "雁雖有帛難尋漢，猴縱無緋肯拜梁。", "泱漭黄流翻地軸，屈盤紫氣貫天章。", "篋中留取秋蘭佩，不識人間有水蒼。"]'),
('3ad1e7b2-c99a-4045-9b0c-1eb99d1fa217','江南西遷國之亡天也歌以紀之','唐涇','宋','宋诗','song-poetry','','[]','吳峰一髪暮雲孤，愁向湘纍訊故都。',64,'全唐诗/poet.song.244000.json','["吳峰一髪暮雲孤，愁向湘纍訊故都。", "鳳去只餘韶樂在，雁來還有帛書無。", "杏壇有客陳孤注，平隴何人復五銖。", "歌徹黍離風雨惡，南山深處叫烏烏。"]'),
('d52e0856-a6be-4f8b-bde1-d58d77655c88','閩亡徙東廣','唐涇','宋','宋诗','song-poetry','','[]','逖泉已矣又菇蕕，半壁乾坤只恁休。',64,'全唐诗/poet.song.244000.json','["逖泉已矣又菇蕕，半壁乾坤只恁休。", "頻歲建杓移北斗，何人持節救東甌。", "烟蜚檣艣風濤怒，雲鎖樓臺日月愁。", "南望羊城天欲暮，可堪回首問神州。"]'),
('ef512a4e-635c-476d-870e-7ea00bec4557','廣亡徙海','唐涇','宋','宋诗','song-poetry','','[]','箕冠如櫛擁茅旌，誰執騂旄歃晉盟。',64,'全唐诗/poet.song.244000.json','["箕冠如櫛擁茅旌，誰執騂旄歃晉盟。", "遵海而南關氣數，渡江以北少功名。", "火旗晻靄雲藏闕，水陣周遭雪壓城。", "一榻不容人鼾睡，那知霧島是神京。"]'),
('1e710071-ca2a-4d1c-9afa-e2b352844f5a','崖山亡','唐涇','宋','宋诗','song-poetry','','[]','萬里輿圖入朔方，摇摇孤注海之陽。',64,'全唐诗/poet.song.244000.json','["萬里輿圖入朔方，摇摇孤注海之陽。", "石尤風惡雲藏軫，天駟星沈月掩房。", "島上有人悲義士，水濱無處問君王。", "羲和指着烏飛路，去去虞淵暮色蒼。"]'),
('ede1bf96-1413-432e-b7a3-27a133d08501','江南四忠節國之紀也歌以哀之  其一','唐涇','宋','宋诗','song-poetry','','[]','咄咄薰風夢已靈，手提孤注竟逃盟。',64,'全唐诗/poet.song.244000.json','["咄咄薰風夢已靈，手提孤注竟逃盟。", "南冠入海五百客，北斾歸燕七十城。", "自信丹心終徇國，只慚白面不知兵。", "二爻無遯公知否，底事吳門變姓名。"]'),
('a04eee03-f7d4-454b-bbbf-54a2f6c76957','江南四忠節國之紀也歌以哀之  其二','唐涇','宋','宋诗','song-poetry','','[]','同時人物今猶昨，只有先生死朔方。',64,'全唐诗/poet.song.244000.json','["同時人物今猶昨，只有先生死朔方。", "殿下青衣晉天子，窖間白髪漢中郎。", "平生東海心猶壯，千古西山骨亦香。", "三復纍臣吟嘯集，天荒地老氣蒼蒼。"]'),
('e0bf71c1-4abc-4593-a798-b639f4847893','江南四忠節國之紀也歌以哀之  其三','唐涇','宋','宋诗','song-poetry','','[]','誰把南牙壓武夫，到頭還似二公無。',64,'全唐诗/poet.song.244000.json','["誰把南牙壓武夫，到頭還似二公無。", "矢心海上逃秦爵，努力山中匿趙孤。", "赤羽星沈迷輦鳳，紅旗風勁逐檣烏。", "三神杳眇人何在，留取丹心付董狐。"]'),
('b036e4ba-1d35-4103-9242-603a082e85b2','丙子紀事','唐涇','宋','宋诗','song-poetry','','[]','才結歲寒盟，歸來詫太平。',48,'全唐诗/poet.song.244000.json','["才結歲寒盟，歸來詫太平。", "閣中呼尚父，殿下狎門生。", "着手營三窟，回頭失兩京。", "聞今不聞古，咄咄詭知兵。"]'),
('25ff0776-772d-44e4-8c99-a28b395c1619','懷黄小牧','唐涇','宋','宋诗','song-poetry','','[]','瓠俎桑弧蒞舊盟，天將吾道寄山林。',64,'全唐诗/poet.song.244000.json','["瓠俎桑弧蒞舊盟，天將吾道寄山林。", "梧桐卧雨魚生釜，梅塢吟雲鶴伴琴。", "海上蘇卿今白髪，山中杜甫老丹心。", "擬呼尊酒論今古，黄葉蕭蕭楚水深。"]'),
('0a5eef0c-c4d6-4197-a6a3-9a07c8fdc61c','讀史懷友','唐涇','宋','宋诗','song-poetry','','[]','羞登廣武議英雄，匣却吳鈎弢却弓。',64,'全唐诗/poet.song.244000.json','["羞登廣武議英雄，匣却吳鈎弢却弓。", "幕下清談王太尉，門前白馬褚司空。", "一編衮斧風塵表，千古綱常天壤中。", "說與華陰捫虱老，何曾正朔在江東。"]'),
('8b217b25-2583-419f-b998-1c674694b214','春日','胡之純','宋','宋诗','song-poetry','','[]','春風蒲柳曲江頭，恨與春波不盡流。',64,'全唐诗/poet.song.244000.json','["春風蒲柳曲江頭，恨與春波不盡流。", "鶑喚新聲啼綠樹，燕尋舊壘認朱樓。", "百年驕豢吳兒脆，一味清談晉士休。", "千古興亡惟有淚，漫山花雨杜鵑愁。"]'),
('20d1e502-4c92-492f-96e8-d3ecbab9900c','上吳平章','邵允祥','宋','宋诗','song-poetry','','[]','嚙雪沙場倦牧羝，空山流涕冷凄凄。',64,'全唐诗/poet.song.244000.json','["嚙雪沙場倦牧羝，空山流涕冷凄凄。", "上林不見朝來雁，函谷空聞夜半雞。", "沽酒每懷澆管鮑，買絲端擬繡夷齊。", "忠貞反被忠貞誤，願借元龍百丈梯。"]'),
('a675b08e-97f5-492d-a09e-5c7009f5551b','上王平章','邵允祥','宋','宋诗','song-poetry','','[]','武陵春暖浩無涯，城下樓船陌上車。',64,'全唐诗/poet.song.244000.json','["武陵春暖浩無涯，城下樓船陌上車。", "禮樂遠傳吳季札，衣冠舊是漢長沙。", "秋高劍氣橫千里，夜靜書聲啟萬家。", "非是避秦前日路，行人何必問桃花。"]'),
('76d52c60-541e-4652-9617-19485c7a4607','石鼓鋪','趙若槸','宋','宋诗','song-poetry','','[]','山前山後杜鵑花，莊上黄鸝識謝家。',32,'全唐诗/poet.song.244000.json','["山前山後杜鵑花，莊上黄鸝識謝家。", "欲問青帘溪上酒，行逢白髪道邊茶。"]'),
('ba698530-f76a-4cdf-a5d2-6e2b2568528d','即事  其一','趙若槸','宋','宋诗','song-poetry','','[]','雲散春山出，人閑白晝長。',48,'全唐诗/poet.song.244000.json','["雲散春山出，人閑白晝長。", "禽聲答空谷，樹影畫斜陽。", "種果期秋實，澆花趁晚凉。", "行藏天已定，隨分且徜徉。"]'),
('f4d01078-9623-4739-82ff-1108ff6b9c30','即事  其二','趙若槸','宋','宋诗','song-poetry','','[]','可意黄鸝喚得醒，日移山影正當庭。',32,'全唐诗/poet.song.244000.json','["可意黄鸝喚得醒，日移山影正當庭。", "飛花忽趁春風過，點破苔痕一片青。"]'),
('5c80acf0-40bd-4fc5-aea8-aee5e88a3128','春詞','趙若槸','宋','宋诗','song-poetry','','[]','玉釵香夢水東流，簾怯春寒寄暮鈎。',32,'全唐诗/poet.song.244000.json','["玉釵香夢水東流，簾怯春寒寄暮鈎。", "燕子不來花滿地，一痕新月又西樓。"]'),
('30fe2963-4a0c-45e6-9970-deeb14243ef2','暮春','趙若槸','宋','宋诗','song-poetry','','[]','香透蜂房蝶夢殘，一簾新雨又春闌。',32,'全唐诗/poet.song.244000.json','["香透蜂房蝶夢殘，一簾新雨又春闌。", "柳腰瘦得難禁舞，今夜春風莫更寒。"]'),
('5c7c6caa-3d57-4bfc-9826-a43f80d46d6c','遇樵川林時中','趙若槸','宋','宋诗','song-poetry','','[]','建水樵川隔幾重，相逢孰意大江東。',64,'全唐诗/poet.song.244000.json','["建水樵川隔幾重，相逢孰意大江東。", "客行芳草垂楊外，春在柔桑小麥中。", "細雨疏田流水碧，殘霞擁樹遠林紅。", "浮生聚散渾無定，有酒何妨一笑同。"]'),
('03232c5a-4207-438f-be75-87efe36fc057','武夷茶','趙若槸','宋','宋诗','song-poetry','','[]','石乳霑餘潤，雲根石髓流。',24,'全唐诗/poet.song.244000.json','["石乳霑餘潤，雲根石髓流。", "玉甌浮動處，神入洞天游。"]'),
('73284398-d382-4b58-8b10-cff28255d3e6','句  其一','鄭德普','宋','宋诗','song-poetry','','[]','山蒸雲氣晴能雨，泉挾風聲夏亦寒。',16,'全唐诗/poet.song.244000.json','["山蒸雲氣晴能雨，泉挾風聲夏亦寒。"]'),
('ac8f46ee-9c3b-4484-84d2-f1574b3a5811','句  其二','鄭德普','宋','宋诗','song-poetry','','[]','石潤黏蒼蘚，澗高流白雲。',12,'全唐诗/poet.song.244000.json','["石潤黏蒼蘚，澗高流白雲。"]'),
('cde70f3f-bafa-4e4a-acfd-23f413452b8d','句  其三','鄭德普','宋','宋诗','song-poetry','','[]','雁斷風仍急，鳥啼天正陰。',12,'全唐诗/poet.song.244000.json','["雁斷風仍急，鳥啼天正陰。"]'),
('f7896599-78f7-4672-9d44-771692b5dbc6','小仰山','蕭炳','宋','宋诗','song-poetry','','[]','萬丈青山插碧天，真人煉藥石依然。',32,'全唐诗/poet.song.244000.json','["萬丈青山插碧天，真人煉藥石依然。", "功成自此飛昇去，屈指人間八百年。"]'),
('63e8f027-7799-4b19-99ee-c4d3295434f8','銅官山','蔣捷','宋','宋诗','song-poetry','','[]','崒嵂荆南山，袁令葬其麓。',120,'全唐诗/poet.song.244000.json','["崒嵂荆南山，袁令葬其麓。", "相傳天賜棺，咄咄誑流俗。", "令嘗成輿梁，天報宜以福。", "賜棺信榮矣，畢竟入鬼錄。", "珠官在嶺南，錦官在巴蜀。", "鹽官與鐵官，登載粉簡牘。", "吾恐古有司，鑄銅山之足。", "後人訛承訛，官傍妄加木。", "政須改銅官，大字鑱崖腹。", "事有作俑者，併按王喬玉。"]'),
('f251ef27-fef3-4d1b-bc3f-6aa3a89bc907','東坡田','蔣捷','宋','宋诗','song-poetry','','[]','老去紅灰酒甕前，向來青草瘴江邊。',32,'全唐诗/poet.song.244000.json','["老去紅灰酒甕前，向來青草瘴江邊。", "卜居自爲溪山好，不是區區爲買田。"]'),
('c962b486-9a6e-4b4c-b62b-d6c7229b4d6a','和通山尹張松坡夢遊廬山吟','余宏孫','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','我行匡廬鬢青青，往往大醉琵琶亭。',128,'全唐诗/poet.song.244000.json','["我行匡廬鬢青青，往往大醉琵琶亭。", "歸來老我二十載，惟有夢寐勞神形。", "有時遍歷開先寺，老僧禪定齁齁睡。", "有時經過五柳家，秫香酒熟邀人醉。", "恍兮惚兮真若飛，高泊天池坐忘歸。", "晴雲漠漠披絮帽，白鶴冉冉來羽衣。", "方將餐霞煉顔色，覺來無失亦無得。", "何當整理下澤車，共逐雙鳬訪真跡。"]'),
('e051e585-36c9-4b26-9262-2921154657b7','和余天開見寄','余宏孫','宋','宋诗','song-poetry','','[]','春樹君方吟渭北，林塘我已卜溪西。',32,'全唐诗/poet.song.244000.json','["春樹君方吟渭北，林塘我已卜溪西。", "賞心樂事優游處，花自飛飛鳥自啼。"]'),
('e09f2390-952b-4b3d-810f-a340f9f4516c','徐孺子讀書臺分得高字','孫素','宋','宋诗','song-poetry','','[]','吾愛徐聘君，沈冥乃人豪。',60,'全唐诗/poet.song.244000.json','["吾愛徐聘君，沈冥乃人豪。", "諸賢搆黨禍，皎皎雲鴻毛。", "平生讀何書，身隠名難逃。", "故宅照湖水，荒墳翳城蒿。", "焉知此山中，突兀書堂高。"]'),
('dd0c4f13-7976-4e35-9263-28993152838a','胡文定墨池分得風字','孫素','宋','宋诗','song-poetry','','[]','吾愛胡夫子，抱道來逃空。',60,'全唐诗/poet.song.244000.json','["吾愛胡夫子，抱道來逃空。", "豈伊桃花源，有此山泉蒙。", "奏疏瀝肝膽，春秋開盲聾。", "當年起草處，想見臨池工。", "願爲池上草，永懷君子風。"]'),
('6ac4ab0c-13c7-41e5-9133-4e08a4a41172','簡樊謙齋','陳茝','宋','宋诗','song-poetry','','[]','一疏闢人千，孤忠殊可賢。',48,'全唐诗/poet.song.244000.json','["一疏闢人千，孤忠殊可賢。", "丈夫不至此，君子有加焉。", "事濟民生福，言違臣職愆。", "還須謄諫草，痛哭九重前。"]'),
('5c7a1f90-359f-421a-b5d3-a589c5a4de76','釣臺二首  其一','陳必敬','宋','宋诗','song-poetry','','[]','公爲名利隠，我爲名利來。',24,'全唐诗/poet.song.244000.json','["公爲名利隠，我爲名利來。", "羞見先生面，黄昏過釣臺。"]'),
('597630cb-8e1f-4cbe-9c14-f08d8baa50b2','釣臺二首  其二','陳必敬','宋','宋诗','song-poetry','','[]','已上桐江臺，又弄桐江釣。',24,'全唐诗/poet.song.244000.json','["已上桐江臺，又弄桐江釣。", "不食桐江魚，不怕嚴公笑。"]'),
('83b7fb10-e8d7-4bdf-8b9e-e9a756facf2b','蛻龍洞','錢朝隠','宋','宋诗','song-poetry','','[]','凡骨何年蛻洞巖，真龍肯向此中蟠。',32,'全唐诗/poet.song.244000.json','["凡骨何年蛻洞巖，真龍肯向此中蟠。", "料應夜半凌空去，雷震千山風雨寒。"]'),
('b837de0f-46c3-4857-97fa-5632babd7990','靈苑寺','錢朝隠','宋','宋诗','song-poetry','','[]','馬前山色連天起，竹外溪聲動地來。',32,'全唐诗/poet.song.244000.json','["馬前山色連天起，竹外溪聲動地來。", "試過溪橋訪山寺，清風爲我拂塵埃。"]'),
('41ddcd66-e980-48df-9d5a-a13dd6449c5f','寄裴雲山','林正','宋','宋诗','song-poetry','','[]','南山高且深，竹深带流水。',84,'全唐诗/poet.song.244000.json','["南山高且深，竹深带流水。", "先生廬其中，迥若崆峒子。", "雪髪覆兩肩，深悟造化理。", "手注三體詩，名滿四海耳。", "時以詩名家，亦來質疑似。", "我本浪得名，長挂春風齒。", "乃識先生心，非非還是是。"]'),
('51379269-e530-4892-b45a-4b9292aacb75','遣興','林正','宋','宋诗','song-poetry','','[]','黄金難買老，自笑鬢毛皤。',48,'全唐诗/poet.song.244000.json','["黄金難買老，自笑鬢毛皤。", "本分且如此，明時可奈何。", "攻吟詩轉少，惜醉事還多。", "寒甚溪頭夜，誰能載雪過。"]'),
('7fca59a7-185f-4d05-85a0-56d97c2a680e','江邊','林正','宋','宋诗','song-poetry','','[]','炎天時偶出，四顧欲躋攀。',48,'全唐诗/poet.song.244000.json','["炎天時偶出，四顧欲躋攀。", "片雨來南浦，殘雲過別山。", "秋萌苗葉上，春寄藕花間。", "更羨沙頭鳥，知幾分外閒。"]'),
('3273906c-7106-4305-bd16-6fedf1c51eee','寄赤城葉學正','林正','宋','宋诗','song-poetry','','[]','相望江村遠，清夢阻雲津。',48,'全唐诗/poet.song.244000.json','["相望江村遠，清夢阻雲津。", "三百里餘路，幾重山外人。", "石橋僧拜月，桃洞馬行春。", "已滯劉郎趣，秋風渺憶蓴。"]'),
('ff42b864-f71e-47a8-8a30-37113bbbb0ba','老來','林正','宋','宋诗','song-poetry','','[]','愁殺漁鹽地，生涯寄蟻柯。',48,'全唐诗/poet.song.244000.json','["愁殺漁鹽地，生涯寄蟻柯。", "春秋將耳順，貧病欲家和。", "笑向老來減，言於醉後多。", "黑頭行樂日，那更識風波。"]'),
('5537f3f3-f3b5-478f-874e-96636d451795','絕句','杭地士人','宋','宋诗','song-poetry','','[]','天目山前水齧磯，天心地脈露危機。',32,'全唐诗/poet.song.244000.json','["天目山前水齧磯，天心地脈露危機。", "西周浸冷觚稜月，未必遷岐說果非。"]'),
('0a81e427-ee4a-4e93-88a5-344385c35bb9','陰那山','蔡蒙吉','宋','宋诗','song-poetry','','[]','宮闕空懸勝絕奇，天然泉石畫中窺。',64,'全唐诗/poet.song.244000.json','["宮闕空懸勝絕奇，天然泉石畫中窺。", "五峰指月攢寒玉，二水流雲漾碧漪。", "魚鳥身如遊極樂，猿猴心似發菩提。", "沈沈鐘鼓僧閒寂，客亦忘言自得之。"]'),
('ede7f046-46b3-4c5a-81c5-89dff25d290a','梅江晚泛二首  其一','蔡蒙吉','宋','宋诗','song-poetry','','[]','罷讀出江岸，江波滾滾來。',24,'全唐诗/poet.song.244000.json','["罷讀出江岸，江波滾滾來。", "呼舟閒打槳，載月二更回。"]'),
('f5bb1027-bcd3-4950-aea1-dde2de53e6ea','梅江晚泛二首  其二','蔡蒙吉','宋','宋诗','song-poetry','','[]','何處吹橫笛，蕭蕭荻葦叢。',24,'全唐诗/poet.song.244000.json','["何處吹橫笛，蕭蕭荻葦叢。", "徐看釣艇出，蓑笠一漁翁。"]'),
('558710cd-c061-48d8-9ab0-7b7585cf1a53','遊王壽山','蔡蒙吉','宋','宋诗','song-poetry','','[]','王壽山頭石徑斜，不知何處有仙家。',32,'全唐诗/poet.song.244000.json','["王壽山頭石徑斜，不知何處有仙家。", "烟霞踏遍芒鞋破，一路春鳩啼落花。"]'),
('812cceb3-74eb-475e-95cb-b04d20af9bae','和文文山中秋賞月韻','趙必𤩪','宋','宋诗','song-poetry','','[]','中秋有月更有酒，樂事賞心并二難。',64,'全唐诗/poet.song.244000.json','["中秋有月更有酒，樂事賞心并二難。", "萬里無塵銀世界，一清徹底玉溪山。", "素娥伴兔夜無寐，仙侶乘鸞曉未還。", "老子南樓動吟興，風吹香句墮塵寰。"]'),
('a6c0e620-059d-48f8-a393-4e7d469588df','和張竹處韻餞陳匝峰之濂泉','趙必𤩪','宋','宋诗','song-poetry','','[]','不愁官冷客無氈，力欲回瀾障百川。',64,'全唐诗/poet.song.244000.json','["不愁官冷客無氈，力欲回瀾障百川。", "無己晚年工覓句，元龍豪氣諱求田。", "焚章徑解諸侯印，買酒時分司業錢。", "庭草池蓮總春意，詩人只合住濂泉。"]'),
('e4ea20eb-d9b3-4ad3-9ba1-f1deb703b261','至節寄家信','趙必𤩪','宋','宋诗','song-poetry','','[]','薄宦駸駸已及瓜，寒梅羞見舊時花。',64,'全唐诗/poet.song.244000.json','["薄宦駸駸已及瓜，寒梅羞見舊時花。", "年來吟苦形成鶴，客裏愁多鬢減鴉。", "浮世有身元大患，此生何處是真家。", "白雲極目空搔首，歸雁兩三寒日斜。"]'),
('ff0db884-e98a-4e19-ad2b-b1cf825ee848','和黄秋三衢舟中韻','趙必𤩪','宋','宋诗','song-poetry','','[]','壯志曾期捋虎鬚，中年跛鱉困泥途。',64,'全唐诗/poet.song.244000.json','["壯志曾期捋虎鬚，中年跛鱉困泥途。", "糟𥻿富貴幾場醉，盧雉功名一擲呼。", "世事看來真塞馬，吾才祇可比黔馿。", "客遊倦矣休歸去，三逕可松園可蔬。"]'),
('d787f9a6-2a91-42d2-af27-54c213a24070','挽李梅邊  其一','趙必𤩪','宋','宋诗','song-poetry','','[]','貞元朝士盡凋零，一世龍門羨李膺。',64,'全唐诗/poet.song.244000.json','["貞元朝士盡凋零，一世龍門羨李膺。", "靖節有詩題晉號，德公無意入襄城。", "牀頭點易朱猶濕，几上遺書稿已謄。", "收拾故家華萼集，翩翩三鳳以文鳴。"]'),
('05017aef-bc64-4d7e-8713-d78356388326','挽李梅邊  其二','趙必𤩪','宋','宋诗','song-poetry','','[]','歸卧西樓理故書，幅巾羽扇一癯儒。',64,'全唐诗/poet.song.244000.json','["歸卧西樓理故書，幅巾羽扇一癯儒。", "家庭師友尊明道，古史文章逼老蘇。", "蓬鬢蚤因時事白，荷衣不受劫塵污。", "嗚呼天不遺耆老，雨淚如傾一束芻。"]'),
('9b7066eb-34d7-4b74-93ba-d9c063368c42','和李梅外韻以傷邑士之無朋','趙必𤩪','宋','宋诗','song-poetry','','[]','兀兀規規鐵限門，鬚眉妾婦徧吾村。',64,'全唐诗/poet.song.244000.json','["兀兀規規鐵限門，鬚眉妾婦徧吾村。", "蜀南見日犬羣吠，井底觀天蛙自尊。", "守望誰爲鄉里助，典型藉有老成存。", "書生唇齒久荆棘，氣不能平又一言。"]'),
('0bbaf0c0-0e82-4b8d-be86-2d628602ce3e','避地惠陽鼓峰用徐心遠韻','趙必𤩪','宋','宋诗','song-poetry','','[]','收拾當年破敕黄，山中蕙帳夢魂香。',64,'全唐诗/poet.song.244000.json','["收拾當年破敕黄，山中蕙帳夢魂香。", "風供松葉暖茶竈，雲卧茆窗凍筆床。", "一雨鳴蛙亂深夜，數聲啼鳥怨斜陽。", "風塵浩蕩愁如海，怎得中山醉酒方。"]'),
('81a463d2-ea15-46cb-92fd-152b71e955a6','挽張縣尹','趙必𤩪','宋','宋诗','song-poetry','','[]','別駕新除墨尚鮮，翩其鳬舄已飛僊。',64,'全唐诗/poet.song.244000.json','["別駕新除墨尚鮮，翩其鳬舄已飛僊。", "床頭空有栽花譜，身後應無買木錢。", "自古才人多薄命，如今鄉國正思賢。", "纍纍孤寡相持泣，說與天知天也憐。"]'),
('728c7d66-5990-4381-b47a-b4bbb56808fc','春行南山訪友不遇','趙必𤩪','宋','宋诗','song-poetry','','[]','瘦筇支我上南山，纔到山中分外閒。',64,'全唐诗/poet.song.244000.json','["瘦筇支我上南山，纔到山中分外閒。", "九十日春將解印，百年心事幾凭欄。", "燕營一壘雛相慶，鶴舞三臺仙未還。", "松菊把門牢閉著，誰人彈壓此騷壇。"]'),
('8fe64d53-6940-4d85-86e8-3b77a1f8cf53','元日客中和同年韻','趙必𤩪','宋','宋诗','song-poetry','','[]','歲堂堂去逐江干，夜半東風送舊寒。',64,'全唐诗/poet.song.244000.json','["歲堂堂去逐江干，夜半東風送舊寒。", "爆竹聲中人老大，梅花香外客平安。", "一番春事從頭起，萬里天衢著步寬。", "上下雲龍平昔願，擬摩短翮附飛翰。"]'),
('9464a76d-0c43-415a-a17f-3f7197f6c236','和黄秋韻','趙必𤩪','宋','宋诗','song-poetry','','[]','騷壇分戍打愁城，奏凱梅邊緩轡行。',64,'全唐诗/poet.song.244000.json','["騷壇分戍打愁城，奏凱梅邊緩轡行。", "詩債填償難一頓，酒緣結習是三生。", "未能范蠡浮輕舸，且學靈均賦落英。", "落魄半生成底事，沙汀月冷負鷗盟。"]'),
('92172bfa-1016-43d5-b53f-4b6ddaeb551d','和自村同年韻寄南山劉義車','趙必𤩪','宋','宋诗','song-poetry','','[]','空谷寥寥絕足音，月明千里故人心。',64,'全唐诗/poet.song.244000.json','["空谷寥寥絕足音，月明千里故人心。", "功名蝴蝶半床夢，歲月蜉蝣一息陰。", "王粲曾聞附劉表，華元何忍薄羊斟。", "買舟欲泛剡溪曲，安道門前雪忒深。"]'),
('35c1b4e9-8fa6-4067-a86d-a536dd1358f5','餞尹權宰  其一','趙必𤩪','宋','宋诗','song-poetry','','[]','半年筆底種甘棠，棠未成陰又趣裝。',64,'全唐诗/poet.song.244000.json','["半年筆底種甘棠，棠未成陰又趣裝。", "明月扁舟琴鶴共，西風一劍斗牛光。", "人生易散情如海，事會無窮鬢未霜。", "莫把屠龍斬蛟手，便携短棹釣滄浪。"]'),
('6d561061-c617-41ee-90cf-72e5da3fc5e0','餞尹權宰  其二','趙必𤩪','宋','宋诗','song-poetry','','[]','老我江湖倦送迎，故人此別若爲情。',64,'全唐诗/poet.song.244000.json','["老我江湖倦送迎，故人此別若爲情。", "綈袍氣義千金重，故紙功名一縷輕。", "我輩何心爭鶩粒，人生到處有魚羹。", "何時握手孤山路，共折梅花醉月明。"]'),
('44cee7c5-fb49-4281-91d9-73291533630f','和尹權宰見訪韻','趙必𤩪','宋','宋诗','song-poetry','','[]','牛下高眠扣角歌，轡金裾翠重相過。',64,'全唐诗/poet.song.244000.json','["牛下高眠扣角歌，轡金裾翠重相過。", "江湖十載知心少，風雨一庭愁思多。", "君向青雲騰驥足，我甘白髪老漁簑。", "茅簷剪燭更酌酒，人世歡娛能幾何。"]'),
('fc60e115-1406-40a7-8d53-ff19c09605ac','和黎簿韻','趙必𤩪','宋','宋诗','song-poetry','','[]','月佩雲冠白雪纓，枳花香裏見詩人。',64,'全唐诗/poet.song.244000.json','["月佩雲冠白雪纓，枳花香裏見詩人。", "武城半載嘗聞政，洛社他年儻卜鄰。", "四海人皆知鑿齒，一簑誰復識玄真。", "斯文共締千年好，杯酒歡娛迹總陳。"]'),
('8f1dd9b4-20af-4889-a254-5df4148bbc21','賀黎耐交建經史閣','趙必𤩪','宋','宋诗','song-poetry','','[]','芹宮地屬淳熙祖，芸閣功成四世孫。',64,'全唐诗/poet.song.244000.json','["芹宮地屬淳熙祖，芸閣功成四世孫。", "千載詩書元氣在，百年文獻故家存。", "卷還贈券珍公帑，留取芳名榜聖門。", "當道宗工鳳樓手，擬干椽筆刻璵璠。"]'),
('e8922fa8-4f67-40b3-b85c-47a1a52973ec','餞陳柳邊權惠陽教','趙必𤩪','宋','宋诗','song-poetry','','[]','豪氣元龍習未除，扁舟撐月過豐湖。',64,'全唐诗/poet.song.244000.json','["豪氣元龍習未除，扁舟撐月過豐湖。", "飯雖不足猶携鶴，累既無多合載書。", "野客慣曾憐鄭老，諸公何敢薄相如。", "江湖交舊如垂問，爲道衰頹只故吾。"]'),
('aad41dee-9e2c-4534-86e7-206d2453181f','挽趙北山','趙必𤩪','宋','宋诗','song-poetry','','[]','嫠緯孤忠泣黍離，吟形如鶴不勝衣。',64,'全唐诗/poet.song.244000.json','["嫠緯孤忠泣黍離，吟形如鶴不勝衣。", "參苓信美難供病，松菊猶存欠賦歸。", "魂夢三千餘里遠，功名四十九年非。", "北山猿鶴多悽愴，獨對梅花淚暗揮。"]'),
('f7998a74-9f75-46ba-9ac9-a5478e69bc9a','避地山中和楊推夜寒韻二首  其一','趙必𤩪','宋','宋诗','song-poetry','','[]','山藏皇恐色，溪訴不平聲。',48,'全唐诗/poet.song.244000.json','["山藏皇恐色，溪訴不平聲。", "落葉啼猿怨，危枝宿鳥驚。", "林疏風四面，霜冷月三更。", "酒醒愁無寐，燒松炙到明。"]'),
('61ad90a4-13d1-4916-8180-c97dc6d762f4','避地山中和楊推夜寒韻二首  其二','趙必𤩪','宋','宋诗','song-poetry','','[]','浮生等萍汎，前事總花虛。',48,'全唐诗/poet.song.244000.json','["浮生等萍汎，前事總花虛。", "橘外訪四皓，林間逢二疏。", "溪山數茅屋，天地一蘧廬。", "怕有桃源路，相期更卜居。"]'),
('ffd381f8-30ed-498e-a969-c6b0d8405bbe','別和明府歸帥省  其一','趙必𤩪','宋','宋诗','song-poetry','','[]','江山如昨日，人物已晨星。',48,'全唐诗/poet.song.244000.json','["江山如昨日，人物已晨星。", "往事風前絮，浮生水上萍。", "別離頭半白，邂逅眼終青。", "客子愁如醉，曉風吹未醒。"]'),
('0ebf68da-0277-4ded-9f8f-2cb74e657414','別和明府歸帥省  其二','趙必𤩪','宋','宋诗','song-poetry','','[]','幾度賦停雲，重逢瘴海濱。',48,'全唐诗/poet.song.244000.json','["幾度賦停雲，重逢瘴海濱。", "已成三載別，猶是舊時貧。", "酒量病來減，詩情老更新。", "慇懃分袂意，折盡柳條春。"]'),
('8cb48434-e1b4-4d78-8773-cf1bbb646804','和朱水鄉韻  其一','趙必𤩪','宋','宋诗','song-poetry','','[]','已落淵明後，歸歟寂寞濱。',48,'全唐诗/poet.song.244000.json','["已落淵明後，歸歟寂寞濱。", "舊交松處士，新寵竹夫人。", "詩國尊齊晉，仙溪隔昴辰。", "南柯還是夢，螻蟻自君臣。"]'),
('8f18f189-b600-476f-8544-27d7dfe738c1','和朱水鄉韻  其二','趙必𤩪','宋','宋诗','song-poetry','','[]','江湖雙鬢短，風雨一燈孤。',48,'全唐诗/poet.song.244000.json','["江湖雙鬢短，風雨一燈孤。", "買酒初嘗芡，抄詩細截蒲。", "織耕同德曜，編簡對韓符。", "怕有傷時句，磨教稜角無。"]'),
('3c6c5b4f-0f01-437a-a796-2c645ef4503c','和朱水鄉韻  其三','趙必𤩪','宋','宋诗','song-poetry','','[]','何處著詩豪，白雲高更高。',48,'全唐诗/poet.song.244000.json','["何處著詩豪，白雲高更高。", "山中別天地，門外自波濤。", "夜雨荒園菊，春風媚觀桃。", "歸來懷故宇，招隠愧離騷。"]'),
('66edc913-eace-42e1-8047-1cebd76f006a','和朱水鄉韻  其四','趙必𤩪','宋','宋诗','song-poetry','','[]','一我獨栖栖，相逢又解携。',48,'全唐诗/poet.song.244000.json','["一我獨栖栖，相逢又解携。", "驚魚依亂藻，忙燕壘新泥。", "亦有種桃者，獨無芳草兮。", "買舟欲乘興，風雨黯前溪。"]'),
('cb76d89f-7424-44e9-9e40-864b8be7fbd8','餞陳匝峰之濂泉','趙必𤩪','宋','宋诗','song-poetry','','[]','桃源渺何處，夢短到家難。',48,'全唐诗/poet.song.244000.json','["桃源渺何處，夢短到家難。", "不辦一邱費，猶爲九品官。", "鶴嫌新俸薄，鷗訝舊盟寒。", "附翼攀鱗事，書生不敢干。"]'),
('6dcb2939-d562-470c-aa56-91f55863909c','重九宴陳東湖亭','趙必𤩪','宋','宋诗','song-poetry','','[]','詩成歡未盡，月下客重來。',48,'全唐诗/poet.song.244000.json','["詩成歡未盡，月下客重來。", "清影共千里，寒香更一杯。", "龍山秋寂寞，牛渚夜徘徊。", "飲待東方白，人生能幾回。"]'),
('5bfe2220-8341-4977-8a05-6036d43abc36','和文文溪慶徐固峰六十得子韻','趙必𤩪','宋','宋诗','song-poetry','','["\u897f\u6e56"]','明珠生老蚌，光彩射西湖。',48,'全唐诗/poet.song.244000.json','["明珠生老蚌，光彩射西湖。", "歲晚穎方實，春榮木不枯。", "卿兒是麟否，陵母夢雲無。", "他日浣花老，騎馿索醉扶。"]'),
('14287df3-bd0d-4c7a-973b-ac4d1068a5cd','題竹隠梅外二先生祠堂','趙必𤩪','宋','宋诗','song-poetry','','[]','一瓣瞻祠像，形癯道自腴。',48,'全唐诗/poet.song.244000.json','["一瓣瞻祠像，形癯道自腴。", "衣冠千載事，功力廿篇書。", "老竹秦四皓，寒梅漢二疏。", "紛紛麟閣畫，章服裹猴狙。"]'),
('ad942bc7-a267-4f7d-bd2d-d0683bcaeeb6','挽陳東湖  其一','趙必𤩪','宋','宋诗','song-poetry','','[]','諸公凋謝盡，此老魯靈光。',48,'全唐诗/poet.song.244000.json','["諸公凋謝盡，此老魯靈光。", "筆硯生涯舊，詩書福澤長。", "春園名獨樂，秋圃賦寒香。", "誰續斯文脈，元方與季方。"]'),
('6cdbf8fc-dfd2-494e-a48b-9d6d2c984f6d','挽陳東湖  其二','趙必𤩪','宋','宋诗','song-poetry','','[]','東湖地百弓，左柳右芙蓉。',48,'全唐诗/poet.song.244000.json','["東湖地百弓，左柳右芙蓉。", "老屋三間月，童顔七十翁。", "曉凉快吟屨，晚霽醉漁篷。", "一夜西風慘，池荷不敢紅。"]'),
('4b4e53e3-3bcc-41c4-a42b-59ee101c8d77','挽陳東湖  其三','趙必𤩪','宋','宋诗','song-poetry','','[]','吾善養吾存，衡茅道更尊。',48,'全唐诗/poet.song.244000.json','["吾善養吾存，衡茅道更尊。", "書聲響三世，詩派禪諸孫。", "今古自秦晉，山林有綺園。", "臨風涕如雨，一些試招魂。"]'),
('1322e60a-47cf-44e6-a1dc-45375daf84fb','挽陳東湖  其四','趙必𤩪','宋','宋诗','song-poetry','','[]','邯鄲塵夢覺，歸卧讀書林。',48,'全唐诗/poet.song.244000.json','["邯鄲塵夢覺，歸卧讀書林。", "投老菊三徑，憂時雪一簪。", "魚安知我樂，鷗自識翁心。", "已矣鍾期死，眼前誰賞音。"]'),
('d6a301f4-74bc-4986-a6bc-2869088e6a21','李月野舍旁之李花於梅時郡齋有詩遂次其韻  其一','趙必𤩪','宋','宋诗','song-poetry','','[]','李花不減梅花白，閒與梅花爭幾回。',32,'全唐诗/poet.song.244000.json','["李花不減梅花白，閒與梅花爭幾回。", "惟有暗香疏影句，承當不下讓還梅。"]'),
('0d190007-d15a-49dd-afcb-8e7581c1fc83','李月野舍旁之李花於梅時郡齋有詩遂次其韻  其二','趙必𤩪','宋','宋诗','song-poetry','','[]','李花久慕梅清潔，取友於梅結己知。',32,'全唐诗/poet.song.244000.json','["李花久慕梅清潔，取友於梅結己知。", "不是爭春逞年少，祇嫌桃杏带妖姿。"]'),
('32b54e69-ba7f-41e4-a367-9c9f10c538d9','懷梅水村十絕用張小山韻  其一','趙必𤩪','宋','宋诗','song-poetry','','[]','人生南北浮萍耳，四海九州都是家。',32,'全唐诗/poet.song.244000.json','["人生南北浮萍耳，四海九州都是家。", "畢竟男兒心似鐵，莫將愁淚涴梅花。"]'),
('421a8bbd-1851-4ed7-a7e3-6fe484267d04','懷梅水村十絕用張小山韻  其二','趙必𤩪','宋','宋诗','song-poetry','','[]','十年騎鶴夢悠悠，天地無情白髪愁。',32,'全唐诗/poet.song.244000.json','["十年騎鶴夢悠悠，天地無情白髪愁。", "歸到咸陽還似客，幾回腸斷望并州。"]'),
('8e5bf0d2-5cd7-4a9d-8aa2-cf58205e37f6','懷梅水村十絕用張小山韻  其三','趙必𤩪','宋','宋诗','song-poetry','','[]','小山山人荷爲衣，松梅爲屋竹爲籬。',32,'全唐诗/poet.song.244000.json','["小山山人荷爲衣，松梅爲屋竹爲籬。", "簷花細雨青燈句，獨憶鄭老同襟期。"]'),
('860db406-d591-48a8-97af-699fa6038429','懷梅水村十絕用張小山韻  其四','趙必𤩪','宋','宋诗','song-poetry','','[]','紙衾如水夢難成，抱膝燈前讀北征。',32,'全唐诗/poet.song.244000.json','["紙衾如水夢難成，抱膝燈前讀北征。", "懊恨雁來無箇字，海雲千里雨溟溟。"]'),
('11c73962-50b9-436e-83fd-e51053f82a30','懷梅水村十絕用張小山韻  其五','趙必𤩪','宋','宋诗','song-poetry','','[]','暮秋已誤張郎約，冬暮歸期又未成。',32,'全唐诗/poet.song.244000.json','["暮秋已誤張郎約，冬暮歸期又未成。", "趁取歲前到家好，春來怕有杜鵑聲。"]'),
('e6a086ce-e030-40b4-b2f9-c787bb5f1344','懷梅水村十絕用張小山韻  其六','趙必𤩪','宋','宋诗','song-poetry','','[]','夢入羅浮歸興崧，回程約莫到閩中。',32,'全唐诗/poet.song.244000.json','["夢入羅浮歸興崧，回程約莫到閩中。", "何當載酒迎馬首，先生莫負琉璃鍾。"]'),
('bee4abd0-611b-4d10-90f2-8b45a91df6b8','懷梅水村十絕用張小山韻  其七','趙必𤩪','宋','宋诗','song-poetry','','[]','梅花集裏識真梅，曾讀梅花偈子來。',32,'全唐诗/poet.song.244000.json','["梅花集裏識真梅，曾讀梅花偈子來。", "四海交游君倒指，江南只有賀方回。"]'),
('8945ce18-d3a5-4ede-8a10-a2b41ac204f5','懷梅水村十絕用張小山韻  其八','趙必𤩪','宋','宋诗','song-poetry','','[]','銀鈎鐵畫憶珍題，筆法精神逼會稽。',32,'全唐诗/poet.song.244000.json','["銀鈎鐵畫憶珍題，筆法精神逼會稽。", "可是荆州佳子弟，爭憐野鶩厭家雞。"]'),
('a7ff12d9-1b40-478f-a4a3-c954045091db','懷梅水村十絕用張小山韻  其九','趙必𤩪','宋','宋诗','song-poetry','','[]','鄰牆砧杵送秋聲，雲掩香幃六曲屏。',32,'全唐诗/poet.song.244000.json','["鄰牆砧杵送秋聲，雲掩香幃六曲屏。", "燈下回文題未就，梅花明月一床冰。"]'),
('a9b7011b-7c0d-40c6-a4ed-55cd4e435a8d','懷梅水村十絕用張小山韻  其一○','趙必𤩪','宋','宋诗','song-poetry','','[]','君行千里無幾微，六見月挂珊瑚枝。',32,'全唐诗/poet.song.244000.json','["君行千里無幾微，六見月挂珊瑚枝。", "山猿野鶴俱無恙，獨有梅花欠數詩。"]'),
('3490efcc-2127-4261-b06f-d2e2ade47bf3','再用前韻集句  其一','趙必𤩪','宋','宋诗','song-poetry','','[]','我思君處君思我，一掬歸心未到家。',32,'全唐诗/poet.song.244000.json','["我思君處君思我，一掬歸心未到家。", "相見或因中夜夢，孤燈何事獨成花。"]'),
('080082c0-8dc1-4bc2-8c3f-ccc35cc2bc7c','再用前韻集句  其二','趙必𤩪','宋','宋诗','song-poetry','','[]','思君天闊水悠悠，醉裏眉攢萬國愁。',32,'全唐诗/poet.song.244000.json','["思君天闊水悠悠，醉裏眉攢萬國愁。", "所不負予如此酒，已教從事到青州。"]'),
('948134b1-d15c-43bd-91ac-6042d2d62de9','再用前韻集句  其三','趙必𤩪','宋','宋诗','song-poetry','','[]','蔬飯藜牀破衲衣，經年兀兀槿花籬。',32,'全唐诗/poet.song.244000.json','["蔬飯藜牀破衲衣，經年兀兀槿花籬。", "與君聚散若雲雨，君問歸期未有期。"]'),
('6b2890cd-f0a7-4cc3-93fa-2828ab08e19f','再用前韻集句  其四','趙必𤩪','宋','宋诗','song-poetry','','[]','聞道騎鯨遊汗漫，寄書因見雁南征。',32,'全唐诗/poet.song.244000.json','["聞道騎鯨遊汗漫，寄書因見雁南征。", "他年一舸鴟夷去，莫羨摶風起北溟。"]'),
('a141e7ff-fc9b-4ee2-b6cb-12e591f091a8','再用前韻集句  其五','趙必𤩪','宋','宋诗','song-poetry','','[]','相思一夜梅花發，吟破離心句不成。',32,'全唐诗/poet.song.244000.json','["相思一夜梅花發，吟破離心句不成。", "橫玉叫雲清似水，夜鐘殘月雁歸聲。"]'),
('fec0e6af-f785-491d-84df-abd861773057','再用前韻集句  其六','趙必𤩪','宋','宋诗','song-poetry','','[]','千里萬里西復東，山川長在淚痕中。',32,'全唐诗/poet.song.244000.json','["千里萬里西復東，山川長在淚痕中。", "何當共剪西窗燭，一曲琵琶酒一鍾。"]'),
('695ec915-f39f-4dec-b636-13ef893afd38','再用前韻集句  其七','趙必𤩪','宋','宋诗','song-poetry','','[]','少年心壯輕爲客，不寄梅花遠信來。',32,'全唐诗/poet.song.244000.json','["少年心壯輕爲客，不寄梅花遠信來。", "爲見行舟試借問，看花出約幾時回。"]'),
('8c0b61fb-0e49-4997-8cf4-6526881a77ec','再用前韻集句  其八','趙必𤩪','宋','宋诗','song-poetry','','[]','何所獨無芳草兮，歸田有計一何稽。',32,'全唐诗/poet.song.244000.json','["何所獨無芳草兮，歸田有計一何稽。", "吾儕流落豈天意，俯仰天地身醯鷄。"]'),
('856e4ece-63be-47b8-a4a4-cd1ecf405d10','再用前韻集句  其九','趙必𤩪','宋','宋诗','song-poetry','','[]','草根何處不蟲聲，燈火昏昏獨掩屏。',32,'全唐诗/poet.song.244000.json','["草根何處不蟲聲，燈火昏昏獨掩屏。", "有約不來過夜半，煮茶敲碎一池冰。"]'),
('9f21cff0-497d-42c2-af7e-13607591ab0f','再用前韻集句  其一○','趙必𤩪','宋','宋诗','song-poetry','','[]','忽憶故人天外去，感君贈我瓊瑶枝。',32,'全唐诗/poet.song.244000.json','["忽憶故人天外去，感君贈我瓊瑶枝。", "世間好句無人共，郎罷吟詩囝和詩。"]'),
('736745e5-5937-4b22-95cf-c701fdd383fa','挽李自玉  其一','趙必𤩪','宋','宋诗','song-poetry','','[]','安樂窩中寄幅巾，床頭易註墨猶新。',32,'全唐诗/poet.song.244000.json','["安樂窩中寄幅巾，床頭易註墨猶新。", "蓋棺只著深衣去，疑是堯夫輩行人。"]'),
('a7dc1393-151b-46c3-9f82-ef5ccb460c18','挽李自玉  其二','趙必𤩪','宋','宋诗','song-poetry','','[]','宗主文盟護梓桑，春風一手種甘棠。',32,'全唐诗/poet.song.244000.json','["宗主文盟護梓桑，春風一手種甘棠。", "葬時移近坡翁墓，留取清名伴菊香。"]'),
('dab2d192-d319-4bfa-b4d5-8190c1076149','挽李自玉  其三','趙必𤩪','宋','宋诗','song-poetry','','[]','百年心事兩眉頭，生死閭閻繫戚休。',32,'全唐诗/poet.song.244000.json','["百年心事兩眉頭，生死閭閻繫戚休。", "浩蕩中流無砥柱，乘風漲浪舞鯨鰍。"]'),
('30f7d79f-acf9-4883-8f3e-a7e0effedb04','挽李自玉  其四','趙必𤩪','宋','宋诗','song-poetry','','[]','醫至猶言疾可爲，酸風吹訃落茅茨。',32,'全唐诗/poet.song.244000.json','["醫至猶言疾可爲，酸風吹訃落茅茨。", "典型諸老凋零盡，一束生芻雨涕垂。"]'),
('bb7050d1-e853-4125-8f2b-9a7fa5ec2b1f','南康縣圃賞梨花呈長官  其一','趙必𤩪','宋','宋诗','song-poetry','','[]','種花之暇點春芳，把酒花邊試洗粧。',32,'全唐诗/poet.song.244000.json','["種花之暇點春芳，把酒花邊試洗粧。", "差勝當年潘令尹，空栽桃李滿河陽。"]'),
('c84f973f-2a7a-4da5-8667-ac2ff06ff2fe','南康縣圃賞梨花呈長官  其二','趙必𤩪','宋','宋诗','song-poetry','','[]','點綠粧紅千萬般，薰桃染柳更蒸蘭。',32,'全唐诗/poet.song.244000.json','["點綠粧紅千萬般，薰桃染柳更蒸蘭。", "梨花也費東風力，九十日春無點閒。"]'),
('f75fa4e7-d60f-4b2d-aae9-3a5aa0738d4e','南康縣圃賞梨花呈長官  其三','趙必𤩪','宋','宋诗','song-poetry','','[]','霜玉肌膚冰雪魂，春風庭院月黄昏。',32,'全唐诗/poet.song.244000.json','["霜玉肌膚冰雪魂，春風庭院月黄昏。", "兒曹不解吟翁意，無雨無風也閉門。"]'),
('72e5bcd7-4b76-4588-9a6b-b0fddea18230','南康縣圃賞梨花呈長官  其四','趙必𤩪','宋','宋诗','song-poetry','','[]','李俗桃麄不用評，梅花之後此花清。',32,'全唐诗/poet.song.244000.json','["李俗桃麄不用評，梅花之後此花清。", "喚醒山谷商量過，差替山礬做弟兄。"]'),
('ecf25eed-3334-4d2d-93e8-4109297b0193','贈黄槐谷  其一','趙必𤩪','宋','宋诗','song-poetry','','[]','我坐詩窮子術窮，只堪雨笠與烟篷。',32,'全唐诗/poet.song.244000.json','["我坐詩窮子術窮，只堪雨笠與烟篷。", "牢收相法無人問，路上相逢盡相公。"]'),
('e96b54bc-c095-40dd-b642-9a8a8e0be871','贈黄槐谷  其二','趙必𤩪','宋','宋诗','song-poetry','','[]','上下乾坤亂失經，禍淫禍善事冥冥。',32,'全唐诗/poet.song.244000.json','["上下乾坤亂失經，禍淫禍善事冥冥。", "老天自是無分曉，更向癡人說五星。"]'),
('0af9b628-ae71-47e0-8b70-ade0c4c110e6','挽鄧南山  其一','趙必𤩪','宋','宋诗','song-poetry','','[]','洛社耆英久隠居，書田付與子孫鋤。',32,'全唐诗/poet.song.244000.json','["洛社耆英久隠居，書田付與子孫鋤。", "終南不是功名徑，說著功名俗了渠。"]'),
('fd7c9373-9e9d-4189-90d2-2c9663995506','挽鄧南山  其二','趙必𤩪','宋','宋诗','song-poetry','','[]','老子平生不好諛，莫教猿鶴費分疏。',32,'全唐诗/poet.song.244000.json','["老子平生不好諛，莫教猿鶴費分疏。", "只消題作南山墓，種竹一庭梅百株。"]'),
('95023fad-4c5d-41e1-98bd-89b5abdc6851','題雲岫半閒堂用李涉韻  其一','趙必𤩪','宋','宋诗','song-poetry','','[]','一塢白雲茅數間，歸與釣水採於山。',32,'全唐诗/poet.song.244000.json','["一塢白雲茅數間，歸與釣水採於山。", "寄聲靈徹休相笑，未必僧閒似我閒。"]'),
('8036f667-01d7-4ccc-a62a-1aac62437657','題雲岫半閒堂用李涉韻  其二','趙必𤩪','宋','宋诗','song-poetry','','[]','卧月眠雲屋半間，詩人到處是家山。',32,'全唐诗/poet.song.244000.json','["卧月眠雲屋半間，詩人到處是家山。", "當年悔弄君房筆，只得忙中一半閒。"]'),
('535858b8-d488-4edc-a249-ef812f5cded2','贈相士陳神眼','趙必𤩪','宋','宋诗','song-poetry','','[]','憶昔初逢神眼時，已於未第便相期。',32,'全唐诗/poet.song.244000.json','["憶昔初逢神眼時，已於未第便相期。", "不嫌屋矮重來訪，宦况蕭然且贈詩。"]'),
('e01d1b30-abf8-4381-b6e4-d366d63906d4','題月巖','趙必𤩪','宋','宋诗','song-poetry','','[]','千年老桂影婆娑，一半銀蟾挂碧蘿。',32,'全唐诗/poet.song.244000.json','["千年老桂影婆娑，一半銀蟾挂碧蘿。", "大抵人間天上事，團圓時少缺時多。"]'),
('26c9c278-6978-4f2c-8d9c-a03b9f40d8fe','戲題睡屏  其一','趙必𤩪','宋','宋诗','song-poetry','','[]','一別相如直至今，床頭綠綺暗生塵。',32,'全唐诗/poet.song.244000.json','["一別相如直至今，床頭綠綺暗生塵。", "當年自是文君誤，未必琴心解挑人。"]'),
('ebce35aa-b6c6-451f-81fa-e800e130bbbf','戲題睡屏  其二','趙必𤩪','宋','宋诗','song-poetry','','[]','點檢殘枰未了棋，才貪著處轉成低。',32,'全唐诗/poet.song.244000.json','["點檢殘枰未了棋，才貪著處轉成低。", "一番輸後惺惺了，記取從前當局迷。"]'),
('dff24575-435d-43ca-b129-024413065569','戲題睡屏  其三','趙必𤩪','宋','宋诗','song-poetry','','[]','翻覆于郎錦笥看，紅邊墨跡未曾乾。',32,'全唐诗/poet.song.244000.json','["翻覆于郎錦笥看，紅邊墨跡未曾乾。", "宮中怨女今無幾，那得新詩到世間。"]'),
('8c89b150-53fb-4cd6-84e2-3929bab06237','戲題睡屏  其四','趙必𤩪','宋','宋诗','song-poetry','','[]','秋水盈盈嬌眼溜，春山淡淡黛眉輕。',32,'全唐诗/poet.song.244000.json','["秋水盈盈嬌眼溜，春山淡淡黛眉輕。", "人間一段真描畫，喚起王維寫不成。"]'),
('e8f4698f-1460-4836-b9d3-621f44aaeeee','吟社遞至詩卷足十四韻以答之爲梅水村發也  其一','趙必𤩪','宋','宋诗','song-poetry','','[]','鐵石其心腸，冰雪其襟胸。',24,'全唐诗/poet.song.244000.json','["鐵石其心腸，冰雪其襟胸。", "晨陪玉輦遊，夕墮瘴海東。"]'),
('0879eae9-dde0-436d-8a95-b9ec9699bb40','吟社遞至詩卷足十四韻以答之爲梅水村發也  其二','趙必𤩪','宋','宋诗','song-poetry','','[]','蕭艾穢羣芳，草木紛零落。',24,'全唐诗/poet.song.244000.json','["蕭艾穢羣芳，草木紛零落。", "梅花我輩人，例合束高閣。"]'),
('e79182c7-5232-42da-8705-646733d940a1','吟社遞至詩卷足十四韻以答之爲梅水村發也  其三','趙必𤩪','宋','宋诗','song-poetry','','[]','紫薇號舍人，紅荔名郎官。',24,'全唐诗/poet.song.244000.json','["紫薇號舍人，紅荔名郎官。", "梅花隠君子，未可一樣觀。"]'),
('5e30497c-cbe6-4631-8120-e26d529749cb','吟社遞至詩卷足十四韻以答之爲梅水村發也  其四','趙必𤩪','宋','宋诗','song-poetry','','[]','無詩對梅羞，詩成梅花開。',24,'全唐诗/poet.song.244000.json','["無詩對梅羞，詩成梅花開。", "梅自工於詩，歐九却識梅。"]'),
('84f38618-26b3-4f2c-8015-197e2012b6cd','吟社遞至詩卷足十四韻以答之爲梅水村發也  其五','趙必𤩪','宋','宋诗','song-poetry','','[]','霜凋雪剝餘，萬卉生意動。',24,'全唐诗/poet.song.244000.json','["霜凋雪剝餘，萬卉生意動。", "梅花讓羣芳，回施春風供。"]'),
('c838e16b-947c-4516-9b6d-b06ead0e468f','吟社遞至詩卷足十四韻以答之爲梅水村發也  其六','趙必𤩪','宋','宋诗','song-poetry','','[]','欲花未花時，此妙無人知。',24,'全唐诗/poet.song.244000.json','["欲花未花時，此妙無人知。", "著花已多事，更爲花吟詩。"]'),
('598cabd2-1073-4b3c-bb46-34bff5bd3f02','吟社遞至詩卷足十四韻以答之爲梅水村發也  其七','趙必𤩪','宋','宋诗','song-poetry','','[]','子猷癖愛竹，無夢到香影。',24,'全唐诗/poet.song.244000.json','["子猷癖愛竹，無夢到香影。", "雪夜棹匆匆，未必有詩興。"]'),
('3f3ac5bc-4a8a-4bb6-b2c2-ef47fc94e829','吟社遞至詩卷足十四韻以答之爲梅水村發也  其八','趙必𤩪','宋','宋诗','song-poetry','','[]','香魂逐逋去，翠羽招不還。',24,'全唐诗/poet.song.244000.json','["香魂逐逋去，翠羽招不還。", "醉倒趙師雄，一身花影寒。"]'),
('9291e07c-cd24-49ab-b0b1-1929987c1dc9','吟社遞至詩卷足十四韻以答之爲梅水村發也  其九','趙必𤩪','宋','宋诗','song-poetry','','[]','我愛梅花清，梅花憐我癯。',24,'全唐诗/poet.song.244000.json','["我愛梅花清，梅花憐我癯。", "寧爲寒東野，毋爲渴相如。"]'),
('59134821-2c2c-45b7-bac8-3adc43b12ed3','吟社遞至詩卷足十四韻以答之爲梅水村發也  其一○','趙必𤩪','宋','宋诗','song-poetry','','[]','對梅日一醉，無酒如梅何。',24,'全唐诗/poet.song.244000.json','["對梅日一醉，無酒如梅何。", "塵世獨醒人，卑之毋甚高。"]'),
('ec79b868-ac8b-4b47-a7d8-2d0ce83cca6b','吟社遞至詩卷足十四韻以答之爲梅水村發也  其一一','趙必𤩪','宋','宋诗','song-poetry','','[]','水月一聯詩，桃杏不敢近。',24,'全唐诗/poet.song.244000.json','["水月一聯詩，桃杏不敢近。", "卷錦歸之梅，梅花無可遜。"]'),
('68d8275b-19c5-4d2a-a448-5faf947ad3c2','吟社遞至詩卷足十四韻以答之爲梅水村發也  其一二','趙必𤩪','宋','宋诗','song-poetry','','[]','無贄謁梅花，一詩我破戒。',24,'全唐诗/poet.song.244000.json','["無贄謁梅花，一詩我破戒。", "春風如打勘，具有案卷在。"]'),
('f29f6b0e-6ef9-4181-8b13-01b55f9e1be6','吟社遞至詩卷足十四韻以答之爲梅水村發也  其一三','趙必𤩪','宋','宋诗','song-poetry','','[]','梅花老山林，思與天下芳。',24,'全唐诗/poet.song.244000.json','["梅花老山林，思與天下芳。", "瓊花差清白，薦之守維揚。"]'),
('d487a2e7-1334-43cb-a3b7-3c54bae7b264','吟社遞至詩卷足十四韻以答之爲梅水村發也  其一四','趙必𤩪','宋','宋诗','song-poetry','','[]','懷哉丈人行，四海空交游。',24,'全唐诗/poet.song.244000.json','["懷哉丈人行，四海空交游。", "桃李不識面，一生慕荆州。"]'),
('7bdc9b85-e862-45c4-9e3c-c40d6f658531','餞實齋趨朝','趙必𤩪','宋','宋诗','song-poetry','','[]','四海人物如晨星，老成典型公一人。',274,'全唐诗/poet.song.244000.json','["四海人物如晨星，老成典型公一人。", "秋月玉壺光皎皎，飛鸞不驂翔八表。", "寒花晚節紛其香，春風筆底多甘棠。", "景定東南民力竭，天畀福星照南粵。", "盡洗蠻烟瘴雨塵，藥洲草木欣然春。", "至今民拜寬分賜，古有今無此廉吏。", "清風去後凜冰臺，前度劉郎又復來。", "閫府清明民快活，滿腔子仁活潑潑。", "一十四州生意多，海鰲不動紅牙高。", "治平奏最居第一，生平受用惟一實。", "一朝徵入作侍郎，晉陞邃閣侍華光。", "國家多難予誰與，嗣王小毖新求助。", "矧今耆俊莫如公，泰內君子上下同。", "大用之機其在此，周公冢宰毋專美。", "不然成王方幼沖，何爲衮衣赤舄先歸東。", "送公此行登鼎席，南豐瓣香此昕夕。", "他時英俊館翹材，桃樹應思去後栽。"]'),
('2c5cf9d7-2b4e-4355-b660-e9bbbb9569c9','南山賞梅分韻得觀字','趙必𤩪','宋','宋诗','song-poetry','','[]','老梅百窠霸騷壇，崢嶸鐵骨傲歲寒。',181,'全唐诗/poet.song.244000.json','["老梅百窠霸騷壇，崢嶸鐵骨傲歲寒。", "千枝萬枝凍欲槁，一花兩花春尚慳。", "愁聞羌雛吼玉笛，羞見公子馱金鞍。", "芳魂久嫁逋仙去，怨雲恨雨迷孤山。", "憔悴獨醒者，納交惟芷蘭。", "江南窮詩人，鄙哉弟山礬。", "甚而含毫吮墨之俗子，或比之粉面之何郎、玉肌之阿環。", "梅花酷怕渠點涴，所以未破冰雪顔。", "與其玉堂兮金屋，孰若竹籬茅舍幽且閒。", "與其狀元兮宰相，孰若收香斂華林壑間。", "逆知梅意同我意，詩人合作如是觀。"]'),
('3f837112-a560-4b21-a989-4c914d8aa948','贈相士桂月巖','趙必𤩪','宋','宋诗','song-poetry','','[]','昔有道人張巖電，口不言錢似王衍。',64,'全唐诗/poet.song.244000.json','["昔有道人張巖電，口不言錢似王衍。", "却言姓錢不姓張，滑稽玩世名猶香。", "昔有巖電今月巖，月眼神舌和天談。", "江湖賸結貴人知，雖不愛錢猶愛詩。"]'),
('65f1fb17-3308-4081-be6a-00aebb1c5541','生朝觴客即席用韻','趙必𤩪','宋','宋诗','song-poetry','','[]','西風吹客浮仙槎，萬斛詩香散幽遐。',96,'全唐诗/poet.song.244000.json','["西風吹客浮仙槎，萬斛詩香散幽遐。", "瓊裾翠裳佩九霞，賜我羔酒龍團茶。", "剪錦飛落山人家，黄絹幼婦無以加。", "衰賤何足辱齒牙，相看白髪羞黄花。", "西山薇蕨東陵瓜，前村烟雨黄犢車。", "共嚼秋芳咀春華，茅齋飲盡鄰可賒。"]'),
('dfcda1bc-28f2-4e1e-afa8-eba6f7c8ac82','南山亭吟梅用韻','趙必𤩪','宋','宋诗','song-poetry','','[]','玉輦瑶車具，飄飄銀臺路。',60,'全唐诗/poet.song.244000.json','["玉輦瑶車具，飄飄銀臺路。", "羣姬擁蓋羽，太真衣縞素。", "夜宴瓊花圃，玉郎騎鶴赴。", "翠衣凍欲仆，芳信誰傳付。", "無夢高唐賦，酒闌散香霧。"]'),
('8bec3096-d90d-4bb0-8baa-4f63a8c393a7','和同社餞梅','趙必𤩪','宋','宋诗','song-poetry','','[]','花開春意動，花謝春意靜。',144,'全唐诗/poet.song.244000.json','["花開春意動，花謝春意靜。", "逋仙餘詩魂，夢斷孤山境。", "飄零萬斛香，冷落一枝影。", "玉笛聲聲愁，月浸闌干冷。", "吟翁餞梅行，詩句真雋永。", "持螯醉酒船，呼童滌茶皿。", "欲調宰相羹，且歸狀元嶺。", "離騷不知音，激楚鄙鄢郢。", "惟有廣平翁，心腸鐵石勁。", "無花實更奇，此意要人領。", "桃李兒女曹，眼底紛蛙井。", "酒醒動微吟，心下快活省。"]'),
('c878b92d-dc07-4e53-88b6-af59e619443f','和李梅南見寄十四韻','趙必𤩪','宋','宋诗','song-poetry','','[]','公歸乎山中，袖藏經濟策。',156,'全唐诗/poet.song.244000.json','["公歸乎山中，袖藏經濟策。", "恨不雲龍遊，相從老樵石。", "樵溪釀泉甘，樵谷嘉禾殖。", "詩壘壓劉曹，酒國并秦越。", "與其千戶侯，何如千畝漆。", "文星耿在目，龍門兮咫尺。", "天風墮珠璣，捧玩手不釋。", "斧鉞太森嚴，句法尤峭拔。", "奈何士也賤，至寶道傍擲。", "平生釣鰲手，烹鮮抑何屑。", "簞食與豆羹，豈足動顔色。", "閒愁惱吟腸，義利自爲敵。", "相逢開口笑，無怨亦無德。"]'),
('2bcec04c-04d4-42fc-afc3-599eb1aed59d','遊濂泉','趙必𤩪','宋','宋诗','song-poetry','','[]','星巖高哉不知其幾千丈兮，下有儒宮上接青雲梯。',235,'全唐诗/poet.song.244000.json','["星巖高哉不知其幾千丈兮，下有儒宮上接青雲梯。", "綠凹鑿破冰泉冽，泉以濂名宗濂溪。", "濂翁去今凡幾載，一脈流通無窒礙。", "光風霽月此山中，景物因人成勝概。", "亭翼翼，水泠泠，一清不著點子塵。", "眼前色色俱呈露，何必解蘭縛塵纓。", "君不見孤山六一泉，硯州包公井。", "君子之澤深且長，清風千古霜凜凜。", "我欲採薇隠此山，祇恐林慚澗恧鎖松關。", "我欲祠下筆一詞，又恐寒泉痛洗凝之詩。", "解襟坐石濯清泠，一歃寒冰和露飲。", "雪我酒腸霜詩脾，此身疑在神仙境。", "倩君爲問玉皇借玉鞭，鞭起睡龍騎上天。", "持此一瓢濂翁泉，一雨炎荒洗蠻烟。"]'),
('d65004f5-844e-4be8-ab74-e4fa80d8c267','陸戶有摴蒱之招詩以答之','趙必𤩪','宋','宋诗','song-poetry','','[]','局促束縮抱羈獨，頹然一我恧兮俗。',171,'全唐诗/poet.song.244000.json','["局促束縮抱羈獨，頹然一我恧兮俗。", "酒病昏沈無詩醫，詩腸枯槁欠酒沃。", "閒窗坐與周公交，焚香痛把楚騷讀。", "世情冷暖故人疏，笑殺和靖鱉頭縮。", "夜長燈明弔影孤，無情紅粉不可呼。", "夢中猛省京華事，圍紅擁翠邀博徒。", "銀燭高燒海棠暖，醉豪一喝雉成盧。", "贏却翠裘六郎恨，丈夫此樂天下無。", "君不見劉毅家四壁，百萬祇一擲。", "袁耽少不羈，破帽懷相隨。", "逢場作戲政不惡，大抵人生樂其樂。"]'),
('52d172db-64d5-474f-89c2-4d6ac900909c','古端飲問梅亭作','趙必𤩪','宋','宋诗','song-poetry','','[]','把酒問梅開未開，梅花問我何時來。',234,'全唐诗/poet.song.244000.json','["把酒問梅開未開，梅花問我何時來。", "嫣然一笑醒塵夢，撩我詩興寬酒懷。", "有梅無詩酒懷惡，有詩無酒羈味薄。", "一觴一咏暢幽情，人生須作及時樂。", "去年嶺頭曾相逢，花邊釃酒酹師雄。", "霜月三更天似水，枝頭翠鳥睡正濃。", "今年寒淺花較遲，一花兩花時最奇。", "春多爛漫無意思，此意梅花知不知。", "孤山寂寞逋仙去，香影之後更無句。", "幾回擬作梅花騷，無力其如梅花何。", "懷哉此花丈人行，冰清玉潔不做時粧樣。", "紛紛桃李嫁春風，臭味未必與我同。", "莫說和羹事，和羹事猶未。", "莫羨玉堂人，玉堂人已陳。", "細把心期向梅說，花開花落有時節。"]'),
('069d4de4-a48d-4bfa-af2e-4400fd3bfb93','和同社酒邊韻','趙必𤩪','宋','宋诗','song-poetry','','[]','規規爲愚傲爲穎，晨華夕喪何足逞。',80,'全唐诗/poet.song.244000.json','["規規爲愚傲爲穎，晨華夕喪何足逞。", "對山悠然此心領，誰歌白雪妙於郢。", "題破蜀牋爲紅杏，晝遊苦短燭堪秉。", "愧我寒蜩嘒如哽，墮身千仞求長綆。", "移文鷗社盟莫冷，共嚼梅花醉香影。"]'),
('7dfeec3f-b199-4a58-9f55-5a384fcc9309','重九即席點韻','趙必𤩪','宋','宋诗','song-poetry','','[]','淵明我輩人，豈爲口體累。',144,'全唐诗/poet.song.244000.json','["淵明我輩人，豈爲口體累。", "歸歟三逕秋，清吟發幽寄。", "醒眼對黄花，陶然已心醉。", "世俗兒女情，飲菊萸繫臂。", "長房果神仙，登高未爲智。", "落帽狂參軍，聲利窮所嗜。", "興來盡君歡，得句輸杜二。", "牛山淚沾衣，鄙哉馬千駟。", "悠然千載吟，高韻未易次。", "人生聚幾何，此意非酒爲。", "徜徉林壑遊，磊落湖海義。", "明年此會日，老健天所賜。"]'),
('4471e349-0805-495b-af26-fece24d61490','和李梅南對梅韻','趙必𤩪','宋','宋诗','song-poetry','','[]','三花兩花疏籬東，玉堂何似茅舍中。',146,'全唐诗/poet.song.244000.json','["三花兩花疏籬東，玉堂何似茅舍中。", "孤芳不受春風涴，千紅萬紫俱下風。", "羅浮夢斷孤山杳，寂寂誰躡二子蹤。", "謫仙天人霸梅國，騷壇萬仞奴羣雄。", "我交梅花二十冬，梅工於詩例合窮。", "我窮於梅詩更拙，豈無膏沐誰爲容。", "湘纍醒眼不相識，蘭芷未必臭味同。", "何時典衣買酒醉梅下，澆我磊落寫我悰。", "詩成閣筆對梅笑，此一瓣香爲梅翁。"]'),
('93ecd01f-b071-4fd2-a27b-24123e27bf1c','即席點韻賦方硯','趙必𤩪','宋','宋诗','song-poetry','','[]','一片端溪雲，至寶俗眼驚。',120,'全唐诗/poet.song.244000.json','["一片端溪雲，至寶俗眼驚。", "體方而質剛，翰林叨寵榮。", "楮君同出處，松侯難弟兄。", "紫肝馬膚潤，綠暈鴝眼明。", "自笑謫仙狂，曾倩妃子擎。", "我愛清廟瑟，人吹高門笙。", "龍尾與鳳咮，圓巧相逢迎。", "吾友管城公，奚假乎猩猩。", "留此鎮山房，移文鷗鷺盟。", "好方已成癖，焉用圓爲卿。"]'),
('ede9d7d4-6ef6-4924-b6fe-1a4d3e690e72','挽李春叟','趙必𤩪','宋','宋诗','song-poetry','','[]','靖節有詩題晉號，德公無意入襄城。',32,'全唐诗/poet.song.244000.json','["靖節有詩題晉號，德公無意入襄城。", "蓬鬢早因時事白，荷衣不受刦塵污。"]'),
('99a10a44-61eb-450f-b127-8dfbae8642bf','句','趙必𤩪','宋','宋诗','song-poetry','','[]','詩人只合住茅屋，天下未嘗無菜羹。',16,'全唐诗/poet.song.244000.json','["詩人只合住茅屋，天下未嘗無菜羹。"]'),
('d32770ff-5d68-40fb-a29d-5ec348d4a174','德驥篇','孫巖','宋','宋诗','song-poetry','','[]','西家白馬如曳練，東家赤馬如驅電。',192,'全唐诗/poet.song.244000.json','["西家白馬如曳練，東家赤馬如驅電。", "時時并轡刷長鞦，羞殺分飛伯勞燕。", "白馬不防牛有角，慘甚兵間中矛矟。", "不出能令赤馬疑，隔巷來奔初不約。", "躊躇血地嘶鳴哀，悲風颯颯驚條枚。", "皦然德驥非凡材，牧人驅迫去復回。", "物於儔匹且如此，何况世間貞信士。", "管仲敗餘勤鮑叔，孝章厄極悲文舉。", "茂弘將坐白其忠，叔翰當收脫之死。", "乞兵欲赴雍丘危，突圍竟雪都昌耻。", "雖云志計有伸屈，至今撓弱聞風起。", "利災樂禍無故情，東家無恙汝得乘。"]'),
('99581c2d-2f90-4491-b8fd-28de9a847ce5','去冬過石潭上時吳義夫同行欣然謂予曰詩境甚佳今日再過有作將寄義夫','孫巖','宋','宋诗','song-poetry','','[]','長潭有令姿，山綠納空洞。',120,'全唐诗/poet.song.244000.json','["長潭有令姿，山綠納空洞。", "軒軒吳武陵，曾此接飛鞚。", "殷勤顧我笑，詩材不勝用。", "重來春事深，物采尤錯綜。", "褚小强懷大，秀異肯受控。", "沈吟日已昃，十彀纔一中。", "故人抱才藻，衆象入嘲弄。", "即今溫水館，匡坐教弦誦。", "嗟哉實前語，束葦代杗棟。", "明當寄東風，烟水發清夢。"]'),
('c0537624-6b75-4e5d-a4fd-e68b499c5969','留武林','孫巖','宋','宋诗','song-poetry','','[]','訪客城南隅，故第何其雄。',108,'全唐诗/poet.song.244000.json','["訪客城南隅，故第何其雄。", "曲池猶瀁漭，土山尚巃嵷。", "頗聞此中人，易姓良匆匆。", "往時恩澤侯，意氣干晴虹。", "樂曲播秦城，衣制聞漢宮。", "恨不逢季倫，詎肯交毛公。", "斥地西鄰去，伐木南山空。", "百楹一傳舍，顧極當年工。", "悠悠感成敗，何獨操鏝翁。"]'),
('26511735-30c6-40df-be90-9978163478e9','德藝有貴賤','孫巖','宋','宋诗','song-poetry','','[]','調弓遣猿悲，削鐻奪神造。',72,'全唐诗/poet.song.244000.json','["調弓遣猿悲，削鐻奪神造。", "伊人天分高，甘以一事老。", "奈何握寸穎，特自矜粉藻。", "沈約僅如奴，子建何足道。", "率爾爲一快，公論日杲杲。", "德藝有貴賤，君子廓懷抱。"]'),
('29067800-a997-4cf4-8859-4c023e91799c','繞行遇獵','孫巖','宋','宋诗','song-poetry','','[]','搜山炬火縱橫飛，百獸猝起驚且馳。',128,'全唐诗/poet.song.244000.json','["搜山炬火縱橫飛，百獸猝起驚且馳。", "出明入暗眼光亂，强者或脫弱者悲。", "兒郎洶洶山精匿，殺氣隨風撼松櫟。", "宋㹱韓獹不盡縱，齧索騰陵求赴敵。", "清霜屢降草莽衰，相與即禽真汝時。", "跳坡驀澗殊未已，扶桑東面推紅曦。", "大矟將軍山下住，摧頹略記銜枚路。", "觀汝角逐心悠悠，風梟旌斾何時休。"]'),
('c90c6626-35ec-4e33-8eeb-9db4c88a7f42','觀漁行','孫巖','宋','宋诗','song-poetry','','[]','霜降平湖鑑羣象，中有黄魚幾一丈。',120,'全唐诗/poet.song.244000.json','["霜降平湖鑑羣象，中有黄魚幾一丈。", "漁師早已中豪家，今旦連舟布新網。", "東西南北三重圍，圍形漸縮如小池。", "孟獲身窮呂布窘，尚許性命延斯須。", "舊與鱒魴同出入，爾暇悲憐禍相及。", "日斜創甚上平沙，兩岸居人如堵立。", "渺渺腥風吹水雲，賣魚沽酒賽湖神，醉來預唱江南春。"]'),
('50563e76-2491-4c54-8572-d116ea3deed9','和元京兄賦蘋花','孫巖','宋','宋诗','song-poetry','','[]','一春觀物眼，紅紫厭繽紛。',48,'全唐诗/poet.song.244000.json','["一春觀物眼，紅紫厭繽紛。", "此水浮明玉，何人翦白雲。", "惠風遊漢女，吉日禮湘君。", "地僻應無是，留花混藻芹。"]'),
('daa3dcd8-664c-4d2c-9e15-de17b53ebe8e','兵後績溪道中','孫巖','宋','宋诗','song-poetry','','[]','古道緣流水，寒郊带斷烟。',48,'全唐诗/poet.song.244000.json','["古道緣流水，寒郊带斷烟。", "稀疏鴉種麥，羞澀女耕田。", "人事休兵後，秋懷落木前。", "小蘇遺翰墨，今古一山川。"]'),
('cfc7211c-df59-4943-a16e-544e9ae66ff1','陳監丞用韻見贈亦和以謝','孫巖','宋','宋诗','song-poetry','','[]','肅肅東方老，依人可計年。',48,'全唐诗/poet.song.244000.json','["肅肅東方老，依人可計年。", "名言傾蓋後，古意結繩前。", "君戶仍多轍，予琴故一弦。", "不應昌歜味，置在衆肴先。"]'),
('a2a7fd42-9a76-46dd-ac45-a4e2c557af04','九日呈戴兄','孫巖','宋','宋诗','song-poetry','','[]','一別三十載，而今近講堂。',48,'全唐诗/poet.song.244000.json','["一別三十載，而今近講堂。", "蕭條同甲子，强健又重陽。", "萸菊數杯酒，烟雲千仞岡。", "偶然爲此夢，寧復次公狂。"]'),
('b57a0336-240d-455f-800b-879580cf3675','金庭觀王右軍祠','孫巖','宋','宋诗','song-poetry','','[]','罷郡歸來三畝宅，化爲琳宇入層雲。',64,'全唐诗/poet.song.244000.json','["罷郡歸來三畝宅，化爲琳宇入層雲。", "樓亡莫辨藏書地，池在如親洗墨人。", "特援憂勤規太傅，不將恢復許中軍。", "世間何物無澌盡，英榘千秋萬古新。"]'),
('45ef7ac9-2a64-4247-8a5e-a58127593b0e','出越城舟行乙夜紆道以避過兵','孫巖','宋','宋诗','song-poetry','','[]','擾擾紅巾起草間，舊遊何地不凋殘。',64,'全唐诗/poet.song.244000.json','["擾擾紅巾起草間，舊遊何地不凋殘。", "歸囊薄有桃花米，行路如經竹節灘。", "戰馬東來橫殺氣，扁舟北去解憂端。", "曲肱便結須臾夢，柳暗黟川把釣竿。"]'),
('2d05bb01-ca29-45bf-83b0-0f0e060c0d08','酬趙隠君還予詩稿之作因來韻增至二十四用柳子厚同劉院長言懷事詩例也','孫巖','宋','宋诗','song-poetry','','[]','度德宜滕長，論交墮魯臯。',288,'全唐诗/poet.song.244000.json','["度德宜滕長，論交墮魯臯。", "淒凉當歲晚，瀟灑見時髦。", "常恐詩無證，空知調欲高。", "扶疏纔社櫟，變化豈胥濤。", "闊略三冬學，增多一字褒。", "大篇參往籙，異事詫吾曹。", "昔嗜梁臺選，仍耽郢士騷。", "長歌落澗谷，中夜駭猿猱。", "攻苦鵜濡翼，求朋鹿食蒿。", "家無彥弘在，鄉失呂溫豪。", "擊拊當誰聽，荒蕪尚自薅。", "英英善和柳，皎皎義熙陶。", "步驟才難至，圖回首屢搔。", "較深搜石髓，務潔取溪毛。", "推激吾非黨，譏訶物得逃。", "辭連盤谷稼，想到武陵桃。", "朝逮虞淵暗，宵幾鶡旦嗷。", "含愁全庾賦，寓樂間莊濠。", "不謂塵明鏡，何殊贈佩刀。", "音書無雁往，時序迫蟬號。", "嵇向諸人遠，周雷再世遭。", "未應求善賈，孰不飲醇醪。", "並席葭依玉，清言輠炙膏。", "斯期方緬邈，北望寸心勞。"]'),
('642c12ed-b5cd-4da0-9f58-fc73275e626c','山間','孫巖','宋','宋诗','song-poetry','','[]','谷鳥鳴聲滑，山雲變態新。',24,'全唐诗/poet.song.244000.json','["谷鳥鳴聲滑，山雲變態新。", "清渠不沒脛，亦有浣紗人。"]'),
('4e2dda35-1970-46ca-80c9-9d8aaa078324','武林絕句  其一','孫巖','宋','宋诗','song-poetry','','[]','繽紛迎酒伎，宛轉賣花聲。',24,'全唐诗/poet.song.244000.json','["繽紛迎酒伎，宛轉賣花聲。", "偶似承平世，携書試鳳城。"]'),
('1f26fa2f-f84b-47bc-aa90-43bd27e757c9','武林絕句  其二','孫巖','宋','宋诗','song-poetry','','[]','比屋單衣日，名城冷食天。',24,'全唐诗/poet.song.244000.json','["比屋單衣日，名城冷食天。", "居人多上塚，遠客未歸田。"]'),
('57139c57-d936-4ef6-9a81-e4523529af08','秋晚園中  其一','孫巖','宋','宋诗','song-poetry','','[]','籬落圍秋色，株梢罥晚暉。',24,'全唐诗/poet.song.244000.json','["籬落圍秋色，株梢罥晚暉。", "菊花供麴盡，桐葉飼魚稀。"]'),
('cac30995-d16f-4630-8e1f-c60558e315d9','秋晚園中  其二','孫巖','宋','宋诗','song-poetry','','[]','風葉相仍下，家童未埽除。',24,'全唐诗/poet.song.244000.json','["風葉相仍下，家童未埽除。", "綿聯封蟄戶，殘缺带蟲書。"]'),
('2eca34df-9b21-4ebc-ba9e-dffb25c9e577','初歸','孫巖','宋','宋诗','song-poetry','','[]','湖蹤海跡一飛蓬，千里常隨莽蕩風。',32,'全唐诗/poet.song.244000.json','["湖蹤海跡一飛蓬，千里常隨莽蕩風。", "今日抵家籬犬噪，不知身是主人翁。"]'),
('c7f1a8bb-7d79-4321-a03a-2b7aabfd1f6f','樹陰','孫巖','宋','宋诗','song-poetry','','[]','春去空山啼乳鶑，鶑邊老樹冪新青。',32,'全唐诗/poet.song.244000.json','["春去空山啼乳鶑，鶑邊老樹冪新青。", "一瓢挂此坐終日，即是蘇家擇勝亭。"]'),
('88509d35-4bc7-4f84-93ea-af1396296c3f','溪上','孫巖','宋','宋诗','song-poetry','','[]','溪翁生計獨熙然，新買南鄰舴艋船。',32,'全唐诗/poet.song.244000.json','["溪翁生計獨熙然，新買南鄰舴艋船。", "日載鸕鷀三十尾，魚爲租入水爲田。"]'),
('f1ed074a-3ffd-428b-b695-c3e5a7495071','寓齋','孫巖','宋','宋诗','song-poetry','','[]','環中風物有誰爭，即日詩情取次生。',32,'全唐诗/poet.song.244000.json','["環中風物有誰爭，即日詩情取次生。", "雲倦竟依簷際宿，雉馴時下竹根行。"]'),
('0701ac96-7686-45fe-8aa2-b0705d77c9c1','別鄉人席間作','孫巖','宋','宋诗','song-poetry','','[]','昔向率山別，離愁尚故鄉。',48,'全唐诗/poet.song.244000.json','["昔向率山別，離愁尚故鄉。", "今來嵊亭聚，縱樂是殊方。", "新草偷江綠，垂陽配酒黄。", "子仍先我去，留滯奈耕桑。"]'),
('b2fafed8-becf-41bc-ab01-45e5eee50615','崿浦早望','孫巖','宋','宋诗','song-poetry','','[]','千峰倒影碧粼粼，摹寫桐江最逼真。',32,'全唐诗/poet.song.244000.json','["千峰倒影碧粼粼，摹寫桐江最逼真。", "每逢佳處謀書屋，漸恐山靈不信人。"]'),
('781d602d-1bb2-44e6-ae89-62d34d298a85','元夕八首  其一','陳世崇','宋','宋诗','song-poetry','','[]','看燈螃蟹月前供，迓鼓金銷畫領中。',32,'全唐诗/poet.song.244000.json','["看燈螃蟹月前供，迓鼓金銷畫領中。", "簾捲重樓燈乍試，柳稍風暖雪初融。"]'),
('7874b0e1-302a-43bc-ae63-2cfb48131351','元夕八首  其二','陳世崇','宋','宋诗','song-poetry','','[]','蒼頭喝道燭光微，梅壓烏雲柳壓眉。',32,'全唐诗/poet.song.244000.json','["蒼頭喝道燭光微，梅壓烏雲柳壓眉。", "打塊成團嬌又顫，閙蛾簇簇翠冠兒。"]'),
('bb1931f3-e48b-4345-bfcc-1f7f7f693e98','元夕八首  其三','陳世崇','宋','宋诗','song-poetry','','[]','風飄蹀躞步摇輕，相喚相呼去看燈。',32,'全唐诗/poet.song.244000.json','["風飄蹀躞步摇輕，相喚相呼去看燈。", "笑整玉梅藏素手，香肩三角卸吳綾。"]'),
('3835017a-996e-4b92-a1d3-6fae0e81d072','元夕八首  其四','陳世崇','宋','宋诗','song-poetry','','[]','麝圓䭔拍澄沙團，餶飿糖霜乳橘盤。',32,'全唐诗/poet.song.244000.json','["麝圓䭔拍澄沙團，餶飿糖霜乳橘盤。", "蕉葉柿花宜利少，叫聲渾雜市聲歡。"]'),
('81bd262f-a70c-4781-82cb-bd240846b962','元夕八首  其五','陳世崇','宋','宋诗','song-poetry','','[]','買市今宵看帥臣，九衢車馬隘香塵。',32,'全唐诗/poet.song.244000.json','["買市今宵看帥臣，九衢車馬隘香塵。", "歡呼百姓同霑惠，無限攙行賣卜人。"]'),
('82cfafcd-6081-492e-8ebb-536b9e4ec61a','元夕八首  其六','陳世崇','宋','宋诗','song-poetry','','[]','女童清樂玉琮琤，一道群絲緩合笙。',32,'全唐诗/poet.song.244000.json','["女童清樂玉琮琤，一道群絲緩合笙。", "更看蘇家坊傀儡，軟風嬌送杵歌聲。"]'),
('c4d483d5-bfe7-4b87-b938-a263a182b292','元夕八首  其七','陳世崇','宋','宋诗','song-poetry','','[]','天街簫鼓厭繁華，靜訪湖山釋子家。',32,'全唐诗/poet.song.244000.json','["天街簫鼓厭繁華，靜訪湖山釋子家。", "珍玩圖書尤絢眼，選僧堂裏萬蓮華。"]'),
('ab33799e-b97b-4341-a512-57a69cd9dcbe','元夕八首  其八','陳世崇','宋','宋诗','song-poetry','','[]','寒星萬點御香飄，和氣潜回積雪消。',32,'全唐诗/poet.song.244000.json','["寒星萬點御香飄，和氣潜回積雪消。", "盈耳嵩呼聲不絕，熙熙春意入簫韶。"]'),
('43e0570c-99dd-45bd-8b7d-85f0e138683b','題曾氏諸帖','陳世崇','宋','宋诗','song-poetry','','[]','南豐而後艇齋君，忠義詞章萃一門。',32,'全唐诗/poet.song.244000.json','["南豐而後艇齋君，忠義詞章萃一門。", "手澤流芳凌劫火，欽承猶得到來孫。"]'),
('4a6a6e73-a80a-46bc-a756-9e5943a2619b','送陳隨隠遊廬山  其一','黄鵬飛','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','天下廬山第一奇，西風楚楚送行時。',32,'全唐诗/poet.song.244000.json','["天下廬山第一奇，西風楚楚送行時。", "晦庵白鹿書猶在，非是游山只愛詩。"]'),
('94644131-d793-484c-afe1-f42f2632ad1f','送陳隨隠遊廬山  其二','黄鵬飛','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','曾從圖畫識廬山，山好誰知畫亦難。',32,'全唐诗/poet.song.244000.json','["曾從圖畫識廬山，山好誰知畫亦難。", "畫好不如詩好讀，就煩詩筆畫來看。"]'),
('1c64c9fb-0c27-465e-8c82-95272c522b4c','庚辰九日陳世崇來訪說偈','釋珍南州','宋','宋诗','song-poetry','','[]','從上行不到處行，取步步登高。',61,'全唐诗/poet.song.244000.json','["從上行不到處行，取步步登高。", "從上說不到處說，取言言見諦。", "白酒釀千家，黄花開滿地。", "噫嘻，陶淵明若知有今此世界，終不執着東籬。"]'),
('e80e02c3-5331-47e1-8271-5a1289d0c0b3','辛巳陳世崇來訪說偈','釋常竹塢','宋','宋诗','song-poetry','','[]','一藏一切藏，錯。',55,'全唐诗/poet.song.244000.json','["一藏一切藏，錯。", "隨隠隨時隠，錯。", "靄靄春雲，眼中金屑。", "直饒并到帝王前，總是一團閑落索。", "這落索，天將以夫子爲木鐸。"]'),
('8e9a3cd1-8fbd-4f80-8b95-de0d94ef5cb3','心遠堂','高晞遠','宋','宋诗','song-poetry','','[]','種竹期十年，栽橘盈千頭。',108,'全唐诗/poet.song.244000.json','["種竹期十年，栽橘盈千頭。", "雖云多遠慮，無乃爲身謀。", "高人絕塵累，俟德居此丘。", "泰宇無畦畛，虛空有天游。", "仁義尚蘧廬，道德成安流。", "結茅依翠微，極目際平疇。", "白雲度寥廓，黄鵠下滄洲。", "百世此周覽，我志尚可求。", "祇應柴桑翁，真趣共悠悠。"]'),
('6b98f485-34ef-4e04-8a45-0f8f8a3e00af','春信','程徹','宋','宋诗','song-poetry','','[]','蕭條冬事堂堂去，拍塞韶光點點開。',32,'全唐诗/poet.song.244000.json','["蕭條冬事堂堂去，拍塞韶光點點開。", "明月清風遮不斷，暗香時入夢中來。"]'),
('c7dc41a1-a171-43ed-981d-08905f4df41e','次韻答李景陽','柯舉','宋','宋诗','song-poetry','','[]','客有扣舷者，悠然太古音。',48,'全唐诗/poet.song.244000.json','["客有扣舷者，悠然太古音。", "風清來水面，月白滿江心。", "世既嘆途絕，君何愛我深。", "愧將瓦缶句，聊以答南金。"]'),
('2a1cd2e4-19a3-48c6-8cc8-23305b4c622f','遊華嚴寺','柯舉','宋','宋诗','song-poetry','','[]','舊遊曾記此山川，萬事回頭一夢然。',64,'全唐诗/poet.song.244000.json','["舊遊曾記此山川，萬事回頭一夢然。", "蚤歲不知人易老，晚年方信世無禪。", "樵歌牧唱千村暮，鶑語花香二月天。", "人境了然描不就，山僧對我更談玄。"]'),
('67b83a12-0177-4ef2-ac92-1c934fe26e19','題幟','牟大昌','宋','宋诗','song-poetry','','[]','大宋忠臣牟大昌，義兵今起應天祥。',32,'全唐诗/poet.song.244000.json','["大宋忠臣牟大昌，義兵今起應天祥。", "赤城雖已降爲虜，黄山不願爲之氓。"]'),
('ef966ffd-cefa-461d-96d8-0835f88cbbb0','凌波辭賦水仙花','彭九萬','宋','宋诗','song-poetry','','[]','歲芳兮婉冉悲，江空兮蘭枻歸。',124,'全唐诗/poet.song.244000.json','["歲芳兮婉冉悲，江空兮蘭枻歸。", "人嬋媛兮胡來遲，憺風魂兮佩誰思。", "素衣兮儼黄裏，玉襦兮蒙翠被。", "明波渟渟兮渺愁予，含香懷春兮中心苦。", "昔遺褋兮今契闊，佇佳期兮窅修絕。", "幻塵緣兮謇中憂，時既晏兮不可留。", "汎雲軿兮水裔，糺予瑟兮難理。", "人奚歸兮路蒼茫，湘有皋兮春綠起。"]'),
('5c551623-2be7-4a81-8d33-26b35ae569db','界牌鋪','彭九萬','宋','宋诗','song-poetry','','[]','地僻人家早掩關，行人忙逐暮鴉還。',32,'全唐诗/poet.song.244000.json','["地僻人家早掩關，行人忙逐暮鴉還。", "急風花落隔牆樹，暗雨鳥啼何處山。"]'),
('55f4ae3a-6d53-4cf6-9638-6f38d62f5f23','命子篇','趙友直','宋','宋诗','song-poetry','','[]','悠悠我祖，肇自軒轅。',160,'全唐诗/poet.song.244000.json','["悠悠我祖，肇自軒轅。", "迄於趙城，因而氏焉。", "漢家涿郡，繼族於燕。", "卜遷大梁，世系綿綿。", "宋自中葉，徙都南塘。", "武顯扈蹕，聿居虞鄉。", "於赫文杏，奕世其芳。", "符德象賢，譜牒有光。", "顧及於我，時運倏傾。", "族居萍散，遂殞家聲。", "苫塊餘息，僅存其形。", "於焉有心，冀我後生。", "後生是畏，聖謨炳如。", "維時孜孜，無忝厥初。", "豈不爾念，爲惜居諸。", "無後非孝，匪才若虛。"]'),
('1da9c523-4c93-47cd-a433-731c3e0fb990','墓廬追親','趙友直','宋','宋诗','song-poetry','','[]','萬古維乾坤，一生資父母。',48,'全唐诗/poet.song.244000.json','["萬古維乾坤，一生資父母。", "乾坤春復春，父母恩難補。", "瞻彼林中烏，猶能懷反哺。", "矧茲六尺軀，不念劬勞苦。"]'),
('b525db44-d6c1-4a28-82f4-3363961090f9','卜居二首  其一','趙友直','宋','宋诗','song-poetry','','[]','出郭雖超俗，塵囂亦蕃駢。',60,'全唐诗/poet.song.244000.json','["出郭雖超俗，塵囂亦蕃駢。", "以此感日蹙，擬耕牛山田。", "溪湖相輸灌，扁舟恣洄沿。", "似茲安樂徑，允可置一椽。", "匪自耽寥寂，與彼墳墓牽。"]'),
('16de5873-6caf-4984-9232-50bbfdfc456b','卜居二首  其二','趙友直','宋','宋诗','song-poetry','','[]','吾宗本郊居，勤儉歷幾世。',60,'全唐诗/poet.song.244000.json','["吾宗本郊居，勤儉歷幾世。", "禮失于野求，力耕真吾事。", "古稱識時務，必在賢與智。", "用貽厥孫謀，無爲忽去此。", "去此亦不難，安居亡所恃。"]'),
('cd5e47fd-5955-44a1-839d-50b4bd7ad9f7','秋夜宿瑞象寺寫懷','趙友直','宋','宋诗','song-poetry','','[]','秋高天宇肅，草際霜華冷。',72,'全唐诗/poet.song.244000.json','["秋高天宇肅，草際霜華冷。", "明月流清光，徘徊薜蘿影。", "予抱千古懷，其將爲誰騁。", "興衰感人事，代謝悲流景。", "長歌紫芝篇，醉卧赤松徑。", "斯亦聊且娛，榮華非所競。"]'),
('4a462228-454d-47d9-b148-8b1bc6eedf66','贈表弟陳萊壽','趙友直','宋','宋诗','song-poetry','','[]','爾自髫𩬔年，期已領鶚薦。',72,'全唐诗/poet.song.244000.json','["爾自髫𩬔年，期已領鶚薦。", "兩浙多賢豪，論交皆北面。", "徊翔踰幾春，尚未輸夙願。", "匪無才與猷，良乏明時眷。", "力田逢少年，處囊陡爾見。", "事績炳寰區，聲華流海甸。"]'),
('a47efad2-9e16-4db9-8585-3b7054b05811','擬古二首  其一','趙友直','宋','宋诗','song-poetry','','[]','聖王創立制，先務正經界。',84,'全唐诗/poet.song.244000.json','["聖王創立制，先務正經界。", "羣侯肆兼併，井田隨破壞。", "經界紊其坊，曷所辨中外。", "三王化邈矣，五霸迭相代。", "仲父作內政，兵與農胥頼。", "列辟已無周，重俾宗且戴。", "偉哉九合功，願執鞭相待。"]'),
('d5c28515-62ef-430d-8bcb-2947e99ff771','擬古二首  其二','趙友直','宋','宋诗','song-poetry','','[]','堂堂谷中室，草木恒相鄰。',84,'全唐诗/poet.song.244000.json','["堂堂谷中室，草木恒相鄰。", "頃緣出遊衍，室內虛無人。", "犬羊窺我間，蹄蹟分擾馴。", "穢我衣裳區，安所置其身。", "翹然起遐思，結屋依湖濱。", "手執羲皇卷，門栽五柳春。", "春風一披拂，意恐緇泥塵。"]'),
('2d324136-5f2b-4333-b1db-4d1d4a170d40','讀靖節集','趙友直','宋','宋诗','song-poetry','','[]','羲皇世遠矣，聖道久粃糠。',84,'全唐诗/poet.song.244000.json','["羲皇世遠矣，聖道久粃糠。", "縱有魯中叟，彌縫猶未遑。", "況復經秦火，燼末誰能匡。", "赤帝按劍起，犄角重傍徨。", "天運如此耳，不飲之何方。", "壺觴輒自引，未肯須臾忘。", "匪苟好沉湎，逃名託醉鄉。"]'),
('85a59828-d5f8-4f64-9cc6-44be11e46d92','贈徐樵隠','趙友直','宋','宋诗','song-poetry','','[]','天命靡有常，空視時運覆。',108,'全唐诗/poet.song.244000.json','["天命靡有常，空視時運覆。", "珍重山間翁，抱道庸自玉。", "掀髯發清興，開軒恣遐矚。", "空谷閴無人，惟有雲相逐。", "山翁爲有知，戀戀情綣縟。", "綣縟林中薪，歌已禽聲續。", "勿謂有傾頹，維心常位育。", "顧我無依歸，猶然嗜幽獨。", "願結金蘭交，共茲南山麓。"]'),
('1ec287d3-6656-4ac7-a810-fea94c55c3b1','歸田園居和陶淵明韻','趙友直','宋','宋诗','song-poetry','','[]','舉世墮塵網，我獨愛丘山。',120,'全唐诗/poet.song.244000.json','["舉世墮塵網，我獨愛丘山。", "舊業久荒蕪，不去待何年。", "棲烏戀故枝，潜魚樂深淵。", "物類各有托，予盍歸田園。", "决水渠雙注，藏書居數間。", "孤松挺後簷，五柳栽門前。", "渺渺綴浮雲，淡淡籠輕煙。", "蛙鼓池塘畔，鶴唳溪山巔。", "微軀足爲樂，稚子堪陪閑。", "不受樊籠繫，靈臺復自然。"]'),
('c4bd0ef5-0391-4d1b-a03a-c7cf6daaf763','送春','趙友直','宋','宋诗','song-poetry','','[]','宿雨淹無霽，落花翠點苔。',24,'全唐诗/poet.song.244000.json','["宿雨淹無霽，落花翠點苔。", "東君今日去，借問幾時回。"]'),
('994c4e98-3d91-40db-9d08-bc06824179ab','端午','趙友直','宋','宋诗','song-poetry','','[]','節遇端陽日，蒲觴滿自斟。',24,'全唐诗/poet.song.244000.json','["節遇端陽日，蒲觴滿自斟。", "興懷多感舊，弔古漫成吟。"]'),
('a9dad986-1c6b-4694-9ded-b63fda699ee6','七夕','趙友直','宋','宋诗','song-poetry','','[]','一葉井梧飄，雙星忽相值。',24,'全唐诗/poet.song.244000.json','["一葉井梧飄，雙星忽相值。", "却憐參與商，晤會當何夕。"]'),
('2bac6b80-25e7-49c0-823b-a9b0178a1629','初晴','趙友直','宋','宋诗','song-poetry','','[]','久雨初收霽，開窗動我情。',24,'全唐诗/poet.song.244000.json','["久雨初收霽，開窗動我情。", "野花含宿淚，山鵲弄新聲。"]'),
('468b5ccd-72ce-4e55-a1fb-b868aa3e3643','贈行','趙友直','宋','宋诗','song-poetry','','[]','無酒不成別，無詩別不成。',24,'全唐诗/poet.song.244000.json','["無酒不成別，無詩別不成。", "別君詩一首，馬上酒三行。"]'),
('59e13d65-e8c2-4af2-85ac-35adb469b440','景物','趙友直','宋','宋诗','song-poetry','','[]','景物撩人□，興思百念攢。',24,'全唐诗/poet.song.244000.json','["景物撩人□，興思百念攢。", "亨屯原有定，呼酒拚紅顔。"]'),
('942f4786-44ae-48e4-9929-fa9e9b7ab2ff','憶攢宮','趙友直','宋','宋诗','song-poetry','','[]','山河繞故封，常照舊時月。',24,'全唐诗/poet.song.244000.json','["山河繞故封，常照舊時月。", "獨有會稽陵，蕭然成狐窟。"]'),
('ccd9306c-5ea5-44f6-ba06-01a17743185a','瞻蘭芎山','趙友直','宋','宋诗','song-poetry','','[]','蘭芎圍絕嶂，圖畫望中懸。',24,'全唐诗/poet.song.244000.json','["蘭芎圍絕嶂，圖畫望中懸。", "幾度令人慕，登臨學葛仙。"]'),
('e35901ed-e3cc-4f10-8b4b-6b7c2ecbbb7b','賦友授徒','趙友直','宋','宋诗','song-poetry','','[]','孤竹清風迥，尼壇化雨淋。',24,'全唐诗/poet.song.244000.json','["孤竹清風迥，尼壇化雨淋。", "羣英公樂育，何必羨華簪。"]'),
('5a51d50f-4511-4772-afb0-d505de60db92','山中即景四首  其一','趙友直','宋','宋诗','song-poetry','','[]','谷風吹我戶，襟抱豁然開。',48,'全唐诗/poet.song.244000.json','["谷風吹我戶，襟抱豁然開。", "雪向梅邊盡，春從柳上來。", "花瓶長綠草，茶碗泛香醅。", "逸興難拘縛，尋詩屐破苔。"]'),
('903bdb75-8a58-4ea1-a82b-d19760a0a75e','山中即景四首  其二','趙友直','宋','宋诗','song-poetry','','[]','趁此清和景，荷筩酒一吞。',48,'全唐诗/poet.song.244000.json','["趁此清和景，荷筩酒一吞。", "圍棋開北墅，羽扇取南薰。", "蘭雨清傳馥，鷗波綠漲紋。", "枕書鼾睡處，忽夢到陶君。"]'),
('af9a04f2-df07-4ecf-a01b-653ee45fe23f','山中即景四首  其三','趙友直','宋','宋诗','song-poetry','','[]','故園秋雨後，足跡遍溪山。',48,'全唐诗/poet.song.244000.json','["故園秋雨後，足跡遍溪山。", "月入蘆花冷，風磨柳葉殘。", "羣烏亂木末，獨雁咽雲端。", "此景堪誰遣，村醪味带酸。"]'),
('5c16f281-00f3-4f0f-a1e2-5a293bf0581b','山中即景四首  其四','趙友直','宋','宋诗','song-poetry','','[]','茅屋凍將壓，柴門寒自拴。',48,'全唐诗/poet.song.244000.json','["茅屋凍將壓，柴門寒自拴。", "掘爐煨芋栗，呵筆寫詩篇。", "策杖深山裏，尋梅古洞邊。", "誰知居士樂，翻受俗人憐。"]'),
('388619f8-1cab-4f0a-8fe5-1fca9a96f95f','暮春即景','趙友直','宋','宋诗','song-poetry','','[]','衡門三月景，萬頃浩無窮。',48,'全唐诗/poet.song.244000.json','["衡門三月景，萬頃浩無窮。", "堤柳輕浮碧，野花淨落紅。", "小橋溪水漲，曲徑峪雲籠。", "牧子橫牛背，前村一笛風。"]'),
('d3bec029-1764-459c-9df1-79ffe24b7e5e','仲夏即景','趙友直','宋','宋诗','song-poetry','','[]','五月憩孤村，幽情敻不羣。',48,'全唐诗/poet.song.244000.json','["五月憩孤村，幽情敻不羣。", "鷺飛天上雪，鷗渡渚中雲。", "翠麥剛纔刈，青苗又復芸。", "浮生行樂耳，世事不須論。"]'),
('36930b9b-e531-4c25-be17-08ad075c0263','避暑','趙友直','宋','宋诗','song-poetry','','[]','寰區皆是火，何地避炎官。',48,'全唐诗/poet.song.244000.json','["寰區皆是火，何地避炎官。", "散髪松陰下，挂巾石壁間。", "詩題疏竹潤，酒入碧筒寒。", "不必頻揮羽，清風無汗顔。"]'),
('b93fd5a0-f765-4171-971c-3f248f4cb965','重九對菊','趙友直','宋','宋诗','song-poetry','','[]','霜壓危簷冷，蕭條秋滿林。',48,'全唐诗/poet.song.244000.json','["霜壓危簷冷，蕭條秋滿林。", "青雲知己惠，黄菊故園心。", "百慮憑祛遣，頹齡仗制禁。", "緬思彭澤叟，履運□懷深。"]'),
('9e2f87ee-a122-4f81-8eb2-018ba01afd70','己卯歲除夜','趙友直','宋','宋诗','song-poetry','','[]','剛迎新歲至，俄驚歲復分。',48,'全唐诗/poet.song.244000.json','["剛迎新歲至，俄驚歲復分。", "燒燈明萬戶，爆竹響千門。", "愁對梅花咏，强將柏葉吞。", "經年心底事，明日付東君。"]'),
('c88de6be-e089-424b-8dab-0ccd20b93a8f','蘭邊晚酌','趙友直','宋','宋诗','song-poetry','','[]','深谷籠幽色，超然味更長。',48,'全唐诗/poet.song.244000.json','["深谷籠幽色，超然味更長。", "薰人先欲醉，對客漫斟嘗。", "初觸來歌席，猶疑撲酒觴。", "主人困坐久，寂寂不聞香。"]'),
('1ba334b6-70f8-4681-90d8-408f23226338','謝徐隠君屢見惠','趙友直','宋','宋诗','song-poetry','','[]','慷慨論交日，情深即故知。',48,'全唐诗/poet.song.244000.json','["慷慨論交日，情深即故知。", "金蘭敦古道，松柏挺奇姿。", "屢辱分嘉惠，何繇致我私。", "臨風無限思，搔首一嗟咨。"]'),
('83854d6c-0006-48e2-8165-5e4902294307','病中感友不至','趙友直','宋','宋诗','song-poetry','','["\u897f\u6e56"]','儂家好觀水，結屋傍西湖。',48,'全唐诗/poet.song.244000.json','["儂家好觀水，結屋傍西湖。", "荒徑人蹤少，蒼苔鳥蹟無。", "交情窮始見，世態燠斯孚。", "病嬾疏迎接，偏宜客不呼。"]'),
('81931fa8-49aa-4412-b062-9279a7341ede','漁','趙友直','宋','宋诗','song-poetry','','[]','垂竿終日坐苔磯，兩岸蘆花作雪飛。',32,'全唐诗/poet.song.244000.json','["垂竿終日坐苔磯，兩岸蘆花作雪飛。", "魚在深波剛不食，蓑披一片凍雲歸。"]'),
('1e26cedd-c900-405d-a723-6eb6194dccf9','樵','趙友直','宋','宋诗','song-poetry','','[]','踏破芒鞋力已疲，朝還礪斧採薪兒。',32,'全唐诗/poet.song.244000.json','["踏破芒鞋力已疲，朝還礪斧採薪兒。", "雲深迷却山頭路，戴笠回來雨濕衣。"]'),
('c6c6ca6f-1d08-4961-852c-73f3f032799d','耕','趙友直','宋','宋诗','song-poetry','','[]','布穀聲中雨一犁，綠蓑青笠兩相宜。',32,'全唐诗/poet.song.244000.json','["布穀聲中雨一犁，綠蓑青笠兩相宜。", "隴頭枉費驅牛力，旱潦年來未可期。"]'),
('9acdffa7-b0de-4ee8-b2e4-ab73adac80aa','牧','趙友直','宋','宋诗','song-poetry','','[]','相呼相喚出煙堤，冒雨前村膝沒泥。',32,'全唐诗/poet.song.244000.json','["相呼相喚出煙堤，冒雨前村膝沒泥。", "萬斛愁懷人不解，嗚嗚桐角倚牛吹。"]'),
('a43027e1-b219-44b6-8a6e-3fd2b0f6ef0a','承友携琴見訪','趙友直','宋','宋诗','song-poetry','','[]','三尺絲桐太古音，清風明月是知心。',32,'全唐诗/poet.song.244000.json','["三尺絲桐太古音，清風明月是知心。", "伯牙去後無消息，會見君家契此深。"]'),
('3b415395-2689-4831-95bf-25991144bde2','與友觀蘭','趙友直','宋','宋诗','song-poetry','','[]','彭澤當年成菊癖，予今亦欲訂蘭盟。',32,'全唐诗/poet.song.244000.json','["彭澤當年成菊癖，予今亦欲訂蘭盟。", "三杯酒向花邊瀉，一首詩從月下賡。"]'),
('c64b0c29-5d74-4415-b064-c5a5be091741','觀菊有感','趙友直','宋','宋诗','song-poetry','','[]','行到籬邊地滿霜，曩時物物已非常。',32,'全唐诗/poet.song.244000.json','["行到籬邊地滿霜，曩時物物已非常。", "自憐失意秋風後，獨有寒花不改香。"]'),
('0d329513-b0b0-4b8a-ae9f-9a218cccd67f','與詠道弟述懷','趙友直','宋','宋诗','song-poetry','','[]','世事爭雄一局棋，浮生碌碌鬢成絲。',32,'全唐诗/poet.song.244000.json','["世事爭雄一局棋，浮生碌碌鬢成絲。", "經年病爲多新釀，竟日忙因檢舊詩。"]'),
('35053c29-2a19-40a5-a3c4-efe6a42e464f','贈別二首  其一','趙友直','宋','宋诗','song-poetry','','[]','千里論交情纍纍，尊酒話別臨溪水。',32,'全唐诗/poet.song.244000.json','["千里論交情纍纍，尊酒話別臨溪水。", "江南爲有一枝春，願寄故人好相慰。"]'),
('55e026dd-8d69-4cfb-b909-892b436b1d26','贈別二首  其二','趙友直','宋','宋诗','song-poetry','','[]','年來聚首情何樂，今日匆匆又解携。',32,'全唐诗/poet.song.244000.json','["年來聚首情何樂，今日匆匆又解携。", "千里故交惟藉酒，勸君更把手中巵。"]'),
('6d411bc0-7fdd-4d38-ab75-18e2281f2d93','秋晚登眠牛岡偶賦','趙友直','宋','宋诗','song-poetry','','[]','滿路塵囂不耐愁，眠牛岡上自清秋。',32,'全唐诗/poet.song.244000.json','["滿路塵囂不耐愁，眠牛岡上自清秋。", "霜高木葉流丹冷，宜爲黄花一舉甌。"]'),
('f63b277d-3710-4dd1-be65-a24fb4c0f3a5','望海尖望海','趙友直','宋','宋诗','song-poetry','','[]','天懸一柱鬰崔嵬，海若遥看出不回。',32,'全唐诗/poet.song.244000.json','["天懸一柱鬰崔嵬，海若遥看出不回。", "疊岸猶疑鞭石起，獨慚無計覓蓬萊。"]'),
('94ff0241-a1b5-400c-87b9-86175af51d6b','登五龍尖晚歸鼓琴','趙友直','宋','宋诗','song-poetry','','[]','絕巘淩風駕白雲，登臨興後鼓南薰。',32,'全唐诗/poet.song.244000.json','["絕巘淩風駕白雲，登臨興後鼓南薰。", "朱絃一到無心處，自覺人間無可聞。"]'),
('e61f790d-cad7-4bba-9b8f-c38ef55527c7','傷春偶得綿字','趙友直','宋','宋诗','song-poetry','','[]','王府原頭芳草芊，却憐杜宇自年年。',32,'全唐诗/poet.song.244000.json','["王府原頭芳草芊，却憐杜宇自年年。", "停杯試向窗前看，飛盡楊花幾樹綿。"]'),
('a114af38-b9a1-42ad-9954-c8fdc6e311c5','寒食','趙友直','宋','宋诗','song-poetry','','[]','人道芳辰載酒行，予心翻起古今情。',32,'全唐诗/poet.song.244000.json','["人道芳辰載酒行，予心翻起古今情。", "紙錢燒罷歸來後，猶有原頭杜宇聲。"]'),
('07b67ced-c11c-4f0c-a56b-1bc822e9b08a','見乳燕','趙友直','宋','宋诗','song-poetry','','[]','梅雨初晴綠滿陂，忽然乳燕脫巢飛。',32,'全唐诗/poet.song.244000.json','["梅雨初晴綠滿陂，忽然乳燕脫巢飛。", "詩成高枕惟鼾睡，不向人間怨索離。"]'),
('42691bb9-fb7b-41eb-ac5d-c8dcdcb4afe8','搆竹樓初成','趙友直','宋','宋诗','song-poetry','','[]','竹樓新搆喜初成，爲檢遺編課子程。',64,'全唐诗/poet.song.244000.json','["竹樓新搆喜初成，爲檢遺編課子程。", "山近硯池雲自濕，門無轍迹草偏青。", "光團霽月盤書案，翠煖香風透畫屏。", "舊業深懷期遠大，心田寸許欲耘耕。"]'),
('fe1a6c7d-c050-4160-b388-6a1d01bcc75c','漫興二首  其一','趙友直','宋','宋诗','song-poetry','','[]','偃息林臯與世違，興來長嘯不妨癡。',64,'全唐诗/poet.song.244000.json','["偃息林臯與世違，興來長嘯不妨癡。", "素懷欲辟留侯穀，僻性耽茹甪里芝。", "漫謂五湖真樂事，須誇三徑足幽棲。", "時人何用訊名氏，久矣迂疏不自知。"]'),
('74132e26-4350-49d8-b89c-0680bc21c27f','漫興二首  其二','趙友直','宋','宋诗','song-poetry','','[]','南軒梅雨晚來頻，雨霽軒清儘可人。',64,'全唐诗/poet.song.244000.json','["南軒梅雨晚來頻，雨霽軒清儘可人。", "不著東山雙屐齒，偏宜渭水一絲綸。", "愁中託酒無辭醉，夢裏看花莫認真。", "行樂隨時吾事耳，乾坤何地不容身。"]'),
('979f0cd9-ed3c-4f7b-947b-835cbdb9ce2e','甑山','趙友直','宋','宋诗','song-poetry','','[]','湖心一凸起金巒，舉目渾如甑底看。',64,'全唐诗/poet.song.244000.json','["湖心一凸起金巒，舉目渾如甑底看。", "偃月蒼松多少樹，敲風翠竹兩三竿。", "石頭苔蘚痕常濕，葉底楊梅味带酸。", "誰學林君來結屋，風光應不讓孤山。"]'),
('f1c1cfdf-809c-46b2-b770-8fa4c087d28d','南源廟','趙友直','宋','宋诗','song-poetry','','[]','乾坤何處不披圖，覓勝誰從此地過。',64,'全唐诗/poet.song.244000.json','["乾坤何處不披圖，覓勝誰從此地過。", "三相神功垂舜治，千秋廟貌壯勾湖。", "衢通瑞象無塵境，山隔眠牛有坦途。", "伏臘歲時同到此，祠前瞻拜一諠呼。"]'),
('12b5bf66-37f6-43bf-94e8-d152c95be78f','創泳澤書院初成','趙友直','宋','宋诗','song-poetry','','[]','萬古湖山一望央，紫陽道脈壯宮牆。',64,'全唐诗/poet.song.244000.json','["萬古湖山一望央，紫陽道脈壯宮牆。", "佳朋鱗集互聯榻，多士雲從相共堂。", "地有金罍非福瑞，天將玉汝任綱常。", "要知學問無他術，只在工夫不怠荒。"]'),
('d62a1e90-ac88-48d3-8bf2-0311ca2adc17','倦來歸','趙友直','宋','宋诗','song-poetry','','[]','馳驅數載倦來歸，一任流光暗裏催。',64,'全唐诗/poet.song.244000.json','["馳驅數載倦來歸，一任流光暗裏催。", "縮首願情忘勢利，斂蹤甘不受輕肥。", "動於沼上觀鷗侶，靜在松間共鶴棲。", "此外囂囂無別事，編茅插棘護幽扉。"]'),
('529a510c-1bef-4a79-a4c2-e2f5bb3d49ce','釋悶','趙友直','宋','宋诗','song-poetry','','[]','檻外山花照眼明，獨憐幽抱向誰評。',64,'全唐诗/poet.song.244000.json','["檻外山花照眼明，獨憐幽抱向誰評。", "因尋樂處詩爲友，欲破愁城酒作兵。", "歌罷倦吟多少句，醉餘强進兩三觥。", "春光容易催人老，莫把污名玷此生。"]'),
('954fde02-e0ca-42ec-894b-e02583d02112','丙戌春霧','趙友直','宋','宋诗','song-poetry','','[]','忽逢陰濁氣氤氳，四顧山河盡已昏。',64,'全唐诗/poet.song.244000.json','["忽逢陰濁氣氤氳，四顧山河盡已昏。", "窗外霏霏成細雨，簷端渺渺綴浮雲。", "朦朧咫尺人難辨，混沌東西路不分。", "若得一番風掃後，依然再覿舊乾坤。"]'),
('d8f08863-6538-4108-8c6c-febecfecc12f','立夏','趙友直','宋','宋诗','song-poetry','','[]','四時天氣促相催，一夜薰風带暑來。',64,'全唐诗/poet.song.244000.json','["四時天氣促相催，一夜薰風带暑來。", "隴畝日長蒸翠麥，園林雨過熟黄梅。", "鶑啼春去愁千縷，蝶戀花殘恨幾回。", "睡起南窗情思倦，閑看槐蔭滿亭臺。"]'),
('5d9599c7-15bf-4db6-9fb0-cd2a14578dd8','聞鶑','趙友直','宋','宋诗','song-poetry','','[]','悶坐書齋學訴春，漫思黄鳥轉傷神。',64,'全唐诗/poet.song.244000.json','["悶坐書齋學訴春，漫思黄鳥轉傷神。", "惟知弄舌嬌和巧，不管行人喜與嗔。", "侵曉愛趨紅樹暖，移時又向綠楊新。", "始知春燕情何厚，日日相依舊主人。"]'),
('478c12ec-6b73-46f5-be6a-e953b00d0350','咏蘭','趙友直','宋','宋诗','song-poetry','','[]','曉來一雨忽初收，九畹分香繞碧流。',64,'全唐诗/poet.song.244000.json','["曉來一雨忽初收，九畹分香繞碧流。", "裛露靈苗凝淺翠，迎風素質拂輕柔。", "自甘深谷同巢許，不羨巍階並管周。", "物類尚知羞媚世，污名穢節豈吾儔。"]'),
('ecfee695-4831-4a22-b7f1-bd7d0b4d8829','壽黄有司誕日','趙友直','宋','宋诗','song-poetry','','[]','天挺英才佐廟廊，千年懋績炳旗常。',64,'全唐诗/poet.song.244000.json','["天挺英才佐廟廊，千年懋績炳旗常。", "懸弧偏喜民生壽，報國還期道體康。", "庭有芝蘭呈晚秀，門多桃李毓春芳。", "微吟聊助岡陵祝，鶴髪烏紗映鬢霜。"]'),
('431c1ae4-3ef1-4aed-8a8c-3fcd65733378','待友不至','趙友直','宋','宋诗','song-poetry','','[]','自與吾朋聊外期，心旌切切望容儀。',64,'全唐诗/poet.song.244000.json','["自與吾朋聊外期，心旌切切望容儀。", "聞言回首非因錯，欲語恁欄豈是癡。", "春酒破愁難作喜，鶑花供興不成詩。", "有時會晤情何限，握手論文到日西。"]'),
('3675a5fb-6a0b-4069-abb0-debc38a47b8d','長短句四時問四首  其一','趙友直','宋','宋诗','song-poetry','','[]','試問春韶光，何事容易老。',28,'全唐诗/poet.song.244000.json','["試問春韶光，何事容易老。", "一點丹心死不灰，餘生未便委芳草。"]'),
('574758c8-92b3-4994-abd0-459532701de6','長短句四時問四首  其二','趙友直','宋','宋诗','song-poetry','','[]','試問夏祝融，何事苦憑陵。',28,'全唐诗/poet.song.244000.json','["試問夏祝融，何事苦憑陵。", "安得金風起天末，大驅凉雨滌炎蒸。"]'),
('71e6df91-3d20-432b-b026-51f4a95ae65c','長短句四時問四首  其三','趙友直','宋','宋诗','song-poetry','','[]','試問秋疏簷，落葉何蕭蕭。',28,'全唐诗/poet.song.244000.json','["試問秋疏簷，落葉何蕭蕭。", "黄花如有故人意，相對籬邊共濁醪。"]'),
('5509f24d-e44f-4da8-9a9e-ea17c60ffb5b','長短句四時問四首  其四','趙友直','宋','宋诗','song-poetry','','[]','試問冬滿面，朔風何獵獵。',28,'全唐诗/poet.song.244000.json','["試問冬滿面，朔風何獵獵。", "雪裏梅花度暗香，騷人頗有詩相狎。"]'),
('c93256fe-641b-43cb-8f61-2482dc3e000d','悲千二弟','趙友直','宋','宋诗','song-poetry','','[]','哀哉我弟兮，一夢竟何歸。',72,'全唐诗/poet.song.244000.json','["哀哉我弟兮，一夢竟何歸。", "堂前紫荆萎，天邊鴻雁離。", "曩爾有志青雲技，茲爾回頭萬事非。", "黄卷窗前不再展，瑶琴月下誰復揮。", "我今爲爾寫哀詞，花箋滴淚聲歔欷。"]'),
('0e679a16-d754-47b1-a53f-b2a15c2ffd45','龍岡歌','趙友直','宋','宋诗','song-poetry','','[]','龍兮龍兮何時興，雲行雨施天下平。',96,'全唐诗/poet.song.244000.json','["龍兮龍兮何時興，雲行雨施天下平。", "湫兮湫兮龍之據，龍今去兮留空名。", "蒼松倒影肖鱗角，根盤石壁徒崚崢。", "當時旱魃爲暴虐，苗禾焦卷皆枯莖。", "嗷嗷下民發虔禱，嗟爾無神揚威靈。", "予今歌罷龍岡曲，翻令兩腋清風生。"]'),
('f0060c38-0d0a-4745-ba35-9a2324ba3125','懸劍歌','趙友直','宋','宋诗','song-poetry','','[]','家徒四壁何所有，橫懸三尺電光溜。',128,'全唐诗/poet.song.244000.json','["家徒四壁何所有，橫懸三尺電光溜。", "牀頭醉看白虹飛，中夜猶驚玉龍吼。", "潜倚空山泣鬼神，寒芒逼人動牛斗。", "無迺干將是前身，莫邪清淬渾天授。", "今者羞爲婦女看，霜稜蟠蟄匣中久。", "何日露拔斬長鯨，啟函一展剸犀手。", "豪曹湛盧祇自珍，雷煥張華世莫遘。", "儻爾識取英雄眸，此時揮霍任馳驟。"]'),
('cc22b7b6-cc4c-4799-af93-6706e912d9ab','種田行','趙友直','宋','宋诗','song-poetry','','[]','春雨一犁足郊原，南村北村齊種田。',66,'全唐诗/poet.song.244000.json','["春雨一犁足郊原，南村北村齊種田。", "拋秧落水時競捷，老者在後少者前。", "日暮天寒完未得，比鄰來相助插田。", "比鄰亦來相助插，如何獨行之士任迍邅。"]'),
('49993c38-d049-4916-ac5c-79d83b468241','杜宇行','趙友直','宋','宋诗','song-poetry','','[]','君不見四更五更月，杜宇口流望帝血。',97,'全唐诗/poet.song.244000.json','["君不見四更五更月，杜宇口流望帝血。", "何爲生子寄別巢，毛羽摧殘悲哽咽。", "將亡皎皎賈廉名，而今怨望未休歇。", "天運自古有廢興，金甌屹然亦傷缺。", "堯舜受禪夏商衰，夷齊孤竹如敝鞋。", "且須有酒拚顔赤，莫向東風空戚戚。"]'),
('f0487666-1363-4eeb-b366-6e18d9e077f8','牛山之木四章  其一','趙友直','宋','宋诗','song-poetry','','[]','牛山之木，於彼空谷。',20,'全唐诗/poet.song.244000.json','["牛山之木，於彼空谷。", "悠悠我思，孰云勿穀。"]'),
('0e0a5763-1e20-448c-8394-3ea086e76c92','牛山之木四章  其二','趙友直','宋','宋诗','song-poetry','','[]','牛山之木，欣欣其榮。',20,'全唐诗/poet.song.244000.json','["牛山之木，欣欣其榮。", "我有好爵，君子攸寧。"]'),
('84d710cb-b4be-4795-8ba9-855532449cad','牛山之木四章  其三','趙友直','宋','宋诗','song-poetry','','[]','木其榮矣，繁霜瘁之。',20,'全唐诗/poet.song.244000.json','["木其榮矣，繁霜瘁之。", "靜言思之，中心愴而。"]'),
('351d72bd-057f-4eb8-b2d7-559f7866b513','牛山之木四章  其四','趙友直','宋','宋诗','song-poetry','','[]','木之瘁矣，益厚其根。',20,'全唐诗/poet.song.244000.json','["木之瘁矣，益厚其根。", "我之懷矣，匪善奚敦。"]'),
('8b18770a-f10f-4854-bcfb-418a71ba6f33','有美人兮四章  其一','趙友直','宋','宋诗','song-poetry','','[]','有美人兮，在天之東。',20,'全唐诗/poet.song.244000.json','["有美人兮，在天之東。", "瞻之勿及，我心憧憧。"]'),
('3f2efec9-a4c6-4b28-80c1-728b6f5f3f67','有美人兮四章  其二','趙友直','宋','宋诗','song-poetry','','[]','有美人兮，在天之西。',20,'全唐诗/poet.song.244000.json','["有美人兮，在天之西。", "見之勿遂，我心悽悽。"]'),
('e59ecb2f-df81-4534-9d22-91a771f50993','有美人兮四章  其三','趙友直','宋','宋诗','song-poetry','','[]','有美人兮，在天之南。',20,'全唐诗/poet.song.244000.json','["有美人兮，在天之南。", "思之勿得，我心惔惔。"]'),
('f403717d-eed6-4ad4-978e-0a11872467e8','有美人兮四章  其四','趙友直','宋','宋诗','song-poetry','','[]','有美人兮，在天之北。',20,'全唐诗/poet.song.244000.json','["有美人兮，在天之北。", "懷之勿已，我心惻惻。"]'),
('1b7d3b06-ed83-46e3-b902-2d022584479e','題壁','趙友直','宋','宋诗','song-poetry','','[]','三北誰人知管仲，五湖何處覓陶朱。',32,'全唐诗/poet.song.244000.json','["三北誰人知管仲，五湖何處覓陶朱。", "壁間遺墨還堪睹，弔罷靈魂一束芻。"]'),
('59ae6780-7ad9-4d77-a255-50f73ae5e238','挽趙秋曉  其一','黎獻','宋','宋诗','song-poetry','','[]','父子龍門客，衣冠濮邸孫。',48,'全唐诗/poet.song.244000.json','["父子龍門客，衣冠濮邸孫。", "海桑塵劫換，文獻故家存。", "白璧今橫道，青衫此蓋棺。", "風流頓消歇，些罷涕汍瀾。"]'),
('6529389e-1f62-4e51-bcd1-017d0e746a9c','挽趙秋曉  其二','黎獻','宋','宋诗','song-poetry','','[]','嶺海英遊少，詩書旺氣衰。',48,'全唐诗/poet.song.244000.json','["嶺海英遊少，詩書旺氣衰。", "先生今不起，後死竟安歸。", "文曲星何暝，靈光賦又非。", "儒宗真可憾，豈但哭吾私。"]'),
('c5445ddd-8510-44f6-a189-e6110633d834','挽趙秋曉  其三','黎獻','宋','宋诗','song-poetry','','[]','淨覺草未宿，先生復踵之。',48,'全唐诗/poet.song.244000.json','["淨覺草未宿，先生復踵之。", "百年幾英特，三載兩凋萎。", "此去無歡日，重逢有夢時。", "向來觴詠地，衰柳带斜暉。"]'),
('a5d18a2d-43e0-450a-9acd-590fe7c6022a','挽趙秋曉  其四','黎獻','宋','宋诗','song-poetry','','[]','假館慚何補，叨鄰卜偶從。',48,'全唐诗/poet.song.244000.json','["假館慚何補，叨鄰卜偶從。", "燈曾分夜讀，歌忍相晨舂。", "一壁山河邈，他生飲啄同。", "眼前無此屋，風雨憶帡幪。"]'),
('405d5365-34f9-4f27-8036-9bd8047cfe0a','輓陳月橋','黎獻','宋','宋诗','song-poetry','','[]','先生仙去上青冥，收拾華詞付六丁。',64,'全唐诗/poet.song.244000.json','["先生仙去上青冥，收拾華詞付六丁。", "遺像堂堂千古月，名公落落幾晨星。", "文章有子傳燈印，學校無人屬典型。", "公論權衡嗟已矣，興言及此涕交零。"]'),
('1c3ef1cb-140c-4fa5-a0af-f85afda72f42','輓陳淡交先生','黎獻','宋','宋诗','song-poetry','','[]','承師受業憶同門，如水之交昔有年。',64,'全唐诗/poet.song.244000.json','["承師受業憶同門，如水之交昔有年。", "痛哭鴒原情未已，徘徊鵩舍意淒然。", "功名早領賢書薦，世業由來家學傳。", "碩德晨星嗟已矣，試編遺稿淚潸漣。"]'),
('ff64ee36-fd3b-4477-a5e4-0c0610b700f5','挽趙秋曉  其一','翟佐','宋','宋诗','song-poetry','','[]','當年汗漫期，蟾窟折危枝。',48,'全唐诗/poet.song.244000.json','["當年汗漫期，蟾窟折危枝。", "四海習鑿齒，三生杜牧之。", "淒其一聲笛，已矣八哀詩。", "忍看亭前柳，青青似舊時。"]'),
('6fa830db-fa6a-4f85-a2eb-dc42a1ffacaa','挽趙秋曉  其二','翟佐','宋','宋诗','song-poetry','','[]','疇昔追隨日，團頭笑語同。',48,'全唐诗/poet.song.244000.json','["疇昔追隨日，團頭笑語同。", "酒船浮大白，荔圃擘輕紅。", "入社慚招亮，忘年肯友戎。", "向來觴詠地，古木起悲風。"]'),
('20788365-71d0-4a65-a944-989655920027','挽趙秋曉','胡駿升','宋','宋诗','song-poetry','','[]','父子同年錄，雲霄步武高。',48,'全唐诗/poet.song.244000.json','["父子同年錄，雲霄步武高。", "功名方夢蟻，宇宙適交鰲。", "巖壑淮南隠，詩文太白豪。", "九泉不可作，幾些續離騷。"]'),
('8019af34-b4db-4ed9-976e-21a0d0f4fb68','挽趙秋曉','張孺子','宋','宋诗','song-poetry','','[]','早袖經綸手，歸歟卧首陽。',48,'全唐诗/poet.song.244000.json','["早袖經綸手，歸歟卧首陽。", "可憐心錦繡，不補帝衣裳。", "祿與名俱靳，身宜壽且康。", "互鄉蒙子潔，聞訃重心傷。"]'),
('7be35ba9-a248-407f-8438-499152ae50f1','挽趙秋曉','陳繼善','宋','宋诗','song-poetry','','[]','燈火南城夜，春風借齒牙。',48,'全唐诗/poet.song.244000.json','["燈火南城夜，春風借齒牙。", "阿蒙曾刮目，文舉幸通家。", "尚渴霏霏誨，翻成起起嗟。", "向來觴詠地，衰柳夕陽斜。"]'),
('806d2e59-9a03-4093-87f6-7867891189b9','挽趙秋曉  其一','姚燃','宋','宋诗','song-poetry','','[]','已矣嗟麟趾，青衫正少年。',48,'全唐诗/poet.song.244000.json','["已矣嗟麟趾，青衫正少年。", "才優合芸閣，時異倏桑田。", "雨散傷同輩，風流瘞九原。", "何當芻一束，揮淚玉人前。"]'),
('001707b6-9e96-4685-9159-0ee81e34a71c','挽趙秋曉  其二','姚燃','宋','宋诗','song-poetry','','[]','一枕春婆夢，如君亦可悲。',48,'全唐诗/poet.song.244000.json','["一枕春婆夢，如君亦可悲。", "人間無著處，天上有歸期。", "光岳失英氣，江湖欠好詩。", "莫愁身後事，跨竈有諸兒。"]'),
('241c7f6e-2840-4eb9-a197-bc48d638b14a','挽趙秋曉  其一','梅時舉','宋','宋诗','song-poetry','','[]','蟾宮年少夢成非，橋梓空分桂一枝。',64,'全唐诗/poet.song.244000.json','["蟾宮年少夢成非，橋梓空分桂一枝。", "酒聖詩狂唐太白，筆精墨妙晉羲之。", "商山早隔人間世，男子不成天下奇。", "聞道寶安埋玉樹，一航秋雨寄相思。"]'),
('759b54f2-3606-4614-b3a7-3831cbcfd487','挽趙秋曉  其二','梅時舉','宋','宋诗','song-poetry','','[]','自古詩人仕不高，偉人底事占詩豪。',64,'全唐诗/poet.song.244000.json','["自古詩人仕不高，偉人底事占詩豪。", "同年親友俱三釜，半壁天傾空二毫。", "守我冷官巾與屨，任他巧宦带而袍。", "一篇覆瓿生光焰，地下修文想和陶。"]'),
('04e344d5-084d-411a-b39e-c9c643b46966','挽趙秋曉','釋覺真','宋','宋诗','song-poetry','','[]','合掌焚香敬揲蓍，數符大衍爲君悲。',64,'全唐诗/poet.song.244000.json','["合掌焚香敬揲蓍，數符大衍爲君悲。", "生如玄德不爲夭，命許宣尼只自知。", "方丈室中曾示病，三生石上又前期。", "他年認取本來面，依舊顛僧與退之。"]'),
('35a8f05f-e2c0-4cf3-b19d-b641bbf8b297','挽趙秋曉','羅附鳳','宋','宋诗','song-poetry','','[]','發軔功名髪未華，轉頭世事已堪嗟。',64,'全唐诗/poet.song.244000.json','["發軔功名髪未華，轉頭世事已堪嗟。", "晚栽栗里歸田菊，早看長安得意花。", "空憶去鴻留爪跡，祇今舊燕傍誰家。", "重尋陳迹真如夢，疏柳殘烟噪暮鴉。"]'),
('8fd2fe95-c417-486a-9ded-0a57bd5cd274','挽趙秋曉','趙時清','宋','宋诗','song-poetry','','[]','諸老凋零不忍聞，奈何天又奪斯人。',64,'全唐诗/poet.song.244000.json','["諸老凋零不忍聞，奈何天又奪斯人。", "漢初賈誼曾前席，晉後淵明恥屈身。", "尚想醉歸松路月，可堪夢斷草池春。", "同宗聞訃尤傷感，老淚無多暗損神。"]'),
('fe03c2ef-cb2d-4175-8a57-d2ed41a5d72e','挽趙秋曉  其一','黎善夫','宋','宋诗','song-poetry','','[]','年時父子記同登，詎意天從杞國傾。',64,'全唐诗/poet.song.244000.json','["年時父子記同登，詎意天從杞國傾。", "輦路春風三月夢，山莊夜雨十年燈。", "率更帖墨知魁梧，庾信文章邁老成。", "二妙風流今已矣，薤歌賦罷淚沾膺。"]'),
('cced349b-bcea-4fa8-aee9-07f41e55ed7a','挽趙秋曉  其二','黎善夫','宋','宋诗','song-poetry','','[]','十載荒村共亂離，雲龍上下憶追隨。',64,'全唐诗/poet.song.244000.json','["十載荒村共亂離，雲龍上下憶追隨。", "生前已飽撞鐘問，死後方傳覆瓿詩。", "此夕巷歌誰忍發，他年鄰笛自應悲。", "傷心豈爲幽冥負，重爲斯文一涕洟。"]'),
('3ee7df60-11b7-45d7-b858-77fb13bec4b4','挽趙秋曉','鄧元奎','宋','宋诗','song-poetry','','[]','文星隕向鳳臺城，凶訃傳來驗奠楹。',64,'全唐诗/poet.song.244000.json','["文星隕向鳳臺城，凶訃傳來驗奠楹。", "天若假年加富貴，人生夢枕做功名。", "謫僊詩在晚唐重，坡老身亡兩蜀輕。", "豪邁如今存者幾，惜乎吾道重傷情。"]'),
('8bdfc719-13cb-472d-accc-a854a2d54514','挽趙秋曉','葉特','宋','宋诗','song-poetry','','[]','枕竅榮名未一炊，谷陵事異賸堪悲。',64,'全唐诗/poet.song.244000.json','["枕竅榮名未一炊，谷陵事異賸堪悲。", "應嗟公子猶麟趾，無奈宗周已黍離。", "更恨并州同逆旅，何堪蒿里致哀詞。", "詩書種有諸郎在，公死猶如未死時。"]'),
('99f798d4-5d4c-4bce-95d0-f1703175b135','挽趙秋曉','張震龍','宋','宋诗','song-poetry','','[]','蚤歲看花遍上都，謂宜東序著河圖。',64,'全唐诗/poet.song.244000.json','["蚤歲看花遍上都，謂宜東序著河圖。", "亭亭玉樹風前皎，浩浩璇源夜半枯。", "自是死生存定數，絕憐神駿蹶長途。", "此行不返神清洞，應抗龍髯去鼎湖。"]'),
('c2e32d21-5e08-4070-a46d-efa6e555a82c','挽趙秋曉','李昌辰','宋','宋诗','song-poetry','','[]','諸老之中骨相奇，天胡遽使哲人萎。',64,'全唐诗/poet.song.244000.json','["諸老之中骨相奇，天胡遽使哲人萎。", "每懷釣月池邊樂，尚憶編茅亭下詩。", "隔面樹雲勞我夢，傷心薤露爲君悲。", "典型已矣嗟何及，腸斷天寒日暮時。"]'),
('1b9d146d-27a0-43aa-aff3-df1d8653a86a','挽趙秋曉  其一','張昭子','宋','宋诗','song-poetry','','[]','亭亭玉樹世間稀，天與科名不與時。',64,'全唐诗/poet.song.244000.json','["亭亭玉樹世間稀，天與科名不與時。", "倍厚每生同族敬，風流多結貴遊知。", "吾於魯肅情偏厚，客謂文園疾莫支。", "撫几自悲還自慨，喜君跨竈有諸兒。"]'),
('42fabb90-67e6-4cc3-80db-0c3997560bfa','挽趙秋曉  其二','張昭子','宋','宋诗','song-poetry','','[]','家住青山擅一丘，菜畦花圃足夷猶。',64,'全唐诗/poet.song.244000.json','["家住青山擅一丘，菜畦花圃足夷猶。", "哲人造物何慳壽，公子平生不識愁。", "雞黍情緣成夢斷，鶑花心性蓋棺休。", "草亭吟卷今猶在，讀向西風老淚流。"]'),
('af4a5164-573f-4626-bb0e-f6e294358603','挽趙秋曉','黎伯元','宋','宋诗','song-poetry','','[]','一榜科名萃此門，當時盛事詫衣冠。',64,'全唐诗/poet.song.244000.json','["一榜科名萃此門，當時盛事詫衣冠。", "文章爾雅向歆上，標致風流晉漢間。", "淚灑銅駝已荆棘，眼看華屋又邱山。", "貞元朝士今誰在，些罷招魂淚雨漫。"]'),
('88173bd8-3fe8-49e7-8bf4-d492e624ad7c','挽趙秋曉  其一','陳師善','宋','宋诗','song-poetry','','[]','風低健翮偶南翔，收斂虹霓萬丈光。',64,'全唐诗/poet.song.244000.json','["風低健翮偶南翔，收斂虹霓萬丈光。", "江左諸賢慕安石，貞元朝士獨劉郎。", "尚期意氣風雲會，竟老英雄潦霧鄉。", "如此典型今已矣，天乎莫詰意茫茫。"]'),
('ca31007d-b4e1-4f87-8853-a2e6aa1a1a27','挽趙秋曉  其二','陳師善','宋','宋诗','song-poetry','','[]','驚呼事定隔存亡，天地無情此恨長。',64,'全唐诗/poet.song.244000.json','["驚呼事定隔存亡，天地無情此恨長。", "冷落席門憐曲逆，凄凉詩法憶濠梁。", "此生結習緣猶淺，晚景追陪愿未償。", "珍重韓公遺稿在，忍將展翫怕情傷。"]'),
('e40d4bb8-66f9-464e-8d67-862a71c49514','古有所思','吳澤','宋','宋诗','song-poetry','','[]','我思至人，遊心唐虞之帝廷。',59,'全唐诗/poet.song.244000.json','["我思至人，遊心唐虞之帝廷。", "上下數千載，迥如雲霄疇與京。", "臯夔禮樂表世則，克紹周孔流芳聲。", "斯文在茲幸不墜，亙古永懷惟六經。"]'),
('8ce40e14-a00c-4db2-90e1-99c089f81589','送德基','李蟠','宋','宋诗','song-poetry','','[]','單閼多餘慶，清時得偉人。',48,'全唐诗/poet.song.244000.json','["單閼多餘慶，清時得偉人。", "德隆荀氏操，學慕孟軻醇。", "久媿溝中斷，常親席上珍。", "征帆忽西去，悵望宛溪濱。"]'),
('518149a1-a46a-474d-927b-34962a3a5b0c','辰光門','李蟠','宋','宋诗','song-poetry','','[]','北林蒼翠拱岩闉，中起紅樓迥照人。',64,'全唐诗/poet.song.244000.json','["北林蒼翠拱岩闉，中起紅樓迥照人。", "四面山河千古在，百年城市一朝新。", "夜深燈火明沙路，秋冷笙歌擁畫輪。", "莫訝使君頻宴樂，欲令盍郡物皆春。"]'),
('5399f393-7552-4033-8f5c-2ac234e00dc4','古意','陸正','宋','宋诗','song-poetry','','[]','結褵事君子，誓作形與影。',60,'全唐诗/poet.song.244000.json','["結褵事君子，誓作形與影。", "人事多乖戾，彼此睽燕郢。", "尺書沉素鱗，啼鵑催逝景。", "妾命詎終薄，君心那得冷。", "開簾花撲面，淚落紛如綆。"]'),
('8c11db63-ff5e-432e-bb60-534e7a27e890','銀城舊縣','李士會','宋','宋诗','song-poetry','','[]','人民城郭駭俱非，從此西遷西復西。',64,'全唐诗/poet.song.244000.json','["人民城郭駭俱非，從此西遷西復西。", "曾是萬家雄井邑，依然一段好山溪。", "津無可鎖沈江渚，市不聞鐘委草泥。", "碑碣更隨年月換，興亡往事向誰稽。"]'),
('19c4c525-e933-4ab5-9795-5e5572af38dc','薛家塘','李士會','宋','宋诗','song-poetry','','[]','自古殺忠良，多用巧中傷。',48,'全唐诗/poet.song.244000.json','["自古殺忠良，多用巧中傷。", "不驅飛作鬼，那得檜封王。", "有士冤狴犴，無辜忤廟堂。", "至今流斥地，人說薛家塘。"]'),
('aaf8d892-1bec-4672-a06e-df67c15fcebf','長樂舊縣','李士會','宋','宋诗','song-poetry','','[]','千古空傳長樂溪，誰知樂極已生悲。',64,'全唐诗/poet.song.244000.json','["千古空傳長樂溪，誰知樂極已生悲。", "凄烟斷礎祝家市，落日荒城柳尹祠。", "上起何年無信史，中更鉅變有殘碑。", "青峰峰下躊躇意，說與時人未必知。"]'),
('30065a86-af74-4166-aec0-84133b26a44c','雲溪叔父賜飲大梅花下以疏影橫斜暗香浮動分韻得動字','張紹文','宋','宋诗','song-poetry','','[]','清溝泂寒波，怪石亂扶擁。',72,'全唐诗/poet.song.244000.json','["清溝泂寒波，怪石亂扶擁。", "輕風捲濃雲，天際孤月湧。", "主人宴親賓，會合意彌重。", "列炬照寒梅，繁星粲脩隴。", "清香逼詩魂，吟興欲飛動。", "酩酊歸去來，嚴城角三弄。"]'),
('8acc4270-2106-40e6-a2c0-f0332c543bdb','鍾山路間','張紹文','宋','宋诗','song-poetry','','[]','立馬鍾山路，斜陽鎖亂峰。',48,'全唐诗/poet.song.244000.json','["立馬鍾山路，斜陽鎖亂峰。", "斷碑生綠蘚，古道立青松。", "春事梅邊覺，鄉愁酒後濃。", "興亡多感慨，我輩復情鍾。"]'),
('3216f7bb-0425-46e7-ad0a-688b582daff1','自維揚辭親暫歸里中登樓有作','張紹文','宋','宋诗','song-poetry','','[]','爛漫家山景物妍，西風收拾下蠻牋。',64,'全唐诗/poet.song.244000.json','["爛漫家山景物妍，西風收拾下蠻牋。", "半分寒事梅花裏，一段幽懷夕照邊。", "漁唱凄凉招野色，雁行縹緲带晴烟。", "淮山只在欄干北，目送飛雲重黯然。"]'),
('ea7485cb-1942-46d5-8926-492bd426c8db','自淮陽還里中抵舍一夕即爲通川之行','張紹文','宋','宋诗','song-poetry','','[]','喜得歸來席未安，又携書劍上江干。',64,'全唐诗/poet.song.244000.json','["喜得歸來席未安，又携書劍上江干。", "莫陪親戚話情愫，空指溪山說肺肝。", "客路幾程來杳杳，天涯一棹去漫漫。", "故鄉又被江雲隔，寫得詩成欲寄難。"]'),
('cbfb6610-c802-4914-8cf5-6c16b377eac2','小院','張紹文','宋','宋诗','song-poetry','','[]','小院春寒閉寂寥，東風吹雪未全消。',32,'全唐诗/poet.song.244000.json','["小院春寒閉寂寥，東風吹雪未全消。", "山茶謝了梅花落，移得詩情上柳條。"]'),
('440a73e6-fc33-4249-bf6f-a3bdc69edd22','醉鄉','張紹文','宋','宋诗','song-poetry','','[]','醉鄉詩筆是生涯，短短蠻牋字字斜。',32,'全唐诗/poet.song.244000.json','["醉鄉詩筆是生涯，短短蠻牋字字斜。", "沉水一株烟未斷，半窗寒月上梅花。"]'),
('df441de7-1927-4035-93c6-7750b9efc645','山庵夜宿呈深居先生','張紹文','宋','宋诗','song-poetry','','[]','松逕轉幽密，一程深一程。',48,'全唐诗/poet.song.244000.json','["松逕轉幽密，一程深一程。", "濤聲在平地，月色正三更。", "僧定欲喚起，鶴眠頻夢驚。", "曉來真富貴，露葉綴珠瓔。"]'),
('f4b26433-b2c8-4d50-ba50-2235bd4ccc20','送梁中砥入道從三茅許松谿','張紹文','宋','宋诗','song-poetry','','[]','無意覓封侯，來從長史遊。',48,'全唐诗/poet.song.244000.json','["無意覓封侯，來從長史遊。", "辭章唐韻度，人物晉風流。", "花影天壇午，松聲月澗秋。", "登臨盡詩境，分我半山不。"]'),
('2f9c8e1b-b24f-4176-a959-7cc55e065852','即事  其一','張紹文','宋','宋诗','song-poetry','','[]','電挾雷聲迅，風將雨脚多。',48,'全唐诗/poet.song.244000.json','["電挾雷聲迅，風將雨脚多。", "須臾寂無有，造化果如何。", "饑鼠撼幃竹，哀蛩語徑莎。", "披衣起中夜，有感寄長歌。"]'),
('75107216-e8b9-4419-96e5-3c33f77e68b6','即事  其二','張紹文','宋','宋诗','song-poetry','','[]','地迥秋聲遠，山空野興多。',48,'全唐诗/poet.song.244000.json','["地迥秋聲遠，山空野興多。", "宦游聊爾耳，疏嬾奈吾何。", "摇落驚黄葉，推敲步綠莎。", "新凉大自在，對酒且高歌。"]'),
('f4bf9f39-7b52-4d91-8b25-c28a0cbfadaf','春閨怨效唐才調集體','張紹文','宋','宋诗','song-poetry','','[]','楊柳和烟翠不分，東風吹雨上離樽。',64,'全唐诗/poet.song.244000.json','["楊柳和烟翠不分，東風吹雨上離樽。", "茝絃調急難藏恨，燕子樓高易斷魂。", "錦字書成春夢遠，玉壺淚滿夜燈昏。", "馬蹄想過長亭路，細與蕭郎認去痕。"]'),
('303fe759-875a-4028-9cf8-c6dd67eccd26','江亭晚眺','張紹文','宋','宋诗','song-poetry','','[]','登高便可豁雙明，吟外還能見物情。',64,'全唐诗/poet.song.244000.json','["登高便可豁雙明，吟外還能見物情。", "南北盛衰關大數，英雄得失總虛名。", "莫雲千里鄉心遠，寒雁一聲秋意清。", "江上白鷗應笑我，等閑虛負水邊盟。"]'),
('388b116b-013c-4e0e-88b0-3a3b470d4b5a','定林','張紹文','宋','宋诗','song-poetry','','[]','三間書屋年年在，一點禪燈夜夜明。',32,'全唐诗/poet.song.244000.json','["三間書屋年年在，一點禪燈夜夜明。", "門外青苗渾不見，半山松竹自秋聲。"]'),
('3eb17712-7001-4f2e-86b7-cc0a37eec27e','金陵道中晚宿','張紹文','宋','宋诗','song-poetry','','[]','卸却征衣卧客窗，移床切莫近寒螀。',32,'全唐诗/poet.song.244000.json','["卸却征衣卧客窗，移床切莫近寒螀。", "空階一雨淒凉甚，不怨梧桐怨夜長。"]'),
('db89d092-8abc-4a0d-b2f5-1f339c1d8514','夜坐','張紹文','宋','宋诗','song-poetry','','[]','金鴨香殘酒半醒，夜深寒月過西櫺。',32,'全唐诗/poet.song.244000.json','["金鴨香殘酒半醒，夜深寒月過西櫺。", "可憐心事無人識，詩眼與燈相對青。"]'),
('d57171d5-4f72-4c56-96cd-fca868297307','絕句二首  其一','張紹文','宋','宋诗','song-poetry','','[]','曉雲扶日上高梧，一枕春酲困未蘇。',32,'全唐诗/poet.song.244000.json','["曉雲扶日上高梧，一枕春酲困未蘇。", "山鳥不知如許事，隔窗猶自勸提壺。"]'),
('139645ac-592d-4c31-88e3-5dd9f367d1e7','絕句二首  其二','張紹文','宋','宋诗','song-poetry','','[]','雨過盤池起綠波，夜來添得幾圓荷。',32,'全唐诗/poet.song.244000.json','["雨過盤池起綠波，夜來添得幾圓荷。", "單衣不奈春寒惡，却美楊枝挾纊多。"]'),
('9c154778-bcc9-470c-ad7d-b264150d1433','哭趙昴發','池州府學生','宋','宋诗','song-poetry','','[]','生爲大宋人，死爲大宋鬼。',24,'全唐诗/poet.song.244000.json','["生爲大宋人，死爲大宋鬼。", "何以洗此污，清溪一泓水。"]'),
('0337138e-3dc8-4b6a-91df-ebd2ca4818ed','題倪文昌玉湖書院','韋奇','宋','宋诗','song-poetry','','["\u8861\u5c71"]','齊齋老子今安在，一去人間餘廿載。',192,'全唐诗/poet.song.244000.json','["齊齋老子今安在，一去人間餘廿載。", "白衣蒼狗幾千回，惟有溪山長不改。", "吳興勝概誇玉湖，鵝溪一幅玄暉圖。", "天光上下渺無極，寒玉倒浸清冰壺。", "晴波萬頃瑩如洗，一卷石向波心起。", "先生具眼此結廬，收拾溪山入詩裏。", "漁人艇子時往還，笭箵擲下前溪灣。", "一聲欸乃水天碧，回頭却羨沙鳥閑。", "樓高望極情思遠，前揖衡山後蒼弁。", "陌頭楊柳幾春風，當年曾識齊齋面。", "我今懷古心悠悠，古人不見今人愁。", "夕陽收盡暝烟浮，扁舟載月歸來休。"]'),
('118783d0-4eac-4a04-9a45-ba5f1fc4dfb7','句  其一','韋奇','宋','宋诗','song-poetry','','[]','撥灰煨芋子，带溼爇松枝。',12,'全唐诗/poet.song.244000.json','["撥灰煨芋子，带溼爇松枝。"]'),
('653e1843-f869-4a97-ae8d-a68e6516c20c','句  其二','韋奇','宋','宋诗','song-poetry','','[]','林缺添松補，籬疏倩菊遮。',12,'全唐诗/poet.song.244000.json','["林缺添松補，籬疏倩菊遮。"]'),
('2d64db02-0231-4f62-8eec-285e0733ab38','句  其三','韋奇','宋','宋诗','song-poetry','','[]','敗壁蝸黏篆，空階蚓結樓。',12,'全唐诗/poet.song.244000.json','["敗壁蝸黏篆，空階蚓結樓。"]'),
('f78cb4f8-b5d3-4b86-b1f4-ce5c59dc0f5d','句  其四','韋奇','宋','宋诗','song-poetry','','[]','窗破入雲氣，林疏漏月痕。',12,'全唐诗/poet.song.244000.json','["窗破入雲氣，林疏漏月痕。"]'),
('d8343d3c-ba3d-4e14-8a74-72103822b8fa','句  其五','韋奇','宋','宋诗','song-poetry','','[]','野黑雞聲顫，林深燐火明。',12,'全唐诗/poet.song.244000.json','["野黑雞聲顫，林深燐火明。"]'),
('2342a61d-dd23-4d81-ab50-8fd6670902bd','句  其六','韋奇','宋','宋诗','song-poetry','','[]','病多諳藥性，吟苦識詩情。',12,'全唐诗/poet.song.244000.json','["病多諳藥性，吟苦識詩情。"]'),
('b1c44e09-f00c-4b54-a24d-00699a9002d5','句  其七','韋奇','宋','宋诗','song-poetry','','[]','黄犢拖犁倦，青帘說酒清。',12,'全唐诗/poet.song.244000.json','["黄犢拖犁倦，青帘說酒清。"]'),
('3e5af8dd-9cb5-44a0-beeb-a3e3cdebeaa5','句  其八','韋奇','宋','宋诗','song-poetry','','[]','山風噓冷信，簷溜管離情。',12,'全唐诗/poet.song.244000.json','["山風噓冷信，簷溜管離情。"]'),
('1e17e316-a0a2-4913-b55f-094e449cece4','詩一首','戚明瑞','宋','宋诗','song-poetry','','[]','藍田戰秦將，子嬰豎降幘。',24,'全唐诗/poet.song.244000.json','["藍田戰秦將，子嬰豎降幘。", "至今柏樹精，疑是卧龍魄。"]'),
('75a7302a-635b-4f27-8f41-246ed5a6b24d','句  其一','戚明瑞','宋','宋诗','song-poetry','','[]','舊夢不堪遊螘國，生涯只合在漁舟。',16,'全唐诗/poet.song.244000.json','["舊夢不堪遊螘國，生涯只合在漁舟。"]'),
('30e2d3d6-9130-445a-b4a6-e7f79c163c7b','句  其二','戚明瑞','宋','宋诗','song-poetry','','[]','鵂鶹歡喜舞南風。',8,'全唐诗/poet.song.244000.json','["鵂鶹歡喜舞南風。"]'),
('2573f548-948f-467d-98b1-d0a9dec360ad','句  其三','戚明瑞','宋','宋诗','song-poetry','','[]','老槐陰下吹箜篌。',8,'全唐诗/poet.song.244000.json','["老槐陰下吹箜篌。"]'),
