('e9d3e3be-62f6-4025-b8af-c076cfda8133','句  其五','戚明瑞','宋','宋诗','song-poetry','','[]','望帝花飛春尚寒。',8,'全唐诗/poet.song.244000.json','["望帝花飛春尚寒。"]'),
('9edbfaa8-23f4-42e9-8f56-c0f71ae25fea','句  其一','許庚','宋','宋诗','song-poetry','','[]','值雨花無怨，留春鳥自謀。',12,'全唐诗/poet.song.244000.json','["值雨花無怨，留春鳥自謀。"]'),
('f2378f6c-5218-43f3-8d38-6cd5d8c96789','句  其二','許庚','宋','宋诗','song-poetry','','[]','思苦無一字，意來成數篇。',12,'全唐诗/poet.song.244000.json','["思苦無一字，意來成數篇。"]'),
('b95d998c-22a3-46fc-858d-63dc167f83d4','句  其三','許庚','宋','宋诗','song-poetry','','[]','花盡辜啼鳥，麻深沒過人。',12,'全唐诗/poet.song.244000.json','["花盡辜啼鳥，麻深沒過人。"]'),
('37fadc47-8e40-4b8f-aee8-f9500e533e1a','句  其四','許庚','宋','宋诗','song-poetry','','[]','硯潤浮殘墨，琴乾響斷弦。',12,'全唐诗/poet.song.244000.json','["硯潤浮殘墨，琴乾響斷弦。"]'),
('7169facc-4c0a-4e00-9777-6312bfde9d54','句  其五','許庚','宋','宋诗','song-poetry','','[]','壯歲期加進，新吟未敢編。',12,'全唐诗/poet.song.244000.json','["壯歲期加進，新吟未敢編。"]'),
('ffc12be4-82c7-48ae-9e55-01854283a221','句  其六','許庚','宋','宋诗','song-poetry','','[]','頓超捷進脫，故習肩前修。',12,'全唐诗/poet.song.244000.json','["頓超捷進脫，故習肩前修。"]'),
('c79ee9d5-1621-4e60-beb2-43c5269b9fc5','挽疊山先生','洪光基','宋','宋诗','song-poetry','','[]','千古精忠日月光，恨無麟筆寫堂堂。',64,'全唐诗/poet.song.244000.json','["千古精忠日月光，恨無麟筆寫堂堂。", "遷家恥作梁江總，辟穀誰知韓子房。", "死後十年應有待，輕生萬里故非狂。", "有兒可拾江邊骨，須信人亡道不亡。"]'),
('4c830834-076b-4a6b-a44c-390cd9f8b79e','絕命詩','徐崧','宋','宋诗','song-poetry','','[]','成仁取義在於斯，一死君恩報未遲。',64,'全唐诗/poet.song.244000.json','["成仁取義在於斯，一死君恩報未遲。", "杲日當空存正氣，狂瀾砥柱起常彝。", "孔明未復中原鼎，鵬舉空搴二帝旂。", "可恨奸回移宋祚，闔門厲鬼泣秦師。"]'),
('86d42f30-dc72-4678-87bd-edc398cdfd4f','刺賈平章','咸淳士人','宋','宋诗','song-poetry','','[]','鼙鼓驚天動地來，九州赤子哭哀哀。',32,'全唐诗/poet.song.244000.json','["鼙鼓驚天動地來，九州赤子哭哀哀。", "廟堂不問平戎策，多把金錢媚秀才。"]'),
('07f4a0cd-1574-4b90-9186-76bb89aae64a','刺賈似道','咸淳士人','宋','宋诗','song-poetry','','[]','厚我藩垣長彼貪，不然銜璧小邦男。',32,'全唐诗/poet.song.244000.json','["厚我藩垣長彼貪，不然銜璧小邦男。", "廟堂從諫真如轉，竟用先生策第三。"]'),
('f6f50d2d-42d0-4923-b7b1-e746acb841b5','刺賈秋壑詩  其一','咸淳士人','宋','宋诗','song-poetry','','[]','深院無人草已荒，漆屏金字尚煇煌。',64,'全唐诗/poet.song.244000.json','["深院無人草已荒，漆屏金字尚煇煌。", "祇知事去身宜去，豈料人亡國亦亡。", "理考發身端自有，鄭人應夢果何祥。", "卧龍不肯留渠住，空使晴光滿畫牆。"]'),
('50f5e2da-57b8-42e5-b310-6198c8516e63','刺賈秋壑詩  其二','咸淳士人','宋','宋诗','song-poetry','','[]','事到窮時計亦窮，此行難倚鄂州功。',64,'全唐诗/poet.song.244000.json','["事到窮時計亦窮，此行難倚鄂州功。", "木棉庵上千年恨，秋壑堂中一夢空。", "石砌苔稠猿步月，松庭葉落鳥呼風。", "客來未用多惆悵，試向吳山望故宮。"]'),
('ac6b3348-b0e0-4319-afd4-d4539034d145','題賈似道養樂園','咸淳士人','宋','宋诗','song-poetry','','[]','老壑曾居葛嶺西，遊人誰敢問蘇隄。',64,'全唐诗/poet.song.244000.json','["老壑曾居葛嶺西，遊人誰敢問蘇隄。", "勢將覆餗不回首，事到出師方噬臍。", "廢圃久無人作主，敗垣惟有客留題。", "算來祇有孤山耐，依舊梅花片月低。"]'),
('c38638c4-6bf4-44fb-9f81-1541aedd9e1a','臨安謠','臨安人','宋','宋诗','song-poetry','','[]','滿頭青，都是假。',16,'全唐诗/poet.song.244000.json','["滿頭青，都是假。", "這回來，不作耍。"]'),
('09eed6dd-cb87-48e7-9f64-3ebf7c96b3ae','和疊山先生韻','王濟源','宋','宋诗','song-poetry','','[]','希武何意出山中，心事當年漢卧龍。',64,'全唐诗/poet.song.244000.json','["希武何意出山中，心事當年漢卧龍。", "行止但憑天作主，別離初不淚沾胸。", "定知晚菊能存節，未必寒松肯受封。", "大義昭明千載事，前程儘更好從容。"]'),
('e814538b-c703-4aa1-8e68-3b9ea924888a','送疊山先生北行','張子惠','宋','宋诗','song-poetry','','[]','打硬修行三十年，如今訂驗是儒仙。',64,'全唐诗/poet.song.244000.json','["打硬修行三十年，如今訂驗是儒仙。", "人皆屈膝甘爲下，公獨高聲駡向前。", "此去好憑三寸舌，再來不值一文錢。", "到頭畢竟全清節，留取芳名萬古傳。"]'),
('5cce1369-c4c7-470c-a5a4-d79c9564f9fb','和疊山先生韻  其一','魏天應','宋','宋诗','song-poetry','','[]','萬疊青山只麽青，從容時止又時行。',64,'全唐诗/poet.song.244000.json','["萬疊青山只麽青，從容時止又時行。", "斯文未喪予何畏，舉世隨流我獨清。", "日月精忠今古在，丘山道義死生輕。", "吾翁鐵脊文翁似，無愧淵明與孔明。"]'),
('d289e4ad-c7f5-4b45-88d0-4e1e102f49e1','和疊山先生韻  其二','魏天應','宋','宋诗','song-poetry','','[]','先生心事炳丹青，顧影何曾愧獨行。',64,'全唐诗/poet.song.244000.json','["先生心事炳丹青，顧影何曾愧獨行。", "商嶺芝能如橘隠，首陽粟不似薇清。", "綱常正要身扶植，出處端爲世重輕。", "安得寒泉來會宿，參同極論到天明。"]'),
('6b0780c4-cf09-4948-b1c9-bd55a9a0169a','和疊山先生韻','蔡正孫','宋','宋诗','song-poetry','','[]','山色愁予渺渺青，平生心事杜鵑行。',64,'全唐诗/poet.song.244000.json','["山色愁予渺渺青，平生心事杜鵑行。", "霜饕雪虐天終定，歲晚江空冰自清。", "肩上綱常千古重，眼前榮辱一毫輕。", "離明坤順文箕事，此是先生素講明。"]'),
('27d62b50-0876-4590-bc74-5951a9318a33','冷田村','蔡正孫','宋','宋诗','song-poetry','','[]','簑下清風笠下煙，一篙三板插秧船。',32,'全唐诗/poet.song.244000.json','["簑下清風笠下煙，一篙三板插秧船。", "田家午饁行厨薄，盡在青裙兩擔肩。"]'),
('4203896c-8850-47e1-8e57-76469171a8a6','送疊山先生北行','陳達翁','宋','宋诗','song-poetry','','[]','孤忠不忘綉衣時，跳足徉狂老亂離。',64,'全唐诗/poet.song.244000.json','["孤忠不忘綉衣時，跳足徉狂老亂離。", "鸚鵡不能逃圈網，麒麟寧肯受鞭羈。", "半生苦被名相誤，萬里甘將死自期。", "今日如公能有幾，此身無愧作男兒。"]'),
('7dc92189-43d8-454c-84f2-22bef1c66500','遺詩','朱宮人','宋','宋诗','song-poetry','','[]','既不辱國，幸免辱身。',40,'全唐诗/poet.song.244000.json','["既不辱國，幸免辱身。", "世食宋祿，羞爲北臣。", "妾輩之死，守於一貞。", "忠臣孝子，期以自新。"]'),
('043a8f71-4f09-4375-b540-588d1543a006','題清風嶺崖石','王氏','宋','宋诗','song-poetry','','[]','君王不幸妾當災，棄女拋男逐馬來。',64,'全唐诗/poet.song.244000.json','["君王不幸妾當災，棄女拋男逐馬來。", "夫面不知何日見，妾身還是幾時回。", "兩行怨淚頻偷滴，一對愁眉怎得開。", "遥望家鄉何處是，存忘兩字苦哀哉。"]'),
('f8eeb254-bafb-4697-96fb-8999b6f5799d','□□□','汪元量','宋','宋诗','song-poetry','','[]','□□□□□□□，□□□□□□□。',64,'全唐诗/poet.song.244000.json','["□□□□□□□，□□□□□□□。", "□□□□□地動，兵前草木挾風寒。", "計窮但覺歸降易，事定方知進退難。", "獻宅乞爲祈請使，酣歌食肉愧田單。"]'),
('8d722482-013a-4689-9b80-ed180eac576c','和徐雪江即事','汪元量','宋','宋诗','song-poetry','','[]','萬里起青烟，旌旗若湧泉。',48,'全唐诗/poet.song.244000.json','["萬里起青烟，旌旗若湧泉。", "國家開氣數，陵谷見推遷。", "避難渾無地，偷生頼有天。", "夜來聞大母，已自納降箋。"]'),
('74117ee5-6480-4e96-9b92-cc27b3071c4f','二月初八日左丞相吳堅右□□□□□樞密使謝堂參政密  其一','汪元量','宋','宋诗','song-poetry','','[]','原缺三十八字。',7,'全唐诗/poet.song.244000.json','["原缺三十八字。"]'),
('3d275536-f5f3-4192-afad-71a8dd5d42c3','二月初八日左丞相吳堅右□□□□□樞密使謝堂參政密  其二','汪元量','宋','宋诗','song-poetry','','[]','巵江海蛟□□□母子悲□□□□□□□□征詩。',21,'全唐诗/poet.song.244000.json','["巵江海蛟□□□母子悲□□□□□□□□征詩。"]'),
('0f625265-8d89-4bfb-9a65-f96e8f668a2c','望海樓獨立','汪元量','宋','宋诗','song-poetry','','[]','風吹腥氣滿樓臺，獨倚闌干十二回。',64,'全唐诗/poet.song.244000.json','["風吹腥氣滿樓臺，獨倚闌干十二回。", "天入越江龍逝去，雨昏吳市燕飛來。", "旌旗閃閃千帆過，簾幙重重一笛哀。", "惆悵玉環何處在，海棠猶自向人開。"]'),
('fa02a503-ae25-42af-a2ce-f917cc50ef8a','吳山曉望','汪元量','宋','宋诗','song-poetry','','[]','城南城北草芊芊，滿地干戈已惘然。',64,'全唐诗/poet.song.244000.json','["城南城北草芊芊，滿地干戈已惘然。", "燕燕鶑鶑隨戰馬，風風雨雨渡江船。", "小儒愁劇吟如哭，老子歌闌醉欲眠。", "一夜春寒花命薄，亂飄紅紫下平川。"]'),
('52b0e293-b68e-4376-bdf7-8261f9bfd937','同毛敏仲出湖上由萬松嶺過浙江亭','汪元量','宋','宋诗','song-poetry','','[]','錢塘門外看新晴，舞蜨游蜂沒一星。',64,'全唐诗/poet.song.244000.json','["錢塘門外看新晴，舞蜨游蜂沒一星。", "風挾斷雲橫北巘，烟隨飛雨度南屏。", "蘇隄柳樹照波綠，吳苑麥苗連地青。", "邂逅尋詩過嶺去，鼓鞞聲震浙江亭。"]'),
('f88a6ccf-dcad-4292-8c31-b326bae30ce7','客感和林石田','汪元量','宋','宋诗','song-poetry','','[]','細柳和烟舞溼雲，落花隨水送歸春。',64,'全唐诗/poet.song.244000.json','["細柳和烟舞溼雲，落花隨水送歸春。", "門東□□□應噪，江上白鷗誰肯馴。", "朱子不仁唐逆賊，□□□□誑漢忠。", "離亭一笛悲風急，君賦秦州□□□。"]'),
('ed08066a-8c26-44ec-948b-007d1c23bb1b','感慈元殿事','汪元量','宋','宋诗','song-poetry','','[]','翠華扶輦出彤庭，蜜炬星繁天未明。',64,'全唐诗/poet.song.244000.json','["翠華扶輦出彤庭，蜜炬星繁天未明。", "鵷鷺分行江上別，熊羆從駕雨中行。", "綠波淼淼浮三殿，紫禁沈沈斷六更。", "惟有周遭山似洛，不堪回首淚縱橫。"]'),
('c4ba661e-aba9-4c56-b854-0212af4e2039','錢塘歌','汪元量','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','錢塘江上龍光死，錢王宮闕今如此。',64,'全唐诗/poet.song.244000.json','["錢塘江上龍光死，錢王宮闕今如此。", "白髪宮娃作遠遊，漠漠平沙千萬里。", "西北高樓白雲齊，欲落未落日已低。", "古人不見今人去，江水東流烏夜啼。"]'),
('65e902ec-ee1e-4b38-b033-927874176403','別楊駙馬','汪元量','宋','宋诗','song-poetry','','[]','去去馬空冀北，行行鶴度遼東。',56,'全唐诗/poet.song.244000.json','["去去馬空冀北，行行鶴度遼東。", "彈鋏三千客裏，囊錐十九人中。", "杜子肯依嚴武，孔融不下曹公。", "南八男兒如此，殺身方是英雄。"]'),
('d4e58231-a89c-45ea-a802-e164b9a7cc9d','清明','汪元量','宋','宋诗','song-poetry','','[]','避難不知寒食，和愁又過清明。',28,'全唐诗/poet.song.244000.json','["避難不知寒食，和愁又過清明。", "都下紛紛躍馬，湖邊恰恰啼鶑。"]'),
('192abf58-0ec9-4733-b413-fd0f0a17f1a7','讀史','汪元量','宋','宋诗','song-poetry','','[]','餓死首陽二子，偷生商嶺四翁。',28,'全唐诗/poet.song.244000.json','["餓死首陽二子，偷生商嶺四翁。", "劉項稱王稱霸，關張無命無功。"]'),
('7d08fa4c-9be9-438c-a1ca-5637179611ee','廢宅','汪元量','宋','宋诗','song-poetry','','[]','王侯多第宅，草滿玉闌干。',24,'全唐诗/poet.song.244000.json','["王侯多第宅，草滿玉闌干。", "縱有春光在，人誰看牡丹。"]'),
('6ec02132-1335-4ec6-b7e9-bf7f152f237c','越女','汪元量','宋','宋诗','song-poetry','','[]','越女爲驅虜，朝來攬鏡慵。',24,'全唐诗/poet.song.244000.json','["越女爲驅虜，朝來攬鏡慵。", "欲梳新墮馬，忍□□□□。"]'),
('2c9f963a-5a70-4f79-aac8-13698db5d8c4','兵後登大內芙蓉閣宮人梳洗處','汪元量','宋','宋诗','song-poetry','','[]','粲粲芙蓉閣，我登雙眼明。',136,'全唐诗/poet.song.244000.json','["粲粲芙蓉閣，我登雙眼明。", "手拊沈香闌，美人已東征。", "美人未去時，朝理綠雲鬟，暮吹紫鸞笙。", "美人既去時，閣下麋鹿走，閣上鴟梟鳴。", "江山咫尺生烟霧，萬年枝上悲風生。", "空有遺鈿碎珥狼籍堆玉案，空有金蓮寶炬錯落懸珠楹。", "楊柳兮青青，芙蓉兮冥冥。", "美人不見空淚零，錦梁雙燕來又去，夜夜蟾蜍窺玉屏。"]'),
('b8059d45-5a85-47fb-bd04-1ff647125472','醉歌  其一','汪元量','宋','宋诗','song-poetry','','[]','呂將軍在守襄陽，十載襄陽鐵脊梁。',32,'全唐诗/poet.song.244000.json','["呂將軍在守襄陽，十載襄陽鐵脊梁。", "望斷援兵無信息，聲聲駡殺賈平章。"]'),
('77c2c2b2-19f4-41a7-9bf6-17f1bef23ef9','醉歌  其二','汪元量','宋','宋诗','song-poetry','','[]','援兵不遣事堪哀，食肉權臣大不才。',32,'全唐诗/poet.song.244000.json','["援兵不遣事堪哀，食肉權臣大不才。", "見說襄樊投拜了，千軍萬馬過江來。"]'),
('77c3d334-e6b2-4670-83d9-a7f998462248','醉歌  其三','汪元量','宋','宋诗','song-poetry','','[]','淮襄州郡盡歸降，鞞鼓喧天入古杭。',32,'全唐诗/poet.song.244000.json','["淮襄州郡盡歸降，鞞鼓喧天入古杭。", "國母已無心聽政，書生空有淚成行。"]'),
('b7c797b2-198c-43b8-ad9b-67baefec43a4','醉歌  其四','汪元量','宋','宋诗','song-poetry','','[]','六宮宮女淚漣漣，事主誰知不盡年。',32,'全唐诗/poet.song.244000.json','["六宮宮女淚漣漣，事主誰知不盡年。", "太后傳宣許降國，伯顔丞相到簾前。"]'),
('79fb22d0-a24f-45ab-8225-6e3dda03cfd7','醉歌  其五','汪元量','宋','宋诗','song-poetry','','[]','亂點連聲殺六更，熒熒庭燎待天明。',32,'全唐诗/poet.song.244000.json','["亂點連聲殺六更，熒熒庭燎待天明。", "侍臣已寫歸降表，臣妾僉名謝道清。"]'),
('7ac0f655-54bb-4461-be0e-5cdf92174de2','醉歌  其六','汪元量','宋','宋诗','song-poetry','','[]','衣冠不改只如先，關會通行滿市廛。',32,'全唐诗/poet.song.244000.json','["衣冠不改只如先，關會通行滿市廛。", "北客南人成買賣，京師依舊使銅錢。"]'),
('85478a9b-71c5-4a72-ac87-f1a5ff5748eb','醉歌  其七','汪元量','宋','宋诗','song-poetry','','[]','北師要討撒花銀，官府行移逼市民。',32,'全唐诗/poet.song.244000.json','["北師要討撒花銀，官府行移逼市民。", "丞相伯顔猶有語，學中要揀秀才人。"]'),
('e7e5357b-ecfb-4fdd-bc15-462bb9017dab','醉歌  其八','汪元量','宋','宋诗','song-poetry','','["\u897f\u6e56"]','湧金門外雨晴初，多少紅船上下趨。',32,'全唐诗/poet.song.244000.json','["湧金門外雨晴初，多少紅船上下趨。", "龍管鳳笙無韻調，却撾戰鼓下西湖。"]'),
('cd59509a-b5e3-499a-8f9f-39cfc8bfab05','醉歌  其九','汪元量','宋','宋诗','song-poetry','','[]','南苑西宮棘露芽，萬年枝上亂啼鴉。',32,'全唐诗/poet.song.244000.json','["南苑西宮棘露芽，萬年枝上亂啼鴉。", "北人環立闌干曲，手指紅梅作杏花。"]'),
('6612b74e-f7be-469c-a2bf-8c043e9f8c63','醉歌  其一○','汪元量','宋','宋诗','song-poetry','','[]','伯顔丞相呂將軍，收了江南不殺人。',32,'全唐诗/poet.song.244000.json','["伯顔丞相呂將軍，收了江南不殺人。", "昨日太皇請茶飯，滿朝朱紫盡降臣。"]'),
('514ba4dc-b00c-454b-9bfc-07c1ee7fbee1','賈魏公府  其一','汪元量','宋','宋诗','song-poetry','','[]','葛嶺當年宰相家，游人不敢此行過。',64,'全唐诗/poet.song.244000.json','["葛嶺當年宰相家，游人不敢此行過。", "柳陰夾道鶑成市，花影壓闌蜂閙衙。", "六載襄陽圍已解，三更魯港事如何。", "棟梁今日皆焦土，新有園丁種火麻。"]'),
('1f63e1ab-9ba2-41e8-bdab-cca3cb933098','賈魏公府  其二','汪元量','宋','宋诗','song-poetry','','[]','重門猶釘舊桃牌，惆悵行人去不回。',64,'全唐诗/poet.song.244000.json','["重門猶釘舊桃牌，惆悵行人去不回。", "萬種好花環曲徑，一泓流水遶香階。", "高臺已見胡羊走，喬木惟聞蜀鳥哀。", "簷外竹梅森似束，鄰翁時剪作燒柴。"]'),
('ad8f7187-c95f-4f82-803e-a844674ec15d','賈魏公府  其三','汪元量','宋','宋诗','song-poetry','','[]','湖邊不見碾香車，斷珥遺鈿滿路塗。',64,'全唐诗/poet.song.244000.json','["湖邊不見碾香車，斷珥遺鈿滿路塗。", "門逕風輕飛野馬，亭臺火盡及池魚。", "海棠花下生青杞，石竹叢邊出紫蘇。", "却憶相公游賞日，三千衛士立階除。"]'),
('6c2da8f4-e1a2-45ee-ac08-9a461de489c8','杭州雜詩和林石田  其一','汪元量','宋','宋诗','song-poetry','','[]','石田林處士，吟境靜無塵。',48,'全唐诗/poet.song.244000.json','["石田林處士，吟境靜無塵。", "亂後長如醉，愁來不爲貧。", "飯蔬留好客，筆硯老斯人。", "近法秦州體，篇篇妙入神。"]'),
('248caf56-f711-488a-94d0-563812b6c9dd','杭州雜詩和林石田  其二','汪元量','宋','宋诗','song-poetry','','[]','先生忘富貴，久客幸平安。',48,'全唐诗/poet.song.244000.json','["先生忘富貴，久客幸平安。", "髪已千莖白，心猶一寸丹。", "衣冠前進士，家世舊郎官。", "醉入烏程里，吟登李杜壇。"]'),
('da228afc-c9dd-40d7-81c2-536ddc6211ed','杭州雜詩和林石田  其三','汪元量','宋','宋诗','song-poetry','','[]','逃難藏深隠，重逢出近詩。',48,'全唐诗/poet.song.244000.json','["逃難藏深隠，重逢出近詩。", "乾坤一反掌，今古兩愁眉。", "我作新亭泣，君生舊國悲。", "向來行樂地，夜雨走狐狸。"]'),
('7827134f-dc31-4458-9d66-a8fba2a6b748','杭州雜詩和林石田  其四','汪元量','宋','宋诗','song-poetry','','[]','蠋也吞聲哭，潜行到水頭。',48,'全唐诗/poet.song.244000.json','["蠋也吞聲哭，潜行到水頭。", "人誰包馬革，子獨衣羊裘。", "水面生何益，南冠死則休。", "百年如過翼，撫掌笑孫劉。"]'),
('0ac07210-e220-4a34-9d14-c2b032f8ca5d','杭州雜詩和林石田  其五','汪元量','宋','宋诗','song-poetry','','[]','一春雲羃羃，三月雨淋淋。',48,'全唐诗/poet.song.244000.json','["一春雲羃羃，三月雨淋淋。", "魚菜不歸市，鶑花空滿林。", "人行官巷口，軍簇御街心。", "老子猖狂甚，猶歌梁甫吟。"]'),
('9949a184-80b6-48a9-be66-d99b22948069','杭州雜詩和林石田  其六','汪元量','宋','宋诗','song-poetry','','[]','烽火來千里，狼烟度六橋。',48,'全唐诗/poet.song.244000.json','["烽火來千里，狼烟度六橋。", "嶺寒蒼兕叫，江曉白魚跳。", "壯士披金甲，佳人弄玉簫。", "偶餘尊酒在，聊以永今朝。"]'),
('86a9a1f6-9139-4aa6-9833-9d918d02e933','杭州雜詩和林石田  其七','汪元量','宋','宋诗','song-poetry','','[]','有客腸回九，無人髪握三。',48,'全唐诗/poet.song.244000.json','["有客腸回九，無人髪握三。", "關中新約法，江左舊清談。", "鐵騎來天北，樓船過海南。", "一枝巢越鳥，八繭熟吳蠶。"]'),
('39e761d6-92e4-460b-8cb4-3757b2c1062b','杭州雜詩和林石田  其八','汪元量','宋','宋诗','song-poetry','','[]','躡足封韓信，剖心嗔比干。',48,'全唐诗/poet.song.244000.json','["躡足封韓信，剖心嗔比干。", "河山千古淚，風雨一番寒。", "世指鹿爲馬，人呼鳥作鸞。", "江頭潮洶洶，城脚水漫漫。"]'),
('5149cadd-9fe0-4606-a282-30c5f325edb2','杭州雜詩和林石田  其九','汪元量','宋','宋诗','song-poetry','','[]','吟身春共瘦，獨立望江亭。',48,'全唐诗/poet.song.244000.json','["吟身春共瘦，獨立望江亭。", "越水荒荒白，吳山了了青。", "軍降欣解甲，民喜罷抽丁。", "拍碎闌干曲，吞聲血淚零。"]'),
('d5993610-a1d1-42e2-8fdc-027c84eb1275','杭州雜詩和林石田  其一○','汪元量','宋','宋诗','song-poetry','','[]','天也今如此，人乎可奈何。',48,'全唐诗/poet.song.244000.json','["天也今如此，人乎可奈何。", "臺邊西子去，宮裏北人過。", "玉樹歌方息，金銅淚已多。", "旌旗遮御路，舟楫滿官河。"]'),
('e85d102f-687b-4c48-b665-1a35c6206f11','杭州雜詩和林石田  其一一','汪元量','宋','宋诗','song-poetry','','[]','此夕知何夕，游船雜戰船。',48,'全唐诗/poet.song.244000.json','["此夕知何夕，游船雜戰船。", "山河空百二，宮闕漫三千。", "雨歇雲垂地，潮平水接天。", "惜哉無祖逖，誰肯著先鞭。"]'),
('1efa6c1b-35ee-4beb-82bc-ad1caa855da4','杭州雜詩和林石田  其一二','汪元量','宋','宋诗','song-poetry','','[]','陵廟成焦土，宮牆沒野蒿。',48,'全唐诗/poet.song.244000.json','["陵廟成焦土，宮牆沒野蒿。", "亡秦皆趙李，佐漢獨蕭曹。", "國子乘黄貴，山人著白高。", "飛埃猶黯黯，逝水正滔滔。"]'),
('278412e0-c3e4-496c-ae4a-e48b6298c3fc','杭州雜詩和林石田  其一三','汪元量','宋','宋诗','song-poetry','','[]','靜看從衡士，番成買賣兒。',48,'全唐诗/poet.song.244000.json','["靜看從衡士，番成買賣兒。", "禁中驚戰鼓，城上出降旗。", "魏操非無漢，唐淵不有隋。", "從茲更革後，寧復太平期。"]'),
('59bfdf0f-b714-4416-b6aa-cac5c0c548a9','杭州雜詩和林石田  其一四','汪元量','宋','宋诗','song-poetry','','["\u897f\u6e56"]','偶出西湖上，新蒲綠未齊。',48,'全唐诗/poet.song.244000.json','["偶出西湖上，新蒲綠未齊。", "携來鯿縮項，買得蟹團臍。", "問酒入新店，喚船行舊隄。", "亂離多殺戮，水畔幾人啼。"]'),
('8b15ede3-25e6-4a0f-b2a5-1ecd657b9de2','杭州雜詩和林石田  其一五','汪元量','宋','宋诗','song-poetry','','[]','天目絲絲雨，江頭翦翦風。',48,'全唐诗/poet.song.244000.json','["天目絲絲雨，江頭翦翦風。", "鼓鞞千艇合，刁斗萬家同。", "金馬憐焦土，銅駝壓草叢。", "杞天愁欲墮，黑入太陰中。"]'),
('9ddd539b-2e7d-4f51-af59-c3de1979dbde','杭州雜詩和林石田  其一六','汪元量','宋','宋诗','song-poetry','','[]','日月往來轂，乾坤生殺機。',48,'全唐诗/poet.song.244000.json','["日月往來轂，乾坤生殺機。", "江春蛟妾舞，塞暖雁奴歸。", "逆旅詩添債，愁城酒破圍。", "如何秦相國，昨夜熓韓非。"]'),
('50cde232-0407-423f-a009-57510f6c8c91','杭州雜詩和林石田  其一七','汪元量','宋','宋诗','song-poetry','','[]','如此只如此，無聊酒一樽。',48,'全唐诗/poet.song.244000.json','["如此只如此，無聊酒一樽。", "江山猶昨日，笳鼓又新元。", "黑潦迷行路，黄埃入禁門。", "皋亭山頂上，百萬漢軍屯。"]'),
('de885c3d-d666-4657-8983-0c208b8b7bc6','杭州雜詩和林石田  其一八','汪元量','宋','宋诗','song-poetry','','[]','世變長椎髻，時更短後衣。',48,'全唐诗/poet.song.244000.json','["世變長椎髻，時更短後衣。", "魏庭翁仲泣，唐殿子孫非。", "樹禿鴉爭集，梁空燕自歸。", "斷橋春已暮，無頼柳花飛。"]'),
('f7a3084b-55f8-48f1-a52e-e5cd93f48f99','杭州雜詩和林石田  其一九','汪元量','宋','宋诗','song-poetry','','[]','春去雨方歇，水流花自飛。',48,'全唐诗/poet.song.244000.json','["春去雨方歇，水流花自飛。", "人生螻蟻夢，世道犬羊衣。", "日月東西驛，乾坤闔闢扉。", "斯令無二子，空有首陽薇。"]'),
('eb70ea76-e222-414a-884f-3c7a2743506e','杭州雜詩和林石田  其二○','汪元量','宋','宋诗','song-poetry','','[]','假途虞滅虢，嘗膽越吞吳。',48,'全唐诗/poet.song.244000.json','["假途虞滅虢，嘗膽越吞吳。", "黑白一棋局，方圓八陣圖。", "是翁猶矍鑠，諸老自揶揄。", "喟歎投麟筆，悲歌擊唾壺。"]'),
('39797db5-ee7e-4572-95f4-3697e63a56c3','杭州雜詩和林石田  其二一','汪元量','宋','宋诗','song-poetry','','[]','竟夕柴門掩，無心接縉紳。',48,'全唐诗/poet.song.244000.json','["竟夕柴門掩，無心接縉紳。", "山中多樂事，世上少全人。", "諸呂幾亡漢，商翁不仕秦。", "柴桑深僻處，亦有晉遺民。"]'),
('0fdfcedc-07bd-4167-931f-395230bd353e','杭州雜詩和林石田  其二二','汪元量','宋','宋诗','song-poetry','','[]','天下愁無盡，生前樂有涯。',48,'全唐诗/poet.song.244000.json','["天下愁無盡，生前樂有涯。", "文章一小技，富貴總虛花。", "塵入金張宅，草生王謝家。", "可憐三月火，不見八姨車。"]'),
('959568d4-3a46-4f9e-ab7a-3b710060f44f','杭州雜詩和林石田  其二三','汪元量','宋','宋诗','song-poetry','','[]','休休休休休，干戈盡白頭。',48,'全唐诗/poet.song.244000.json','["休休休休休，干戈盡白頭。", "諸公雲北去，萬事水東流。", "春雨不知止，晚山相對愁。", "呼童携斗酒，我欲一登樓。"]'),
('080848b7-1df1-47ca-b438-4410f614d8e8','送琴師毛敏仲北行  其一','汪元量','宋','宋诗','song-poetry','','[]','西塞山前日落處，北關門外雨來天。',32,'全唐诗/poet.song.244000.json','["西塞山前日落處，北關門外雨來天。", "南人墮淚北人笑，臣甫頭低拜杜鵑。"]'),
('106f9872-6f4d-4e4e-a5f6-f85e35bba26a','送琴師毛敏仲北行  其二','汪元量','宋','宋诗','song-poetry','','[]','五里十里亭長短，千帆萬帆船去來。',32,'全唐诗/poet.song.244000.json','["五里十里亭長短，千帆萬帆船去來。", "請君收淚向前去，要看幽州金築臺。"]'),
('408fb0b2-a906-400b-9ea9-65e909213e9d','送琴師毛敏仲北行  其三','汪元量','宋','宋诗','song-poetry','','[]','蘇子瞻喫惠州飯，黄魯直度鬼門關。',32,'全唐诗/poet.song.244000.json','["蘇子瞻喫惠州飯，黄魯直度鬼門關。", "今日君行清淚落，他年勛業勒燕山。"]'),
('766320c0-5e6f-4b56-95ea-b3f609896c2a','吳兒','汪元量','宋','宋诗','song-poetry','','[]','玉貌兒童淚盈把，辮髪垂肩行酒斚。',32,'全唐诗/poet.song.244000.json','["玉貌兒童淚盈把，辮髪垂肩行酒斚。", "將軍又去打蘇州，出門指使教牽馬。"]'),
('0c4e9fd9-9595-49ca-97e8-f10be3933924','答林石田','汪元量','宋','宋诗','song-poetry','','[]','南朝千古傷心事，每閲陳編淚滿襟。',32,'全唐诗/poet.song.244000.json','["南朝千古傷心事，每閲陳編淚滿襟。", "我更傷心成野史，人看野史更傷心。"]'),
('1b6af472-6ce0-49ec-a44f-800b001ff61d','浙江亭別客','汪元量','宋','宋诗','song-poetry','','[]','諸公來此欲憑闌，禿樹粘雲溼不乾。',64,'全唐诗/poet.song.244000.json','["諸公來此欲憑闌，禿樹粘雲溼不乾。", "小燕正嫌三月雨，老鶑又受一春寒。", "樓頭呼酒盡情飲，江上遇花隨意看。", "莫怨人生有離別，人生到此別離難。"]'),
('2c22bf10-6c19-4742-849f-70676887fb9d','江上','汪元量','宋','宋诗','song-poetry','','[]','太學諸齋揀秀才，出門何處是金臺。',64,'全唐诗/poet.song.244000.json','["太學諸齋揀秀才，出門何處是金臺。", "楝花風緊子規急，楊柳烟昏黄鳥哀。", "潮落潮生天外去，人歌人哭水邊來。", "推篷坐對吳山月，幾度關門擊柝回。"]'),
('8c40c794-ea92-4151-97a8-70bee4a68507','曉行','汪元量','宋','宋诗','song-poetry','','[]','癡坐書窗待曉鐘，背燈無語意無窮。',64,'全唐诗/poet.song.244000.json','["癡坐書窗待曉鐘，背燈無語意無窮。", "一家骨肉正愁絕，四海弟兄如夢同。", "西舍東鄰今日別，北魚南雁幾時通。", "行行忍見御溝水，流出滿江花片紅。"]'),
('5219e5e6-64d4-4cd1-a122-b47e315a1833','北征','汪元量','宋','宋诗','song-poetry','','[]','北師有嚴程，挽我投燕京。',96,'全唐诗/poet.song.244000.json','["北師有嚴程，挽我投燕京。", "挾此萬卷書，明發萬里行。", "出門隔山嶽，未知死與生。", "三宮錦帆張，粉陣吹鸞笙。", "遺氓拜路傍，號哭皆失聲。", "吳山何青青，吳水何泠泠。", "山水豈有極，天地終無情。", "回首叫重華，蒼梧雲正橫。"]'),
('6c412635-b5df-4cd8-be41-9d894624932b','吳江','汪元量','宋','宋诗','song-poetry','','[]','吳江潮水化蟲沙，兩岸垂楊噪亂鴉。',64,'全唐诗/poet.song.244000.json','["吳江潮水化蟲沙，兩岸垂楊噪亂鴉。", "舟子魚羹分宰相，路人麥飯進官家。", "莫思後事悲前事，且向天涯到海涯。", "回首尚憐西去路，臨平山下有荷花。"]'),
('61bfedc2-2288-4085-befe-952ad0611176','蘇臺','汪元量','宋','宋诗','song-poetry','','[]','闔閭門外草如霜，到此躊躇欲斷腸。',64,'全唐诗/poet.song.244000.json','["闔閭門外草如霜，到此躊躇欲斷腸。", "紅陣教成人已去，黄池會罷事堪傷。", "將雛野鹿銜枯薺，挾子宮烏噪夕陽。", "越蠡扁舟漭無所，五湖風浪白茫茫。"]'),
('e16e0115-82f9-44e6-939e-e391fe5abcc3','虎丘','汪元量','宋','宋诗','song-poetry','','[]','維舟與客訪興亡，寺有殘僧說故王。',64,'全唐诗/poet.song.244000.json','["維舟與客訪興亡，寺有殘僧說故王。", "寶物已銷龍虎氣，奎章猶射斗牛光。", "爲妖真女花藏墓，說法生公月滿堂。", "邂逅一樽歸路遠，樵歌牧笛送斜陽。"]'),
('eedf76e0-2fee-41cf-b90b-f85aee9a98c5','惠山值雨','汪元量','宋','宋诗','song-poetry','','[]','惠山寺裏北人過，古柏莖莖伐盡柯。',64,'全唐诗/poet.song.244000.json','["惠山寺裏北人過，古柏莖莖伐盡柯。", "三世佛身猶破相，一泓泉水亦生波。", "山林雖樂元非樂，塵世多魔未是魔。", "舉似于人何以故，坐簷閒看雨霶𩃱。"]'),
('bc6f403d-05c3-43a7-a342-e4a89e34a258','畫溪酒邊','汪元量','宋','宋诗','song-poetry','','[]','夜來飲酒醉如何，酒醒方知事轉多。',64,'全唐诗/poet.song.245000.json','["夜來飲酒醉如何，酒醒方知事轉多。", "趙國未衰廉藺在，齊城將下酈韓過。", "鵲飛月樹無依所，龍入風江漫作波。", "忽有好詩來眼底，畫溪榔板唱漁歌。"]'),
('c3424a3b-6d05-4083-a91a-2fb3a64a7599','常州','汪元量','宋','宋诗','song-poetry','','[]','渡頭風起柳摇絲，丁卯橋邊屋已稀。',64,'全唐诗/poet.song.245000.json','["渡頭風起柳摇絲，丁卯橋邊屋已稀。", "河草青青淮馬健，江花冉冉海鷗肥。", "一樽酒對三人飲，八字帆分兩岸飛。", "天末有人難問訊，仲連東去不須歸。"]'),
('d455ea37-01b5-4ef1-aa20-6afa549db734','重游甘露寺','汪元量','宋','宋诗','song-poetry','','[]','小留甘露莫開船，我欲題詩寄佛軒。',64,'全唐诗/poet.song.245000.json','["小留甘露莫開船，我欲題詩寄佛軒。", "犬下脩廊迎宿客，僧歸曲巷背𣟴門。", "梅邊拂石安棋局，竹外鳴琴薦酒尊。", "却憶市朝無事日，笙歌日日醉昏昏。"]'),
('6f373516-6370-4c40-8362-ec56f16f5842','多景樓','汪元量','宋','宋诗','song-poetry','','[]','多景樓中晝掩扉，畫梁不敢住烏衣。',64,'全唐诗/poet.song.245000.json','["多景樓中晝掩扉，畫梁不敢住烏衣。", "禪房花木兵燒殺，佛寺干戈僧怕歸。", "山雨欲來淮樹立，潮風初起海雲飛。", "酒尊未盡登舟急，更過金焦看落暉。"]'),
('f2831058-8341-4432-abc5-efeec73550d5','金山','汪元量','宋','宋诗','song-poetry','','[]','楊柳隄邊看渡船，金山山上訪金仙。',64,'全唐诗/poet.song.245000.json','["楊柳隄邊看渡船，金山山上訪金仙。", "一江風起塵揚海，兩岸潮來浪拍天。", "龍化老人頻問法，狐爲少婦竊聽禪。", "此機何與書生事，且借方牀熟晝眠。"]'),
('073e2161-8a23-4457-9ccc-1d3522b9280f','焦山','汪元量','宋','宋诗','song-poetry','','[]','焦山寺裏白雲堆，百尺危樓百尺臺。',64,'全唐诗/poet.song.245000.json','["焦山寺裏白雲堆，百尺危樓百尺臺。", "持咒聖僧漂海去，尋詩閒客渡江來。", "雷轟古樹蜈公出，日轉虛簷燕子回。", "案上楞嚴都好在，昆明又見有新灰。"]'),
('7d129ccf-cf2e-4fe8-b1ca-90b67dfffae6','京口野望','汪元量','宋','宋诗','song-poetry','','[]','傍岸人家插酒旗，受降城下客行稀。',64,'全唐诗/poet.song.245000.json','["傍岸人家插酒旗，受降城下客行稀。", "南徐白晝虎成陣，北固黄昏鴉打圍。", "亂後江山元歷歷，愁邊楊柳極依依。", "櫂歌漁子無些事，網得時魚換酒歸。"]'),
('03a47c92-4b0f-4ef5-90b7-0c4cbb9be779','揚子江','汪元量','宋','宋诗','song-poetry','','[]','揚子津頭客子愁，孤舟欲渡意綢繆。',64,'全唐诗/poet.song.245000.json','["揚子津頭客子愁，孤舟欲渡意綢繆。", "蛟龍洶洶爭新穴，鷗鷺輕輕下故洲。", "水捲岸沙連地去，風掀江浪接天流。", "試披陸羽圖經看，洗鼎煎茶更少留。"]'),
('6763c903-49da-4823-96f5-5d5f0bf9d461','揚州','汪元量','宋','宋诗','song-poetry','','[]','江都王氣逐浮漚，舊說維揚第一州。',64,'全唐诗/poet.song.245000.json','["江都王氣逐浮漚，舊說維揚第一州。", "銀燭夜攢喧鳳吹，金鞍曉織衛龍舟。", "綠蕪城上軍聲合，紅藥階前客淚收。", "雲散月明天在水，誤疑身世落瀛洲。"]'),
('5da87c8e-b87f-4780-a82e-14f8ad13f134','淮安水驛','汪元量','宋','宋诗','song-poetry','','[]','薄暮舟維楊柳隄，手攀楊柳立多時。',64,'全唐诗/poet.song.245000.json','["薄暮舟維楊柳隄，手攀楊柳立多時。", "漢兒快意歌荷葉，越女含愁舞柘枝。", "月溼江花和露泫，潮摇淮樹带風悲。", "長亭一夜渾無寐，與客傳杯更和詩。"]'),
('af31eaa4-d1cb-43d5-9807-d86febd1a3d3','邳州','汪元量','宋','宋诗','song-poetry','','[]','身如傳舍任西東，夜榻荒郵四壁空。',64,'全唐诗/poet.song.245000.json','["身如傳舍任西東，夜榻荒郵四壁空。", "鄉夢漸生燈影外，客愁多在雨聲中。", "淮南火後居民少，河北兵前戰鼓雄。", "萬里別離心正苦，帛書何日寄歸鴻。"]'),
('4dfa9306-ca2c-4bf4-8bb6-1a0050bca440','徐州','汪元量','宋','宋诗','song-poetry','','[]','白楊獵獵起悲風，滿目黄埃漲太空。',64,'全唐诗/poet.song.245000.json','["白楊獵獵起悲風，滿目黄埃漲太空。", "野壁山牆彭祖宅，塺花糞草項王宮。", "古今盡付三杯外，豪傑同歸一夢中。", "更上城樓見城郭，亂鴉古木夕陽紅。"]'),
('d2cc41e6-4775-4f20-8f8b-1bafd5059cd4','戲馬臺','汪元量','宋','宋诗','song-poetry','','[]','臺空馬盡始知休，枳棘叢邊鹿自游。',64,'全唐诗/poet.song.245000.json','["臺空馬盡始知休，枳棘叢邊鹿自游。", "泗水不關興廢事，佛峰空鎖古今愁。", "風吹野甸稻花晚，雨暗山城楓葉秋。", "欲弔英靈何處在，髑髏無數滿長洲。"]'),
('b9718470-7ea7-4cba-9dfe-dd31bf41699b','燕子樓','汪元量','宋','宋诗','song-poetry','','[]','樓顛瓦解草如鬣，燕子不來風獵獵。',32,'全唐诗/poet.song.245000.json','["樓顛瓦解草如鬣，燕子不來風獵獵。", "倚筇搔首重徘徊，野花叢裏飛蝴蜨。"]'),
('bb1057db-5ff0-4fe1-a5da-d408a063823d','呂梁','汪元量','宋','宋诗','song-poetry','','[]','呂梁三十仞，縣水莫知源。',48,'全唐诗/poet.song.245000.json','["呂梁三十仞，縣水莫知源。", "雨歇山如沃，波狂岸欲翻。", "黄雲撲古塞，青草織平原。", "最是關情處，秋霜一夜猿。"]'),
('9c398236-6998-41ae-96bf-8d75d01470b0','歌風臺','汪元量','宋','宋诗','song-poetry','','[]','百尺荒臺禾黍悲，沈思往事似輪飛。',64,'全唐诗/poet.song.245000.json','["百尺荒臺禾黍悲，沈思往事似輪飛。", "洛中車駕秦皇去，沛上風雲漢帝歸。", "鷹入塞榆衝雁陣，鶻穿城樹破鴉圍。", "東徐多少英雄恨，留與行人歌是非。"]'),
('51ea0d4d-bbf6-455c-b656-e274a62353f1','觀魚臺','汪元量','宋','宋诗','song-poetry','','[]','高臺留古跡，不見隠公游。',48,'全唐诗/poet.song.245000.json','["高臺留古跡，不見隠公游。", "白日悲風起，清河逆水流。", "潜魚投別浦，狡兔據荒丘。", "應笑臧僖伯，何如諫得休。"]'),
('b9f0f8ea-19f3-4ed2-a540-96799d214f3e','東平官舍','汪元量','宋','宋诗','song-poetry','','[]','曉鞭驛馬入東州，瘦骨稜嶒怯素秋。',64,'全唐诗/poet.song.245000.json','["曉鞭驛馬入東州，瘦骨稜嶒怯素秋。", "天地不仁人去國，江山如待客登樓。", "市沽魯酒難爲醉，座咽胡笳易得愁。", "日暮憑闌窮目力，一行征雁塞邊頭。"]'),
('75d6f608-96a0-4339-91f1-b41b247c4608','通州道中','汪元量','宋','宋诗','song-poetry','','[]','一片秋雲妬太虛，窮荒漠漠走羣狐。',64,'全唐诗/poet.song.245000.json','["一片秋雲妬太虛，窮荒漠漠走羣狐。", "西瓜黄處藤如織，北棗紅時樹若屠。", "雪塞搗砧人戍遠，霜營吹角客愁孤。", "幾回兀坐穹廬下，頼有葡萄酒熟初。"]'),
('d0ac4493-03e7-4b54-8885-bfd2942b80a3','幽州會同館','汪元量','宋','宋诗','song-poetry','','[]','六花飛舞下天衢，萬里羈人心正孤。',64,'全唐诗/poet.song.245000.json','["六花飛舞下天衢，萬里羈人心正孤。", "收拾碎磚裨煖炕，掘穿平地結寒爐。", "行厨日給官中粟，遞驛時供塞上酥。", "忽報傳宣雙敕使，王門今欲試齊竽。"]'),
('61b1582f-f874-482a-aaff-5380f5e6eeae','黄金臺和吳實堂韻','汪元量','宋','宋诗','song-poetry','','[]','把酒上金臺，傷心淚落杯。',48,'全唐诗/poet.song.245000.json','["把酒上金臺，傷心淚落杯。", "君臣難再得，天地不重來。", "古木巢蒼鶻，殘碑枕碧苔。", "倚闌休北望，萬里起黄埃。"]'),
('771e35ac-a15d-49c9-aae2-cfc9e44260b4','幽州歌','汪元量','宋','宋诗','song-poetry','','[]','漢兒辮髪籠氈笠，日暮黄金臺上立。',32,'全唐诗/poet.song.245000.json','["漢兒辮髪籠氈笠，日暮黄金臺上立。", "臂鷹解带忽放飛，一行塞雁南征急。"]'),
('34ba2217-ead4-4971-ab68-515d1d80a5fb','御宴蓬萊島','汪元量','宋','宋诗','song-poetry','','[]','曉入重闈對冕旒，內家開宴擁歌謳。',64,'全唐诗/poet.song.245000.json','["曉入重闈對冕旒，內家開宴擁歌謳。", "駝峰屢割分金盌，馬嬭時傾泛玉甌。", "禁苑風生亭北角，寢園日轉殿西頭。", "山前山後花如錦，一朵紅雲侍輦游。"]'),
('47cb56fc-57b0-4a8e-aa9a-dfb82e458085','幽州寒食游江鄉園','汪元量','宋','宋诗','song-poetry','','[]','曉出城南信杖藜，江鄉小圃百花開。',64,'全唐诗/poet.song.245000.json','["曉出城南信杖藜，江鄉小圃百花開。", "侑尊妓女騎馿去，頂笠僧官躍馬來。", "幾架秋千紅嬝娜，數行簫管綠低徊。", "隔河小艇人歌舞，摇蕩春光不肯回。"]'),
('5ac34925-3c15-4ba0-9540-272e79fb8c5d','登薊門用家則堂韻','汪元量','宋','宋诗','song-poetry','','[]','薊門高處小凝眸，雨後林巒翠欲流。',64,'全唐诗/poet.song.245000.json','["薊門高處小凝眸，雨後林巒翠欲流。", "車笠自來還自去，笳簫如怨復如愁。", "珍珠絡臂誇燕舞，紗帽蒙頭笑楚囚。", "忽憶舊家行樂地，春風花柳十三樓。"]'),
('fea0980e-9c81-479b-bf47-d16d76fad2cc','燕山送黄千戶之旴江','汪元量','宋','宋诗','song-poetry','','[]','萬里關河道路迂，出門一笑意何如。',64,'全唐诗/poet.song.245000.json','["萬里關河道路迂，出門一笑意何如。", "來時雨雪侵駝褐，歸日風雲藹駟車。", "玉座喜聞黄石策，金臺榮拜紫泥書。", "野人無以效芹獻，一斗酒邊雙鯉魚。"]'),
('c5d11688-445c-4566-871e-aacf908f0a4a','盧奉御自上都回見訪','汪元量','宋','宋诗','song-poetry','','[]','詩人騎馬接官回，解后居庸懷抱開。',64,'全唐诗/poet.song.245000.json','["詩人騎馬接官回，解后居庸懷抱開。", "冷地不禁風聒聒，炎天長見雪堆堆。", "昨宵我夢中南去，今日君從直北來。", "說盡窮陰無限事，呼童携酒上金臺。"]'),
('cdc4151c-71e4-49f1-98fe-473ff6b86130','筠溪王奉御寄詩次韻呈崖松盧奉御','汪元量','宋','宋诗','song-poetry','','["\u897f\u6e56"]','新詩蒙遠寄，客路不勝秋。',48,'全唐诗/poet.song.245000.json','["新詩蒙遠寄，客路不勝秋。", "同谷歌臣甫，新豐醉客周。", "君今嫌作吏，我已厭封侯。", "何日西湖曲，紅船上下游。"]'),
('22100377-58ea-449b-bdf6-278d0afc546d','幽州秋日聽王昭儀琴','汪元量','宋','宋诗','song-poetry','','[]','瑶池宴罷夜何其，拂拭朱絃落指遲。',64,'全唐诗/poet.song.245000.json','["瑶池宴罷夜何其，拂拭朱絃落指遲。", "彈到急時聲不亂，曲當終處意尤奇。", "雪深沙磧王嬙怨，月滿關山蔡琰悲。", "羈客相看默無語，一襟愁思自心知。"]'),
('a390771f-1fcc-440b-9d2c-d6d801d4cd76','薊北春望','汪元量','宋','宋诗','song-poetry','','[]','江南二月蕨筍肥，江北客行殊未歸。',32,'全唐诗/poet.song.245000.json','["江南二月蕨筍肥，江北客行殊未歸。", "怕上西樓洒鄉淚，東風吹雨濕征衣。"]'),
('50a604ee-c255-4f2b-ae00-8344766e0754','燕歌行','汪元量','宋','宋诗','song-poetry','','[]','北風刮地愁雲彤，草木爛死黄塵蒙。',218,'全唐诗/poet.song.245000.json','["北風刮地愁雲彤，草木爛死黄塵蒙。", "撾鞞伐鼓聲鼕鼕，金鞍鐵馬摇玲瓏。", "將軍浩氣吞長虹，幽并健兒膽力雄。", "戰車軋軋馳先鋒，甲戈相撥聲摩空。", "雁行魚貫彎角弓，披霜踏雪渡海東。", "鬬血浸野吹腥風，捐軀報國效死忠。", "鼓衰矢竭誰收功，將軍卸甲入九重。", "錦袍宣賜金團龍，天子錫宴葡萄宮。", "烹龍炰鸞割駝峰，紫霞瀲灧琉璃鍾。", "天顔有喜春融融，乞與窈窕雙芙蓉。", "虎符腰佩官益穹，歸來賀客皆王公。", "戟門和氣春風中，美人左右如花紅。", "朝歌夜舞何時窮，豈知沙場雨溼悲風急，冤魂戰鬼成行泣。"]'),
('bd644bcc-ba8d-4d2a-878d-fbba95285fe1','秋日酬王昭儀','汪元量','宋','宋诗','song-poetry','','[]','愁到濃時酒自斟，挑燈看劍淚痕深。',64,'全唐诗/poet.song.245000.json','["愁到濃時酒自斟，挑燈看劍淚痕深。", "黄金臺隗少知己，碧玉調湘空好音。", "萬葉秋風孤館夢，一燈夜雨故鄉心。", "庭前昨夜梧桐語，勁氣蕭蕭入短襟。"]'),
('54f861bc-02ae-4aeb-a21e-690405c054c1','平原郡公夜宴月下待瀛國公歸寓府','汪元量','宋','宋诗','song-poetry','','[]','春事闌珊夢裏休，他鄉相見淚空流。',64,'全唐诗/poet.song.245000.json','["春事闌珊夢裏休，他鄉相見淚空流。", "柳摇楚館牽新恨，花落吳宮憶舊游。", "渴想和羹梅已熟，饑思進飯麥初收。", "瀛洲歸去琅玕長，月朗風熏十二樓。"]'),
('a5784406-aa15-47f6-996d-0c01dcf89f9a','燕山九日','汪元量','宋','宋诗','song-poetry','','[]','九日淒凉戲馬臺，龍山高會亦塵埃。',64,'全唐诗/poet.song.245000.json','["九日淒凉戲馬臺，龍山高會亦塵埃。", "天翻地覆英雄盡，暑往寒來歲月催。", "人隔關河歸未得，客逢時節轉堪哀。", "十年舊夢風吹過，忍對黄花把酒杯。"]'),
('d485f145-840f-43ac-ab08-f7922f246dfe','幽州雪霽翰林諸公分韻得明字','汪元量','宋','宋诗','song-poetry','','[]','寒雪初晴冷氣清，地爐火活漸春生。',64,'全唐诗/poet.song.245000.json','["寒雪初晴冷氣清，地爐火活漸春生。", "嬾騎□□□人戶，滿酌肥羔朝帝京。", "屋破玉川貧亦樂，□□□塢貴何榮。", "道心自得鍾儀趣，一操南音□□□。"]'),
('cfd516a5-1917-4562-a77e-9323ae8b7fa0','庚辰正月旦早朝呈留忠齋','汪元量','宋','宋诗','song-poetry','','[]','庭燎明如晝，金壺漏水平。',48,'全唐诗/poet.song.245000.json','["庭燎明如晝，金壺漏水平。", "爐烟摇曉色，櫩□□□聲。", "三祝聖人壽，一忠臣子情。", "新元奏封事，□□□蒼生。"]'),
('5e7ef5b7-96de-4b55-b3d3-f2adfd44df1a','妾薄命呈文山道人','汪元量','宋','宋诗','song-poetry','','[]','妾初未嫁時，晨夕深閨中。',180,'全唐诗/poet.song.245000.json','["妾初未嫁時，晨夕深閨中。", "年當十五餘，顔色如花紅。", "千里遠結婚，出門山重重。", "與君盛容飾，一笑開芙蓉。", "君不顧妾色，劍氣干長虹。", "耿耿丈夫□，□□天下雄。", "結髪未逾載，倏然各西東。", "妾獨□□□，□養姑與翁。", "姑翁去年春，長夢隨飄風。", "思君□□□，音信安可通。", "諒無雙飛翼，焉得長相從。", "自服嫁時衣，荆釵淡爲容。", "誓以守貞潔，與君生死同。", "君當立高節，殺身以爲忠。", "豈無春秋筆，爲君紀其功。"]'),
('f4981351-0b77-4351-84e3-a8ad893083d1','幽州送景僧錄歸錢塘','汪元量','宋','宋诗','song-poetry','','[]','天目山前景老禪，長安傳法舊沙門。',64,'全唐诗/poet.song.245000.json','["天目山前景老禪，長安傳法舊沙門。", "十年不見身爲累，萬里相逢舌尚存。", "漠漠塵埃凝破衲，淒淒風露襲歸轅。", "到家定有秋光在，報答黄花滿故園。"]'),
('1daf7071-9646-4f8c-9e76-2e2a7ad0adf5','冬至日同舍會拜','汪元量','宋','宋诗','song-poetry','','[]','燕市人爭看秀才，團欒此日會金臺。',64,'全唐诗/poet.song.245000.json','["燕市人爭看秀才，團欒此日會金臺。", "葡萄酒熟澆駝髓，蘿蔔羹甜煮鹿胎。", "硯筆寂寥空洒淚，管絃嗚咽自生哀。", "雪寒門戶賓朋少，且撥紅爐守泰來。"]'),
('a41bef73-c609-41db-ac29-312d4fac0292','自笑','汪元量','宋','宋诗','song-poetry','','[]','釋氏掀天官府，道家隨世功名。',28,'全唐诗/poet.song.245000.json','["釋氏掀天官府，道家隨世功名。", "俗子執鞭亦貴，書生無用分明。"]'),
('0b7803cc-dc7b-4a7c-99ce-97a43de2d007','斡魯垛觀獵','汪元量','宋','宋诗','song-poetry','','[]','黑風滿天紅日出，千里萬里棲寒烟。',64,'全唐诗/poet.song.245000.json','["黑風滿天紅日出，千里萬里棲寒烟。", "快鷹已落薊水畔，獵馬更在燕山前。", "白旄黄鉞左右繞，氈房殿帳東西旋。", "海青眇然從此去，天鵝正墜陰崖巔。"]'),
('0df406a7-0a55-45d9-95a2-92eec2fa14e1','幽州月夜酒邊賦西湖月','汪元量','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖月，光皎潔，曾照錢王九重闕。',291,'全唐诗/poet.song.245000.json','["西湖月，光皎潔，曾照錢王九重闕。", "錢王歌舞戀春風，月亦有情光不歇。", "一朝歌舞成塵土，斷礎荒宮走狐兔。", "月亦傷心不肯明，人亦吞聲淚如雨。", "西湖月，幾度圓，幾度缺。", "人生南北岐路多，幾度相逢幾度別。", "去年月圓時，我在西湖十里荷花香，□□月吞酒巵。", "今年月缺時，我在燕山萬里來□□，□酒招月來。", "勸月酒一杯，我酒飲盡□□□□□□飲，胡爲乎來哉。", "停杯問月月變色，嫌□□□□□窄。", "人生如白駒之過隙，若不痛飲真可惜。", "□□□物如流水，何如月照金樽裏。", "首陽二子忍□□，□丘盜跖成螻蟻。", "我有長鯨吸川口，倒挽銀河添我酒。", "我酒千年飲不乾，月光與我長相守。", "酒酣拔劍斫地歌，錢王宮闕生白波。", "西湖月，光更多，有酒不飲將如之何。"]'),
('394094ff-91e4-4c2c-a857-59b0ed79df88','瀘溝橋王昭儀見寄回文次韻','汪元量','宋','宋诗','song-poetry','','[]','溝水瀘邊落木疏，舊家天遠寄來書。',64,'全唐诗/poet.song.245000.json','["溝水瀘邊落木疏，舊家天遠寄來書。", "秋風冷驛官行未，夜月虛窗客夢初。", "流雁斷鴻飛曠野，舞鸞離鶴別穹廬。", "裘貂醉盡一樽酒，愁散方知獨上車。"]'),
('3f4fa999-1b00-42d4-af2c-8b2356c73a44','幽州除夜','汪元量','宋','宋诗','song-poetry','','[]','十年旅食在天涯，到處身安只是家。',64,'全唐诗/poet.song.245000.json','["十年旅食在天涯，到處身安只是家。", "雪塞春回鄒衍律，霜營寒入禰衡撾。", "壺傾卯酒杯浮粟，厨出辛盤飣簇花。", "奴僕不須喧鼓吹，恐驚櫪馬與林鴉。"]'),
('cda00b8c-f0c3-4ec2-bb4b-51b16b5c602a','關山月','汪元量','宋','宋诗','song-poetry','','[]','關山月，關山月，東邊來，西邊沒。',188,'全唐诗/poet.song.245000.json','["關山月，關山月，東邊來，西邊沒。", "夜夜照關山，□□多戰骨。", "男兒莫去學弓刀，女兒莫嫁關山□。", "□□母啼送爺去當軍，今年妻啼送夫去當□。", "□□□老妻年少，養子嫁夫不得力。", "關山月，關山月，□□見月圓，月月見月缺。", "萬里征夫淚流血。", "將軍□□大羽箭，沙場格鬬無休歇。", "誰最苦兮誰□□，□□出戍當門戶。", "只今頭白未還鄉，母死妻亡業無主。", "關山月，關山月，生離別，死離別。", "爺娘妻子顧不得，努力戎行當報國。"]'),
('1f8e4fdd-91d8-436b-b38f-aa833cbaf0e4','出居庸關','汪元量','宋','宋诗','song-poetry','','[]','平生愛讀書，反被讀書誤。',84,'全唐诗/poet.song.245000.json','["平生愛讀書，反被讀書誤。", "今辰出長城，未知死何處。", "下馬古戰場，荆榛莽回互。", "羣狐正從橫，野梟號古樹。", "黑雲滿天飛，白日翳復吐。", "移時風揚沙，人馬俱失路。", "躊躇默吞聲，聊歌遠游賦。"]'),
('a5deb733-6e09-4226-a44a-396cc54a80c0','長城外','汪元量','宋','宋诗','song-poetry','','[]','飲馬長城窟，馬繁水枯竭。',84,'全唐诗/poet.song.245000.json','["飲馬長城窟，馬繁水枯竭。", "水竭將奈何，馬嘶不肯歇。", "君看長城中，盡是骷髏骨。", "骷髏幾千年，猶且未滅沒。", "空銜千年冤，此冤何時雪。", "祖龍去已遠，長城久迸裂。", "嘆息此骷髏，夜夜泣秋月。"]'),
('7e7990df-5554-4852-993d-47a538442b65','寰州道中','汪元量','宋','宋诗','song-poetry','','[]','窮荒六月天，地有一尺雪。',72,'全唐诗/poet.song.245000.json','["窮荒六月天，地有一尺雪。", "孤兒可憐人，哀哀淚流血。", "書生不忍啼，尸坐愁欲絕。", "鼙鼓夜達明，角笳競於邑。", "此時入骨寒，指墮膚亦裂。", "萬里不同天，江南正炎熱。"]'),
('18379060-8563-44a3-b4ce-23d4715d316d','李陵臺','汪元量','宋','宋诗','song-poetry','','[]','伊昔李少卿，築臺望漢月。',108,'全唐诗/poet.song.245000.json','["伊昔李少卿，築臺望漢月。", "月落淚縱橫，悽然腸斷裂。", "當時不受死，心懷歸漢闕。", "豈謂壯士身，中道有摧折。", "我行到寰州，悠然見突兀。", "下馬登斯臺，臺荒草如雪。", "妖氛靄冥濛，六合何恍惚。", "傷彼古豪雄，清淚泫不歇。", "吟君五言詩，朔風共嗚咽。"]'),
('f0565511-fbc3-41d1-963d-2c62a8738a18','蘇武洲氈房夜坐','汪元量','宋','宋诗','song-poetry','','[]','明發啟帳房，冷氣迸將入。',60,'全唐诗/poet.song.245000.json','["明發啟帳房，冷氣迸將入。", "饑鷹傍人飛，瘦馬對人立。", "禦寒挾貂裘，蒙頭帽氈笠。", "淒然絕火烟，陰雲壓身濕。", "頼有葡萄醅，借煖敵風急。"]'),
('69f41f75-de0b-4c4b-b3c9-affe3c8c3127','居延','汪元量','宋','宋诗','song-poetry','','[]','憶昔蘇子卿，持節入異域。',84,'全唐诗/poet.song.245000.json','["憶昔蘇子卿，持節入異域。", "淹留十九年，風霜毒顔色。", "嚙氈曾牧羝，跣足涉沙磧。", "日夕思漢君，恨不生羽翼。", "一朝天氣清，持節入漢國。", "胤子生別離，回視如塊礫。", "丈夫抱赤心，安肯淚沾臆。"]'),
('0c63fe95-d62a-4cc7-a8f8-9fcbd0894aab','昭君墓','汪元量','宋','宋诗','song-poetry','','[]','一昔王昭君，遠嫁單于去。',60,'全唐诗/poet.song.245000.json','["一昔王昭君，遠嫁單于去。", "上馬出宮門，琵琶語如訴。", "昔爲漢宮妃，今作胡虜婦。", "別來歲月深，竟入泉下路。", "還知身後名，青草覆孤墓。"]'),
('c2b9ff48-ad5e-4af0-965e-98139837252c','開平雪霽','汪元量','宋','宋诗','song-poetry','','[]','雪霽山崔嵬，平荒絕人跡。',96,'全唐诗/poet.song.245000.json','["雪霽山崔嵬，平荒絕人跡。", "獵獵大風寒，杳杳遠天碧。", "腐儒策蹇馿，覓句繞沙磧。", "一吟三徘徊，日卓人影直。", "孤鴻雲中來，對我聲嚦嚦。", "迺知晴天好，物類各有適。", "頃刻片雲生，雪花大如席。", "偉哉復偉哉，造物真戲劇。"]'),
('742b3df4-0152-4875-b322-5f28afdc024b','天山觀雪王昭儀相邀割駝肉','汪元量','宋','宋诗','song-poetry','','[]','北征已十年，抑鬰悲局促。',84,'全唐诗/poet.song.245000.json','["北征已十年，抑鬰悲局促。", "拄杖看天山，雪光皎如玉。", "滿目鸇鷹飛，晴天獵鴻鵠。", "羈人竈無炊，竟夕枵其腹。", "美人塞邊來，邀我分豆粥。", "手持并鐵刀，欣然割駝肉。", "勿誚草堂翁，一飽死亦足。"]'),
('2ed10d26-45db-4646-9832-cfcc16498d0d','草地','汪元量','宋','宋诗','song-poetry','','[]','齷齪復齷齪，昔聞今始見。',96,'全唐诗/poet.song.245000.json','["齷齪復齷齪，昔聞今始見。", "一月不梳頭，一月不洗面。", "饑則嚼乾糧，渴則啖雪片。", "困來卧氈房，重裘頗相戀。", "故衣連百結，蟣蝨似珠串。", "平明獵陰山，鷹犬逐人轉。", "呱呱凍欲僵，老娃淚如霰。", "忽有使臣來，宣賜尚方饍。"]'),
('202bb6c6-c8c1-46d1-90dc-954c402cc6df','開平','汪元量','宋','宋诗','song-poetry','','[]','冷霰撒行車，呻吟獨搔首。',84,'全唐诗/poet.song.245000.json','["冷霰撒行車，呻吟獨搔首。", "須臾大如席，風卷半空走。", "母子鼻酸辛，依依自相守。", "書生倒行囊，沽來一樽酒。", "暫時借溫和，耳熱豈長久。", "萬木舞陰風，言語冰在口。", "氈房耿無眠，兀兀聽刁斗。"]'),
('1e161abd-495c-4218-b23a-cbeb12534400','草地寒甚氈帳中讀杜詩','汪元量','宋','宋诗','song-poetry','','[]','少年讀杜詩，頗厭其枯槁。',120,'全唐诗/poet.song.245000.json','["少年讀杜詩，頗厭其枯槁。", "斯時熟讀之，始知句句好。", "書生挾蠹魚，流行萬里道。", "朱顔日以衰，玄髪日已老。", "耿耿不圓卿，寧方自爲皂。", "舉目無寸親，憂傷入懷抱。", "炎天冷如冰，磧地不生草。", "我馬跑沙石，我饑面蒼昊。", "人馬不相離，凍死俱未保。", "何當回白日，陰雲盡一掃。"]'),
('579be25a-8590-479e-a675-749e3cf5df1e','陰山觀獵和趙待制回文','汪元量','宋','宋诗','song-poetry','','[]','圍獵看人放海青，黑山峽口路交橫。',64,'全唐诗/poet.song.245000.json','["圍獵看人放海青，黑山峽口路交橫。", "飛鴻雨濕雲天遠，去馬風寒雪塞平。", "歸客北邊關柝擊，過軍西畔寨燈明。", "巍巍殿帳氈房煖，衣鐵冷深更鼓鳴。"]'),
('374e62a8-6529-40fc-b60e-2fc3013563ab','萬安殿夜直','汪元量','宋','宋诗','song-poetry','','[]','鳳銜紫詔下雲端，千載明良際會難。',64,'全唐诗/poet.song.245000.json','["鳳銜紫詔下雲端，千載明良際會難。", "金闕早朝天表近，玉堂夜直月光寒。", "宮衣屢賜恩榮重，御宴時開禮數寬。", "却憶玄都人去後，桃花零落倚闌干。"]'),
('bd1e40bd-c6a0-4c5f-a5b7-d91b6bc06887','送張舍人從軍','汪元量','宋','宋诗','song-poetry','','[]','大笑出門去，誰能筆硯囚。',48,'全唐诗/poet.song.245000.json','["大笑出門去，誰能筆硯囚。", "十年渾不調，萬里欲先侯。", "衰爾吾將老，飛揚子未休。", "他年身退遁，肯伴赤松游。"]'),
('56927b20-2c58-4da3-b82d-305c08985f3c','文山丞相丙子自京口脫去變姓名作清江劉洙今日相對得非夢耶','汪元量','宋','宋诗','song-poetry','','[]','昔年變姓走淮濱，虎豹從橫獨愴神。',64,'全唐诗/poet.song.245000.json','["昔年變姓走淮濱，虎豹從橫獨愴神。", "青海茫茫迷故國，黄塵黯黯泣孤臣。", "魏雎張祿夢中夢，越蠡陶朱身後身。", "今日相看論往事，劉洙元是姓文人。"]'),
('8470df90-223b-4abe-a3e6-2dccf8fedd9c','讀文山詩藁','汪元量','宋','宋诗','song-poetry','','[]','一朝禽瘴海，孤影落窮荒。',48,'全唐诗/poet.song.245000.json','["一朝禽瘴海，孤影落窮荒。", "恨極心難雪，愁濃鬢易霜。", "燕荆歌易水，蘇李泣河梁。", "讀到艱難際，梅花鐵石腸。"]'),
('63c43b52-da55-4348-bf48-a032a766624f','送張總管歸廣西','汪元量','宋','宋诗','song-poetry','','[]','燕玉成行把酒巵，酒巵未盡即言離。',64,'全唐诗/poet.song.245000.json','["燕玉成行把酒巵，酒巵未盡即言離。", "賓鴻冒雨回峰日，旅燕衝風過海時。", "棹撥蓼灣秋斫膾，劍飛梅嶺夜吟詩。", "明年有約重來否，一騎紅塵貢荔枝。"]'),
('244c0b47-493f-46a2-a20c-473c95e2ece4','易水','汪元量','宋','宋诗','song-poetry','','[]','蘆葦蕭森古渡頭，征鞍卸却上孤舟。',64,'全唐诗/poet.song.245000.json','["蘆葦蕭森古渡頭，征鞍卸却上孤舟。", "烟籠古木猿啼夜，月印平沙雁叫秋。", "砧杵遠聞添客淚，鼓鼙纔動起人愁。", "當年擊筑悲歌處，一片寒光凝不流。"]'),
('c3334e70-9f8b-48ec-b944-53215f9deb5e','北嶽降香呈嚴學士','汪元量','宋','宋诗','song-poetry','','[]','萬里溟濛起戰埃，翩翩勒馬出金臺。',64,'全唐诗/poet.song.245000.json','["萬里溟濛起戰埃，翩翩勒馬出金臺。", "同君遠使山頭去，如朕親行嶽頂來。", "野廟橫斜挨老樹，古碑顛倒枕荒苔。", "瞻天只有丹心在，香篆爐熏達九垓。"]'),
('a0f37773-3562-42bb-ad03-438f607c3725','太華峰','汪元量','宋','宋诗','song-poetry','','[]','華山山木亂紛紛，鐵鎖垂垂裊裊猿。',64,'全唐诗/poet.song.245000.json','["華山山木亂紛紛，鐵鎖垂垂裊裊猿。", "石齒齒前光爍爍，壁巖巖後勢奔奔。", "奇奇怪怪雲根聳，鬰鬰葱葱霧氣昏。", "上上上頭仍上上，最高高處有乾坤。"]'),
('e791ad5f-1b70-4a64-9e0e-411b7807fbf3','商山廟','汪元量','宋','宋诗','song-poetry','','[]','蹇柏枯松枕廟門，獨瞻遺像酹清尊。',64,'全唐诗/poet.song.245000.json','["蹇柏枯松枕廟門，獨瞻遺像酹清尊。", "紫芝奕奕浮香氣，碧草纖纖沒燒痕。", "羽翼已成猶有說，腹心相視更何言。", "高歌一曲歸來隠，靜看山禽哺子孫。"]'),
('a218b97d-16e8-4e6b-9f76-f14a8a2ceedc','孟津','汪元量','宋','宋诗','song-poetry','','[]','寒蘆風颯颯，時節近昏黄。',48,'全唐诗/poet.song.245000.json','["寒蘆風颯颯，時節近昏黄。", "木脫千山瘦，江空一水長。", "雲高鵬北運，天闊雁南翔。", "讀盡焚舟賦，持觴酹子桑。"]'),
('dfa72807-50f3-4b09-b489-6b8b9f23da0f','少室山','汪元量','宋','宋诗','song-poetry','','[]','巖巖路徑入空濛，中有幽人舊日宮。',64,'全唐诗/poet.song.245000.json','["巖巖路徑入空濛，中有幽人舊日宮。", "野草敗垣供暮雨，斷碑古木管秋風。", "山川融結千年秀，天地包籠一世雄。", "從此不須高索價，高名過眼總飄蓬。"]'),
('e558a63c-91aa-4cbc-8167-bcc7787a0932','天壇山','汪元量','宋','宋诗','song-poetry','','[]','我登天壇山，洒然清吟目。',96,'全唐诗/poet.song.245000.json','["我登天壇山，洒然清吟目。", "羣峰如兒孫，羅列三十六。", "支藤陟曾巔，中有少室屋。", "山人化飛仙，庭除生苜蓿。", "古碑野火燒，剝落字難讀。", "雛鹿卧幽巖，孤鳥響空谷。", "解鞍小遲留，偷閒半日足。", "長嘯歸去來，題詩紀幽獨。"]'),
('848592ce-1a73-4fd6-bec7-a40717ada6e0','阿房宮故基','汪元量','宋','宋诗','song-poetry','','[]','祖龍築長城，雄關百二所。',108,'全唐诗/poet.song.245000.json','["祖龍築長城，雄關百二所。", "阿房高接天，六國收歌女。", "跨海覓仙方，蓬萊眇何許。", "欲爲不死人，萬代秦宮主。", "風吹鮑魚腥，茲事竟虛語。", "乾坤反掌間，山河淚如雨。", "誰憐素車兒，奉璽納季父。", "楚人斬關來，一炬成焦土。", "空餘此餘基，千秋泣禾黍。"]'),
('4c01ac60-6f2f-4edd-9001-6c68313a2934','洛陽橋','汪元量','宋','宋诗','song-poetry','','[]','日西來到洛陽城，下馬橋邊信步行。',64,'全唐诗/poet.song.245000.json','["日西來到洛陽城，下馬橋邊信步行。", "紅紫已無花爛漫，青黄只有草從橫。", "風吹渭水秋砧急，月滿秦川夜柝清。", "我醉欲眠眠不得，更聽人唱楚歌聲。"]'),
('b86bd1b7-21f1-4967-a754-0810fa5d89cc','馬嵬坡','汪元量','宋','宋诗','song-poetry','','[]','霓裳驚破出宮門，馬上香羅拭淚痕。',32,'全唐诗/poet.song.245000.json','["霓裳驚破出宮門，馬上香羅拭淚痕。", "到此竟爲山下鬼，不堪鞞鼓似招魂。"]'),
('24cda720-c248-4a11-894e-041314bc72ff','北邙山','汪元量','宋','宋诗','song-poetry','','[]','芒芒北邙山，高墳盡無主。',24,'全唐诗/poet.song.245000.json','["芒芒北邙山，高墳盡無主。", "惟有石麒麟，相向立秋雨。"]'),
('d5e4d585-0d2b-46f6-a31f-92a3aee24188','天津橋','汪元量','宋','宋诗','song-poetry','','[]','白楊獵獵柳青青，怒浪高低不肯平。',32,'全唐诗/poet.song.245000.json','["白楊獵獵柳青青，怒浪高低不肯平。", "一自堯夫分手後，更無人聽杜鵑聲。"]'),
('4060e5ef-784b-41f3-987a-95dfd574d583','華清池','汪元量','宋','宋诗','song-poetry','','[]','一夜春寒事可知，海棠無地避風吹。',32,'全唐诗/poet.song.245000.json','["一夜春寒事可知，海棠無地避風吹。", "溫泉自向東流去，不管飛紅出禁池。"]'),
('480b4bed-b4dc-467b-92e2-bb7eadbce806','終南山館','汪元量','宋','宋诗','song-poetry','','["\u7ec8\u5357\u5c71"]','夜凉金氣轉淒其，正是羈孤不寐時。',64,'全唐诗/poet.song.245000.json','["夜凉金氣轉淒其，正是羈孤不寐時。", "千古傷心南渡曲，一襟清淚北征詩。", "霜凝鞞鼓星橫劍，風卷旌旗月滿巵。", "旅雁已離榆塞去，帛書摇曳過江遲。"]'),
('2a1c17a7-36fa-4f2d-addd-93bddde05469','函谷關','汪元量','宋','宋诗','song-poetry','','[]','西風吹我度函關，古壑泉聲靜自閒。',64,'全唐诗/poet.song.245000.json','["西風吹我度函關，古壑泉聲靜自閒。", "老子騎牛沙上去，仙人化鶴苑中還。", "斷崖木脫懸殘日，絕域雲橫失好山。", "舊說度關珠履客，一聲雞唱翠微間。"]'),
('d8d40b7f-8b4e-44e0-ab0a-1bf383667097','潼關','汪元量','宋','宋诗','song-poetry','','[]','蔽日烏雲撥不開，昏昏勒馬度關來。',64,'全唐诗/poet.song.245000.json','["蔽日烏雲撥不開，昏昏勒馬度關來。", "綠蕪逕路人千里，黄葉郵亭酒一杯。", "事去空垂悲國淚，愁來莫上望鄉臺。", "桃林塞外秋風起，大漠天寒鬼哭哀。"]'),
('7f5a2466-6ef9-49e4-be22-d0edb0efe1f2','秦嶺','汪元量','宋','宋诗','song-poetry','','[]','峻嶺登臨最上層，飛埃漠漠草稜稜。',64,'全唐诗/poet.song.245000.json','["峻嶺登臨最上層，飛埃漠漠草稜稜。", "百年世路多翻覆，千古河山幾廢興。", "紅樹青烟秦祖隴，黄茅白葦漢家陵。", "因思馬上昌黎伯，回首雲橫淚濕膺。"]'),
('560fc8a6-b722-4c90-aafe-686a03c7090e','藍田','汪元量','宋','宋诗','song-poetry','','[]','寒更客起卷花氈，又勒青驄過玉田。',64,'全唐诗/poet.song.245000.json','["寒更客起卷花氈，又勒青驄過玉田。", "一匊歸心千澗外，十分秋思兩峰前。", "藍關月冷猿啼木，秦嶺風高雁貼天。", "北望茂陵應咫尺，髑髏沙白草芊芊。"]'),
('7e1f54bd-390a-4da2-b837-4a1482942d34','嵩山  其一','汪元量','宋','宋诗','song-poetry','','[]','客行天地中，嵩峰何突兀。',108,'全唐诗/poet.song.245000.json','["客行天地中，嵩峰何突兀。", "鳥道阻且修，馬煩行復歇。", "一入玉女窗，便覺幽興發。", "好鳥鳴嚶嚶，細草亂如髪。", "石城蔭青松，瓊壁白噴雪。", "中有神聖居，飛甍半摧折。", "寶繪翳苔莓，古碑字亦滅。", "莫辯千載事，焉能踏仙轍。", "徒有感慨懷，脈脈淚不絕。"]'),
('35451307-4b2d-425c-87b5-88bcdd5cef1e','嵩山  其二','汪元量','宋','宋诗','song-poetry','','[]','行行太室峰，秋聲若鳴鏑。',72,'全唐诗/poet.song.245000.json','["行行太室峰，秋聲若鳴鏑。", "流目矚崎嶇，蓬萊應咫尺。", "上有神仙區，下有穆王宅。", "徘徊復徘徊，泫然感疇昔。", "八駿不重來，秋山空月白。", "安得會璆韶，共作瑶池客。"]'),
('4cdcadbd-e393-4b95-adc8-334580f41a6d','七月初七夜渡黄河','汪元量','宋','宋诗','song-poetry','','[]','長河界破東南天，怒濤日夜如奔川。',144,'全唐诗/poet.song.245000.json','["長河界破東南天，怒濤日夜如奔川。", "此行適逢七月夕，妖氛散作空中烟。", "牛郎織女涉清淺，支機石上今何年。", "揚帆一縱萬里目，身世恍若槎中仙。", "仰看銀河忽倒瀉，月明風露何娟娟。", "狂來拔劍斫河水，欲與祖逖爭雄鞭。", "扣舷把酒酹河伯，低頭細看河清漣。", "平生此懷具已久，到此欲說空回旋。", "嗟予不曉神靈意，咫尺雷雨心茫然。"]'),
('bce8c27c-0f49-4b5c-818f-c51747766118','汴都紀行','汪元量','宋','宋诗','song-poetry','','[]','尋僧入相國寺，領客過太師橋。',28,'全唐诗/poet.song.245000.json','["尋僧入相國寺，領客過太師橋。", "行到汴隄西畔，柳陰陰處魚跳。"]'),
('f5220f5b-0692-41b8-adf0-e286883cc419','夷山醉歌  其一','汪元量','宋','宋诗','song-poetry','','[]','楚狂醉歌歌正發，更上梁臺望明月。',252,'全唐诗/poet.song.245000.json','["楚狂醉歌歌正發，更上梁臺望明月。", "朔風獵獵吹我衣，絕代佳人皎如雪。", "搥羯鼓，彈箜篌，烹羊宰牛坐糟丘，一笑再笑揚清謳。", "遥看汴水波聲小，錦櫂忘還事多少。", "昨日金明池上來，艮嶽淒凉麋鹿遶。", "麥青青，黍離離，萬年枝上鴉亂啼。", "二龍北狩不復返，六龍南渡無還期。", "金銅淚迸露盤濕，畫闌桂柱酸風急。", "鳩居鵲構蒼隼入，蛇出燕巢白狐立。", "東南地陷妖氛黑，雙鳳高飛海南陌。", "吳山日落天沈沈，母子同行向天北。", "關河萬里雨露深，小儒何必悲苦辛。", "歸來耳熱忘頭白，買笑揮金莫相失。", "呼奚奴，吹觱篥，美人縱復橫，今夕復何夕。", "楚狂醉歌歌欲輟，老猿爲我啼竹裂。"]'),
('2e7e88ba-7e25-4a6d-acfc-86d682bc0bb7','夷山醉歌  其二','汪元量','宋','宋诗','song-poetry','','[]','嗚呼再歌兮花滿臺，好月爲我光徘徊。',312,'全唐诗/poet.song.245000.json','["嗚呼再歌兮花滿臺，好月爲我光徘徊。", "人生在世不滿百，紛華過眼皆成灰。", "夷山青青汴水綠，西北高樓咽絲竹。", "美人十指纖如玉，爲我行觴歌一曲。", "含宮嚼徵當窗牖，露脚斜飛濕楊柳。", "就中有客話陳橋，如此山河落人手。", "客且住，聽我語，楚漢中分兩丘土。", "七雄爭戰總塵埃，三國鶑花浩無主。", "咸陽宮殿不復都，華清池沼溫泉枯。", "世間興廢奔如電，滄海桑田幾回變。", "人生得意且盡歡，何須苦苦爲高官。", "人生有命且行樂，何必區區歎牢落。", "遮莫金章與玉珂，何如桐江披釣簑。", "遮莫貂蟬貴此身，何如柴桑漉酒巾。", "君不見海上看羊手持節，饑來和雪和氈囓。", "又不見飯顆山頭人見嗤，愁吟痛飲真吾師。", "美人美人勸我酒，有客有客聽我歌。", "須臾客醉美人睡，我亦不知天與地。", "嗚呼再歌兮無人聽，月自落兮酒未醒。"]'),
('24819796-da0d-45d0-9f27-c6cc238e2522','濟瀆','汪元量','宋','宋诗','song-poetry','','[]','玉簡投潭洞，金樽出石隈。',48,'全唐诗/poet.song.245000.json','["玉簡投潭洞，金樽出石隈。", "龍光蟠窟宅，蜃氣結樓臺。", "卷地風雷起，掀天雨雹來。", "人間爲濟瀆，水底即蓬萊。"]'),
('8766051f-7059-4eb6-96f3-39f4cd0e1dc1','孔子舊宅','汪元量','宋','宋诗','song-poetry','','[]','奉出天家一瓣香，著鞭東魯謁靈光。',64,'全唐诗/poet.song.245000.json','["奉出天家一瓣香，著鞭東魯謁靈光。", "堂堂聖像垂龍衮，濟濟賢生列雁行。", "屋壁詩書今絕響，衣冠人物只堪傷。", "可憐杏老空壇上，惟有寒鴉噪夕陽。"]'),
('dc2de381-3330-45d6-920e-2515985f810f','泰山','汪元量','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','敕使聯鑣上翠岑，飛泉躍澗吼雷音。',64,'全唐诗/poet.song.245000.json','["敕使聯鑣上翠岑，飛泉躍澗吼雷音。", "凌高一覽知天遠，迂曲千蹊覺洞深。", "龍蟄滄溟蛟舞壑，梟橫碧落鳳歸林。", "山靈護得神祠在，苔蝕秦碑古樹陰。"]'),
('27bcfbca-70d2-4469-b1ee-72b1b3fed3b6','降香回燕','汪元量','宋','宋诗','song-poetry','','[]','一從得玉旨，勒馬幽燕起。',24,'全唐诗/poet.song.245000.json','["一從得玉旨，勒馬幽燕起。", "河北與河南，一萬五千里。"]'),
('b7923bf7-e391-4f7b-b133-20388becd3d8','大元皇后游蓬萊島','汪元量','宋','宋诗','song-poetry','','[]','午夜紅雲滿太清，曉來王母下瑶京。',32,'全唐诗/poet.song.245000.json','["午夜紅雲滿太清，曉來王母下瑶京。", "日從萬歲山頭出，人在九重天上行。"]'),
('93071acb-1f1c-41cf-989b-d9c43d76304f','太皇謝太后挽章  其一','汪元量','宋','宋诗','song-poetry','','[]','羯鼓喧吳越，傷心國破時。',48,'全唐诗/poet.song.245000.json','["羯鼓喧吳越，傷心國破時。", "雨闌花灑淚，烟苑柳顰眉。", "事去千年速，愁來一死遲。", "舊臣相弔後，寒月墮燕支。"]'),
('a7c83f7a-f616-427d-affa-cb59ff7768cf','太皇謝太后挽章  其二','汪元量','宋','宋诗','song-poetry','','[]','大漠陰風起，羈孤血淚縣。',48,'全唐诗/poet.song.245000.json','["大漠陰風起，羈孤血淚縣。", "忽聞天下母，已赴月中仙。", "哀樂浮雲外，榮枯逝水前。", "遺書乞骸骨，歸葬越山邊。"]'),
('8bf52dd5-dfb6-4237-8355-ebfc5a7738de','青陽提刑哀些','汪元量','宋','宋诗','song-poetry','','["\u897f\u6e56"]','提刑辭宋國，奉使到燕都。',48,'全唐诗/poet.song.245000.json','["提刑辭宋國，奉使到燕都。", "入貢能全璧，懷歸不獻圖。", "看羊居北海，化鶴返西湖。", "楚客歌哀些，臨棺奠酒壺。"]'),
('8bc0ca6f-9df8-4f2f-a9a5-c2f0e430e685','女道士王昭儀仙游詞','汪元量','宋','宋诗','song-poetry','','[]','吳國生如夢，幽州死未寒。',48,'全唐诗/poet.song.245000.json','["吳國生如夢，幽州死未寒。", "金閨詩卷在，玉案道書閑。", "苦霧蒙丹旐，酸風射素棺。", "人間無葬地，海上有仙山。"]'),
('7760fa79-b8ad-475a-a780-d27fdaf8afb7','平原郡公趙福王挽章','汪元量','宋','宋诗','song-poetry','','[]','大王無起日，草木盡傷悲。',48,'全唐诗/poet.song.245000.json','["大王無起日，草木盡傷悲。", "生在太平世，死當離亂時。", "南冠流遠路，北面幸全屍。", "舊客行霜霰，呼天淚濕麾。"]'),
('e58c8e17-99c4-4b13-b7bb-bcc6ecc6d52a','文山道人事畢壬午臘月初九日','汪元量','宋','宋诗','song-poetry','','[]','崖山禽得到燕山，此老從容就義難。',64,'全唐诗/poet.song.245000.json','["崖山禽得到燕山，此老從容就義難。", "生愧夷齊尚周粟，死同巡遠只唐官。", "雪平絕塞魂何往，月滿通衢骨未寒。", "一劍固知公所欠，要留青史與人看。"]'),
('2971f437-0314-4e61-8211-2d6f36379dd7','瀛國公入西域爲僧號木波講師','汪元量','宋','宋诗','song-poetry','','[]','木老西天去，袈裟說梵文。',48,'全唐诗/poet.song.245000.json','["木老西天去，袈裟說梵文。", "生前從此別，去後不相聞。", "忍聽北方雁，愁看西域雲。", "永懷心未已，梁月白紛紛。"]'),
('f29cc90e-a78e-43f7-9175-7dd3889ed3e5','全太后爲尼','汪元量','宋','宋诗','song-poetry','','[]','南國舊王母，西方新世尊。',48,'全唐诗/poet.song.245000.json','["南國舊王母，西方新世尊。", "頭顱歸妙相，富貴悟空門。", "傳法優婆域，誦經孤獨園。", "夜闌清磬罷，趺坐雪花繁。"]'),
('b093d006-7f2f-4787-a21c-6b402307422c','幽州會飲','汪元量','宋','宋诗','song-poetry','','[]','客路相逢在異鄉，佐尊先得杜韋娘。',64,'全唐诗/poet.song.245000.json','["客路相逢在異鄉，佐尊先得杜韋娘。", "舞迴錦臂花爭豔，醉吸金波月鬬光。", "他日未忘今日樂，老年須記少年狂。", "五陵游俠休相笑，歸去奚奴有錦囊。"]'),
('1199cb21-213f-47c4-bf92-d4188b0d5cb9','余將南歸燕趙諸公子携妓把酒餞別醉中作把酒聽歌行  其一','汪元量','宋','宋诗','song-poetry','','[]','君把酒，聽我歌。',210,'全唐诗/poet.song.245000.json','["君把酒，聽我歌。", "君不見陌上桑，鶉奔奔兮鵲疆疆。", "高堂今夕燈燭光，燕姝趙女吹笙簧。", "君把酒，聽我歌。", "美人美人美如此，傾城傾國良有以。", "周惑褒姒烽火起，紂惑妲己賢人死。", "君把酒，聽我歌。", "漢家之亂呂太后，唐家之亂武則天。", "魏公銅臺化焦土，隋煬月殿成飛烟。", "君把酒，聽我歌。", "美人美人色可食，美人美人笑可愛。", "美人命薄爭奈何，美人色衰相棄背。", "美人一笑難再得，美人絕色今何在。", "君不見馬嵬坡下楊太真，天生尤物不足珍。", "那及唐虞九婦人，千古萬古名不湮。"]'),
('2b81e7ca-d107-42bc-b4b5-5404746acfe2','余將南歸燕趙諸公子携妓把酒餞別醉中作把酒聽歌行  其二','汪元量','宋','宋诗','song-poetry','','[]','我把酒，聽君歌。',257,'全唐诗/poet.song.245000.json','["我把酒，聽君歌。", "美人娟娟花灼灼，月照金樽光綽約。", "有酒有歌君亦愁，把酒聽歌君亦樂。", "我有鸚鵡杯，君有鸕鷀杓。", "一杯一杯復一杯，酒盡還沽共君酌。", "我把酒，聽君歌。", "天不荒，地不老，人生百年休草草。", "對花對酒且高歌，蓋世功名亦枯槁。", "滿堂金玉守者誰，萬事何如酒杯好。", "君不見巢父許由空洗耳，伯夷叔齊空餓死。", "范蠡扁舟挾西子，五湖風浪兼天起。", "又不見相如懷璧空歸來，廉頗善飯何壯哉。", "謝安携妓入東山，蒼生望望霖雨乾。", "把酒勸君飲，請君爲我歌。", "燕昭築臺金滿地，郭隗登臺多意氣。", "劉琨夢裏起聽雞，班超萬里封侯歸。", "君不見浣花溪頭老翁哭，白首爲儒守茅屋。"]'),
('b753ad7c-9d00-4e5a-b65a-501dfff70935','出自薊門行','汪元量','宋','宋诗','song-poetry','','[]','出自薊門行，行行望天北。',72,'全唐诗/poet.song.245000.json','["出自薊門行，行行望天北。", "何處愁殺人，黑風走沙石。", "華裾者誰子，意氣萬人敵。", "金鞍鞁白馬，奮飛虎生翼。", "書生爾何爲，不草相如檄。", "徒有經濟心，壯年已斑白。"]'),
('753dca4c-ecf2-43a8-80b6-ad78f0daea61','涿州','汪元量','宋','宋诗','song-poetry','','[]','瀘溝橋下水泠泠，落木無邊秋正清。',64,'全唐诗/poet.song.245000.json','["瀘溝橋下水泠泠，落木無邊秋正清。", "牛馬亂鋪黄帝野，鷹鸇高摩涿州城。", "柳亭日射旌旗影，花館風傳鼓吹聲。", "歸客偶然舒望眼，酒邊觸景又詩成。"]'),
('05eaf015-eba8-4b24-b654-2d1f478110a2','真定官舍','汪元量','宋','宋诗','song-poetry','','[]','使君數問夜如何，燈燭高張照綺羅。',64,'全唐诗/poet.song.245000.json','["使君數問夜如何，燈燭高張照綺羅。", "白酒千杯澆客醉，紅粧一面惱人多。", "風烟漠漠庭前樹，霜月娟娟沼內荷。", "驛吏出門相語及，城南便是滹沱河。"]'),
('01dc6f6b-295d-4c68-9634-022f3950c2a3','雲臺','汪元量','宋','宋诗','song-poetry','','[]','荒亭駐馬酌金罍，風卷黄埃丑上來。',32,'全唐诗/poet.song.245000.json','["荒亭駐馬酌金罍，風卷黄埃丑上來。", "滿地山河無漢業，趙州留得古雲臺。"]'),
('6860bc89-bde6-4209-9c73-7c4cc87db899','比干墓','汪元量','宋','宋诗','song-poetry','','[]','衛州三十里，荒墩草無數。',84,'全唐诗/poet.song.245000.json','["衛州三十里，荒墩草無數。", "忽聽路人言，此葬比干處。", "下馬拊石碑，三歎不能去。", "斐然成歌章，聊書墓頭樹。", "我弔比干心，不弔比干墓。", "世間賢與愚，同盡成黄土。", "斯人亦人爾，千千萬萬古。"]'),
('8cd943bd-74f0-4280-ae5a-1b395050e6ca','封丘','汪元量','宋','宋诗','song-poetry','','[]','今夜宿封丘，明朝過汴州。',48,'全唐诗/poet.song.245000.json','["今夜宿封丘，明朝過汴州。", "雲橫遮遠塞，水落見長洲。", "樹折棗初剝，藤枯瓜未收。", "傾囊沽一斗，聊以慰羈愁。"]'),
('e3ca6fba-85ea-4402-9c1c-99f16ea88c73','花石綱','汪元量','宋','宋诗','song-poetry','','[]','假山雖假總非真，未必中間可隠身。',32,'全唐诗/poet.song.245000.json','["假山雖假總非真，未必中間可隠身。", "若使此山身可隠，上皇不作遠行人。"]'),
('a2d24355-43e8-420e-81c3-e1628816cc53','揚州','汪元量','宋','宋诗','song-poetry','','[]','重到揚州十載餘，畫橋雨過月模糊。',64,'全唐诗/poet.song.245000.json','["重到揚州十載餘，畫橋雨過月模糊。", "后皇廟裏花何在，煬帝隄邊柳亦枯。", "陂麥青青嘶亂馬，城蕪冉冉落羣烏。", "人生聚散愁無盡，且小停鞭向酒罏。"]'),
('be5d245d-30d7-4fdd-9d3d-8f1aacf0b80b','金陵','汪元量','宋','宋诗','song-poetry','','[]','只見空城不見臺，客行搔首重徘徊。',64,'全唐诗/poet.song.245000.json','["只見空城不見臺，客行搔首重徘徊。", "風雲舊日龍南渡，宇宙新秋雁北來。", "三國衣冠同草莽，六朝宮殿總塵埃。", "交游相見休相問，把手江頭且一杯。"]'),
('3a42254d-ffec-4324-a245-33d5398497a1','鳳凰臺','汪元量','宋','宋诗','song-poetry','','[]','草沒高臺鳳不游，大江日夜自東流。',64,'全唐诗/poet.song.245000.json','["草沒高臺鳳不游，大江日夜自東流。", "齊梁地廢鴉千樹，王謝家空蟻一丘。", "騎馬僧爭淮口渡，捕魚人據石頭洲。", "玉簫聲斷悲風起，不見長安李白愁。"]'),
('64d06fae-7b56-40fc-9e65-9fffd8cafdb4','石頭城','汪元量','宋','宋诗','song-poetry','','[]','石頭城上小徘徊，世換僧殘寺已灰。',64,'全唐诗/poet.song.245000.json','["石頭城上小徘徊，世換僧殘寺已灰。", "地接汴淮山北去，江吞吳越水東來。", "健魚奮鬣隨蛟舞，快鶻翻身獵雁回。", "一片降旗千古淚，前人留與後人哀。"]'),
('9087490e-07db-4f35-bf4c-bf1c563dc395','采石','汪元量','宋','宋诗','song-poetry','','[]','夜泊青山下，江空不受塵。',24,'全唐诗/poet.song.245000.json','["夜泊青山下，江空不受塵。", "只看波底月，便是謫仙人。"]'),
('2608fc3c-93b5-471a-83d7-baf52f3eb77f','凌歊臺','汪元量','宋','宋诗','song-poetry','','[]','百尺凌歊事已非，古碑巖畔上苔衣。',64,'全唐诗/poet.song.245000.json','["百尺凌歊事已非，古碑巖畔上苔衣。", "禁園風暖草爭發，廢殿雨寒花亂飛。", "海北天高鵬得運，江南春盡雁知歸。", "三千歌舞今何處，惟有姑溪遶翠微。"]'),
('844ad6ce-90bf-4ba6-a963-6eb99c6affad','烏江','汪元量','宋','宋诗','song-poetry','','[]','平生英烈世無雙，漢騎飛來肯受降。',32,'全唐诗/poet.song.245000.json','["平生英烈世無雙，漢騎飛來肯受降。", "早與虞姬帳下死，不教戰血到烏江。"]'),
('ee2e5ec2-59c0-4b00-a198-2778cba3a9c7','魯港','汪元量','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','博徒無計解其紛，夜半鳴鉦潰萬軍。',64,'全唐诗/poet.song.245000.json','["博徒無計解其紛，夜半鳴鉦潰萬軍。", "魯港朔風掀惡浪，吳山寒日翳愁雲。", "周褒媚己終亡國，孟德欺孤忍負君。", "大木已顛天柱折，錢塘江上雁成羣。"]'),
('eb36266f-7fb9-4dc1-9467-970fbb054050','星子驛別客','汪元量','宋','宋诗','song-poetry','','[]','星江彼此繫行舟，我向南州君北州。',64,'全唐诗/poet.song.245000.json','["星江彼此繫行舟，我向南州君北州。", "彭澤初歸元亮醉，沙場遠使子卿愁。", "人生離合花間蝶，世事浮沉柳外鷗。", "明日沾襟各分手，相思何處倚高樓。"]'),
('3b219faa-b1d3-4d9f-8306-212045625123','豫章驛','汪元量','宋','宋诗','song-poetry','','[]','豫章門外盡青原，高閣臨江喜尚存。',64,'全唐诗/poet.song.245000.json','["豫章門外盡青原，高閣臨江喜尚存。", "鶑舌瀾翻嘲鶴靜，鷗心恬淡厭蛙喧。", "綠波淼淼投書渚，翠竹森森寫韻軒。", "約客不來人已遠，滿天風雨又黄昏。"]'),
('b8cdb9ec-f5dc-4c4b-8dad-8935dc5c92c1','臨川水驛','汪元量','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','羊角山高鎖戰塵，春風吹草綠孤城。',64,'全唐诗/poet.song.245000.json','["羊角山高鎖戰塵，春風吹草綠孤城。", "鵲巢遜與鳩夫婦，燕幙能容雁弟兄。", "今古廢興棋一著，萍蓬聚散酒三行。", "悲歌曲盡故人去，笛響長江月正明。"]'),
('577b4df3-a211-4b42-a038-3042e5d60462','歲暮過信州靈溪','汪元量','宋','宋诗','song-poetry','','[]','不彈長鋏歎無車，獨倚枯筇面碧虛。',64,'全唐诗/poet.song.245000.json','["不彈長鋏歎無車，獨倚枯筇面碧虛。", "兵破鄉村人住少，火燒橋道客行疏。", "雲低天闊鷹呼隼，水落溪喧獺趁魚。", "東騖西馳歸未得，明朝又是歲將除。"]'),
('fe1f336e-b61f-4e19-a67e-f96f9c8f557c','三衢官舍和王府教','汪元量','宋','宋诗','song-poetry','','[]','十年牢落走窮荒，萬里歸來行路長。',64,'全唐诗/poet.song.245000.json','["十年牢落走窮荒，萬里歸來行路長。", "坐上佳賓能鼓瑟，窗前細雨好燒香。", "武淹某澤常思漢，甫寓鄜州只念唐。", "秉燭相看真夢寐，夜闌無語意茫茫。"]'),
('7bf5e326-6ca8-4a1e-bff4-db8f6f17aa75','釣臺','汪元量','宋','宋诗','song-poetry','','[]','灘沙疊疊是潮痕，古木蒼然叫斷猿。',64,'全唐诗/poet.song.245000.json','["灘沙疊疊是潮痕，古木蒼然叫斷猿。", "此老不干天子貴，故人方訝布衣尊。", "雨甜春水魚龍動，風暖寒林鳥雀喧。", "我恰扁舟臺下過，桐花香處月黄昏。"]'),
('4f3d4571-64c3-4631-bfef-6c7d7649b5a1','錢塘','汪元量','宋','宋诗','song-poetry','','[]','躑躅吞聲淚暗傾，杖藜徐步浙江行。',64,'全唐诗/poet.song.245000.json','["躑躅吞聲淚暗傾，杖藜徐步浙江行。", "青蕪古路人烟絕，綠樹新墟鬼火明。", "事去玉環沈異域，愁來金盌出佳城。", "十年草木都糜爛，留得南枝照淺清。"]'),
('28ee7ebf-97aa-4e7f-ba5b-6f8254b7f858','浙江亭和徐雪江','汪元量','宋','宋诗','song-poetry','','[]','朱甍突兀倚雲寒，潮打孤城寂寞還。',64,'全唐诗/poet.song.245000.json','["朱甍突兀倚雲寒，潮打孤城寂寞還。", "荒草斷烟新驛路，夕陽古木舊江山。", "英雄聚散闌干外，今古興亡欸乃間。", "一曲尊前空擊劍，西風白髪淚斑斑。"]'),
('a6459170-50ce-4fba-b200-4d411d2dde49','答林石田見','汪元量','宋','宋诗','song-poetry','','[]','偶携降幟立詩壇，剪燭西窗共笑歡。',64,'全唐诗/poet.song.245000.json','["偶携降幟立詩壇，剪燭西窗共笑歡。", "落魄蘇秦今席煖，猖狂阮籍尚氈寒。", "山中客老干莖白，海上人歸一寸丹。", "世事本來愁不得，乾坤只好醉時看。"]'),
('b95f1cb7-7ec3-4420-b330-7a0287fa511a','孤山和李鶴田','汪元量','宋','宋诗','song-poetry','','[]','湖上悲風舞白楊，英雄凋盡只堪傷。',64,'全唐诗/poet.song.245000.json','["湖上悲風舞白楊，英雄凋盡只堪傷。", "花飛廢苑憐銅馬，草沒荒墳卧石羊。", "人在醉中春已晚，客於愁處日偏長。", "林西樓觀青紅濕，又遜僧官燕梵王。"]'),
('892adb77-fe91-49f6-9393-5abde91ab322','湖山堂','汪元量','宋','宋诗','song-poetry','','[]','高堂寂寞半開門，草沒頹牆竹滿園。',64,'全唐诗/poet.song.245000.json','["高堂寂寞半開門，草沒頹牆竹滿園。", "雨過湖天籠白晝，雲歸山市鎖黄昏。", "忘機今古鷗來往，說夢興亡燕語言。", "行盡六橋吟更好，萬松嶺上一聲猿。"]'),
('c9a02daa-5a93-40bd-b0c6-d2d9e9b34bcd','答徐雪江','汪元量','宋','宋诗','song-poetry','','[]','十載高居白玉堂，陳情一表乞還鄉。',64,'全唐诗/poet.song.245000.json','["十載高居白玉堂，陳情一表乞還鄉。", "孤雲落日渡遼水，匹馬西風上太行。", "行橐尚留官裏俸，賜衣猶带御前香。", "只今對客難爲答，千古中原話柄長。"]'),
('48fa91be-0533-4564-a405-1ca2973a0eef','歌樓感事','汪元量','宋','宋诗','song-poetry','','[]','昔年同輦載花仙，此日登樓籍妓員。',64,'全唐诗/poet.song.245000.json','["昔年同輦載花仙，此日登樓籍妓員。", "恩賜舞衣香未歇，御書歌扇墨猶鮮。", "碧雲翼翼金釵滑，紅雪翩翩玉珮圓。", "却把向來供奉曲，酒邊對客續朱絃。"]'),
('bad80895-5401-4388-9ffc-21f94da26543','九日次周義山','汪元量','宋','宋诗','song-poetry','','[]','杜陵清瘦不禁寒，白髪蕭蕭强笑歡。',64,'全唐诗/poet.song.245000.json','["杜陵清瘦不禁寒，白髪蕭蕭强笑歡。", "階下决明難獨立，庭前甘菊好誰看。", "一錢留得囊羞澀，九日沽來酒带酸。", "却憶大明朝謁罷，紫萸擎出賜千官。"]'),
('bd813051-a8c4-4114-9df8-24030d3b78da','寄李鶴田','汪元量','宋','宋诗','song-poetry','','["\u897f\u6e56"]','文江別後又三年，別後三年詩幾篇。',64,'全唐诗/poet.song.245000.json','["文江別後又三年，別後三年詩幾篇。", "老去莫思身外事，命窮甘作飲中仙。", "天陰雨溼龍歸海，雲淡風輕鶴在田。", "回首西湖湖上路，新蒲細柳爲誰妍。"]'),
('2480c06a-a4c6-4689-b709-061364c9a3fc','讀李鶴田錢塘百詠','汪元量','宋','宋诗','song-poetry','','[]','南浦亭邊話別時，扁舟東下浙江湄。',64,'全唐诗/poet.song.245000.json','["南浦亭邊話別時，扁舟東下浙江湄。", "徧將越國千年事，吟作錢塘百詠詩。", "無火可能燒莽卓，有刀恨不斬高斯。", "五陵佳氣飛揚盡，淚洒西風兩鬢絲。"]'),
('f5225902-ccbb-43e2-a7a0-7a117d682911','宮人爲尼','汪元量','宋','宋诗','song-poetry','','[]','白髪今如此，無依實可憐。',48,'全唐诗/poet.song.245000.json','["白髪今如此，無依實可憐。", "聖恩空舊想，佛相又新圓。", "鏡曉容顔別，鐘昏夢寐懸。", "百年心上事，懷古淚漣漣。"]'),
('f53095ae-3d33-41bf-a3e7-1ce5bf23af0f','重訪馬碧梧','汪元量','宋','宋诗','song-poetry','','[]','萬里遠行役，十年良可哀。',48,'全唐诗/poet.song.245000.json','["萬里遠行役，十年良可哀。", "前輩古風在，故人今雨來。", "絕口不言事，挽鬚惟把杯。", "種得碧梧樹，春風花自開。"]'),
('98087e5d-acfe-4532-abd1-a5237f438366','別章杭山','汪元量','宋','宋诗','song-poetry','','[]','抱琴曾北向，彈鋏復南圖。',48,'全唐诗/poet.song.245000.json','["抱琴曾北向，彈鋏復南圖。", "李泌游衡嶽，知章賜鑑湖。", "柱頭仙是鶴，濠上子非魚。", "此夜同聯鼎，他年莫寄書。"]'),
('53746907-a048-4eff-9d77-ed95b3a3a424','曾平山招飲','汪元量','宋','宋诗','song-poetry','','[]','老貌不隨俗，固窮而隠居。',48,'全唐诗/poet.song.245000.json','["老貌不隨俗，固窮而隠居。", "一塢百竿竹，八窗千卷書。", "酌以旋篘酒，薦之新網魚。", "興盡出門去，晚凉山雨餘。"]'),
('a89d6623-9df1-40b1-a307-ea168c955296','東湖送春和陳自堂','汪元量','宋','宋诗','song-poetry','','[]','十年南北競，故舊幾人存。',48,'全唐诗/poet.song.245000.json','["十年南北競，故舊幾人存。", "兵後誰知我，城中獨見君。", "東湖徐孺宅，北海孔融樽。", "宛轉留春意，吟詩到夜分。"]'),
('9801bad6-6625-4aaa-9496-2af53d65650f','南歸對客','汪元量','宋','宋诗','song-poetry','','[]','北行十三載，癡懶身羈孤。',240,'全唐诗/poet.song.245000.json','["北行十三載，癡懶身羈孤。", "勒馬向天山，咄咄空踟躕。", "窮陰六月內，白雪飛穹廬。", "冷氣刺骨髓，寒風割肌膚。", "饑餐棗與栗，渴飲酪與酥。", "棄置勿復言，言之則成迂。", "前年走河北，荆榛鬰丘墟。", "夜宿古戰場，鬼物聲嗚嗚。", "去年及淮南，黄塵翳行裾。", "長流漂白骨，滿目皆畏途。", "今年歸湖山，喬木依故居。", "堂前雙老親，粲粲色敷腴。", "壁間豈無琴，牀頭亦有書。", "友朋日過從，可嬉仍可娛。", "開軒耿晴色，梅花繞庭除。", "呼兒斫海鯨，新篘酒盈壺。", "偶爾得生還，相對真夢如。", "萬事一畫餠，百年捋髭鬚。", "向來誤儒冠，今也無壯圖。", "且願休王師，努力加飯蔬。"]'),
('5c67f618-4d2e-4cb8-bbc6-0bd9d916001a','湖州歌九十八首  其一','汪元量','宋','宋诗','song-poetry','','[]','丙子正月十有三，撾鞞伐鼓下江南。',32,'全唐诗/poet.song.245000.json','["丙子正月十有三，撾鞞伐鼓下江南。", "臯亭山上青烟起，宰執相看似醉酣。"]'),
('64aa3aeb-b4af-48ae-a0ab-6814a7233ac9','湖州歌九十八首  其二','汪元量','宋','宋诗','song-poetry','','[]','萬馬如雲在外間，玉階仙仗罷趨班。',32,'全唐诗/poet.song.245000.json','["萬馬如雲在外間，玉階仙仗罷趨班。", "三宮北面議方定，遣使臯亭慰伯顔。"]'),
('a604030c-38ea-4265-bb04-4c7af30be6a2','湖州歌九十八首  其三','汪元量','宋','宋诗','song-poetry','','[]','殿上羣臣默不言，伯顔丞相趣降箋。',32,'全唐诗/poet.song.245000.json','["殿上羣臣默不言，伯顔丞相趣降箋。", "三宮共在珠簾下，萬騎虬鬚遶殿前。"]'),
('08daa829-07f9-4134-8b8e-642c769520b0','湖州歌九十八首  其四','汪元量','宋','宋诗','song-poetry','','[]','謝了天恩出內門，駕前喝道上將軍。',32,'全唐诗/poet.song.245000.json','["謝了天恩出內門，駕前喝道上將軍。", "白旄黄鉞分行立，一點猩紅似幼君。"]'),
('4b7d3a88-80c8-459d-8bdd-b0097f99bafc','湖州歌九十八首  其五','汪元量','宋','宋诗','song-poetry','','[]','一匊吳山在眼中，樓臺纍纍間青紅。',32,'全唐诗/poet.song.245000.json','["一匊吳山在眼中，樓臺纍纍間青紅。", "錦颿後夜烟江上，手抱琵琶憶故宮。"]'),
('028c034b-7b5f-49aa-8e6f-6df233155ec2','湖州歌九十八首  其六','汪元量','宋','宋诗','song-poetry','','["\u63cf\u5199\u6c34", "\u611f\u53f9", "\u6000\u53e4", "\u6c34", "\u5199\u6c34"]','北望燕雲不盡頭，大江東去水悠悠。',32,'全唐诗/poet.song.245000.json','["北望燕雲不盡頭，大江東去水悠悠。", "夕陽一片寒鴉外，目斷東西四百州。"]'),
('370fae53-618f-4f24-8852-b6e12b0a9448','湖州歌九十八首  其七','汪元量','宋','宋诗','song-poetry','','[]','十數年來國事乖，大臣無計逐時挨。',32,'全唐诗/poet.song.245000.json','["十數年來國事乖，大臣無計逐時挨。", "三宮今日燕山去，春草萋萋上玉階。"]'),
('8913e98b-becd-4f59-966b-de7c462eda3b','湖州歌九十八首  其八','汪元量','宋','宋诗','song-poetry','','[]','錦颿高揭繡簾開，鼉鼓聲悲鳳管哀。',32,'全唐诗/poet.song.245000.json','["錦颿高揭繡簾開，鼉鼓聲悲鳳管哀。", "月子纖纖雲裏見，吳江不盡暮潮來。"]'),
('5a03b0e6-4398-4850-90b8-01b189342457','湖州歌九十八首  其九','汪元量','宋','宋诗','song-poetry','','[]','一出宮門上畫船，紅紅白白艷神仙。',32,'全唐诗/poet.song.245000.json','["一出宮門上畫船，紅紅白白艷神仙。", "山長水遠愁無那，又見江南月上弦。"]'),
('b1c62950-32c4-4e84-a499-6d4e97d88a5c','湖州歌九十八首  其一○','汪元量','宋','宋诗','song-poetry','','["\u592a\u6e56"]','太湖風起浪頭高，錦柁摇摇坐不牢。',32,'全唐诗/poet.song.245000.json','["太湖風起浪頭高，錦柁摇摇坐不牢。", "靠著篷窗垂兩目，船頭船尾爛弓刀。"]'),
('3dea043b-db15-4c76-914a-33af052d58f6','湖州歌九十八首  其一一','汪元量','宋','宋诗','song-poetry','','[]','昨夜三更淚濕腮，伍胥何事夢中來。',32,'全唐诗/poet.song.245000.json','["昨夜三更淚濕腮，伍胥何事夢中來。", "三宮從此相分別，自勒潮頭白馬迴。"]'),
('f0e601a5-d5b1-4a44-9843-cee0b8a4384f','湖州歌九十八首  其一二','汪元量','宋','宋诗','song-poetry','','[]','受降城下草離離，寒食清明只自悲。',32,'全唐诗/poet.song.245000.json','["受降城下草離離，寒食清明只自悲。", "漢寢秦陵何處在，鶑花無主雨如絲。"]'),
('1b88db93-e20d-43db-a6ec-c04d54963c7c','湖州歌九十八首  其一三','汪元量','宋','宋诗','song-poetry','','[]','金陵昨夜有降書，更說揚州一戰輸。',32,'全唐诗/poet.song.245000.json','["金陵昨夜有降書，更說揚州一戰輸。", "淮北淮南清未了，又添軍馬下東吳。"]'),
('589721ec-4b55-43f6-902b-816ca5f85ad5','湖州歌九十八首  其一四','汪元量','宋','宋诗','song-poetry','','[]','鐵甕城頭馬亂嘶，金陵城下砲如飛。',32,'全唐诗/poet.song.245000.json','["鐵甕城頭馬亂嘶，金陵城下砲如飛。", "黑風捲地鼓鼙急，昨夜常州又受圍。"]'),
('a87b2c0e-f15a-4e88-ae6a-442d3d602b78','湖州歌九十八首  其一五','汪元量','宋','宋诗','song-poetry','','[]','曉來宮櫂去如飛，掠削鬟雲淺畫眉。',32,'全唐诗/poet.song.245000.json','["曉來宮櫂去如飛，掠削鬟雲淺畫眉。", "風雨淒淒能自遣，三三五五坐彈棋。"]'),
('b99cb8cd-5eee-4bb0-b6f7-51057b7d7b00','湖州歌九十八首  其一六','汪元量','宋','宋诗','song-poetry','','[]','暮雨瀟瀟酒力微，江頭楊柳正依依。',32,'全唐诗/poet.song.245000.json','["暮雨瀟瀟酒力微，江頭楊柳正依依。", "宮娥抱膝船窗坐，紅淚千行濕繡衣。"]'),
('b2b83aeb-abb0-458b-a778-21bfb45febfa','湖州歌九十八首  其一七','汪元量','宋','宋诗','song-poetry','','[]','曉鬢鬅鬆懶不梳，忽聽人說是南徐。',32,'全唐诗/poet.song.245000.json','["曉鬢鬅鬆懶不梳，忽聽人說是南徐。", "手中明鏡拋船上，半揭篷窗看打魚。"]'),
('9a69a6e1-70e9-4013-be14-ebf5ab8bb1a4','湖州歌九十八首  其一八','汪元量','宋','宋诗','song-poetry','','[]','京口沿河賣酒家，東邊楊柳北邊花。',32,'全唐诗/poet.song.245000.json','["京口沿河賣酒家，東邊楊柳北邊花。", "柳摇花謝人分散，一向天涯一海涯。"]'),
('f10c545e-9709-409c-b3e6-4910ae16665c','湖州歌九十八首  其一九','汪元量','宋','宋诗','song-poetry','','[]','滿船明月夜鳴榔，船上宮人燒夜香。',32,'全唐诗/poet.song.245000.json','["滿船明月夜鳴榔，船上宮人燒夜香。", "好是燒香得神力，片帆穩送到漁陽。"]'),
('f7d260db-72bc-488b-96e0-3ccc5b1e98eb','湖州歌九十八首  其二○','汪元量','宋','宋诗','song-poetry','','[]','一片淮山落照中，開船忽遇打頭風。',32,'全唐诗/poet.song.245000.json','["一片淮山落照中，開船忽遇打頭風。", "行軍元帥傳言語，別撥官軍下浙東。"]'),
('5d6adc67-d7d7-46b1-8a48-67270839fe5f','湖州歌九十八首  其二一','汪元量','宋','宋诗','song-poetry','','[]','揚子江頭潮退遲，三宮船傍釣魚磯。',32,'全唐诗/poet.song.245000.json','["揚子江頭潮退遲，三宮船傍釣魚磯。", "須臾風定過江去，不奈林間杜宇啼。"]'),
('a83e9890-5a06-4cf4-a296-1b5325af82d7','湖州歌九十八首  其二二','汪元量','宋','宋诗','song-poetry','','[]','一半淮江半浙江，怒潮日夜自相撞。',32,'全唐诗/poet.song.245000.json','["一半淮江半浙江，怒潮日夜自相撞。", "揚州昨夜軍書至，說道淮安未肯降。"]'),
('27006d2e-379b-477f-bd59-49290df5b349','湖州歌九十八首  其二三','汪元量','宋','宋诗','song-poetry','','[]','曉來潮信暫相留，滿耳驚濤愁復愁。',32,'全唐诗/poet.song.245000.json','["曉來潮信暫相留，滿耳驚濤愁復愁。", "月殿不知何處在，錦帆摇曳到揚州。"]'),
('5cfc910c-fe82-4380-a503-7406e6d88054','湖州歌九十八首  其二四','汪元量','宋','宋诗','song-poetry','','["\u897f\u6e56"]','金屋煌煌麗九天，朝歌夜舞艷神仙。',32,'全唐诗/poet.song.245000.json','["金屋煌煌麗九天，朝歌夜舞艷神仙。", "尋常只道西湖好，不識淮南是極邊。"]'),
('796cd6bf-1268-4e97-a2ad-c9ae79b10570','湖州歌九十八首  其二五','汪元量','宋','宋诗','song-poetry','','[]','風雨聲中聽櫂歌，山炰野饌奈愁何。',32,'全唐诗/poet.song.245000.json','["風雨聲中聽櫂歌，山炰野饌奈愁何。", "雪花淮白甜如蜜，不減江珧滋味多。"]'),
('fce94792-c7c3-4a23-946c-574d9c5c384d','湖州歌九十八首  其二六','汪元量','宋','宋诗','song-poetry','','[]','九出瓊花一夜開，無雙亭曲小徘徊。',32,'全唐诗/poet.song.245000.json','["九出瓊花一夜開，無雙亭曲小徘徊。", "可憐后土空祠宇，望斷韋郎不見來。"]'),
('282f1ebb-5f2e-4acc-85c1-f0a3f84f6539','湖州歌九十八首  其二七','汪元量','宋','宋诗','song-poetry','','[]','兩淮戰鼓不停撾，萬騎精兵賽夜叉。',32,'全唐诗/poet.song.245000.json','["兩淮戰鼓不停撾，萬騎精兵賽夜叉。", "破陣焚舟彈指頃，漢人猶悞夏爺爺。"]'),
('d7b2795f-6970-4916-9e61-83842de91872','湖州歌九十八首  其二八','汪元量','宋','宋诗','song-poetry','','[]','官軍兩岸護龍舟，麥飯魚羹進不休。',32,'全唐诗/poet.song.245000.json','["官軍兩岸護龍舟，麥飯魚羹進不休。", "宮女垂頭空作惡，暗拋珠淚落船頭。"]'),
('b34af252-e06a-433a-91c8-2fad4bbd748a','湖州歌九十八首  其二九','汪元量','宋','宋诗','song-poetry','','[]','都人不識有干戈，羅綺叢中樂事多。',32,'全唐诗/poet.song.245000.json','["都人不識有干戈，羅綺叢中樂事多。", "一夜月明天漠漠，漢人歌罷楚人歌。"]'),
('de72fb6a-5266-4ddc-be92-631f8ff7eb20','湖州歌九十八首  其三○','汪元量','宋','宋诗','song-poetry','','["\u897f\u6e56"]','太皇太后過江都，遥指淮山似畫圖。',32,'全唐诗/poet.song.245000.json','["太皇太后過江都，遥指淮山似畫圖。", "拋却故家風雨外，夜來歸夢繞西湖。"]'),
('69cef2a5-d804-4e1e-bdb7-ae607eee677f','湖州歌九十八首  其三一','汪元量','宋','宋诗','song-poetry','','[]','萬騎橫江泣鼓鞞，千枝畫角一行吹。',32,'全唐诗/poet.song.245000.json','["萬騎橫江泣鼓鞞，千枝畫角一行吹。", "淮南今夜好明月，船上美人空淚垂。"]'),
('10227ca7-45bc-4bcb-a00e-40a056d54bb3','湖州歌九十八首  其三二','汪元量','宋','宋诗','song-poetry','','[]','蘆荻颼颼風亂吹，戰場白骨暴沙泥。',32,'全唐诗/poet.song.245000.json','["蘆荻颼颼風亂吹，戰場白骨暴沙泥。", "淮南兵後人烟絕，新鬼啾啾舊鬼啼。"]'),
('fed65f9b-7788-4c34-a4da-aff0498fdef4','湖州歌九十八首  其三三','汪元量','宋','宋诗','song-poetry','','[]','不堪回首淚盈盈，萬里淮河聽雨聲。',32,'全唐诗/poet.song.245000.json','["不堪回首淚盈盈，萬里淮河聽雨聲。", "莫問萍虀併豆粥，且餐麥飯與魚羹。"]'),
('1a2b5360-4139-4fde-94b2-7dde70d1c860','湖州歌九十八首  其三四','汪元量','宋','宋诗','song-poetry','','[]','宰執連鑣向北行，淮南夜夜鬼燈青。',32,'全唐诗/poet.song.245000.json','["宰執連鑣向北行，淮南夜夜鬼燈青。", "雖然適意無南北，生死難逃篩下星。"]'),
('f0c8349a-12e6-45bc-95fd-6ca9452d8ca0','湖州歌九十八首  其三五','汪元量','宋','宋诗','song-poetry','','[]','更闌炙燭繡簷遮，卸却金鈿與翠花。',32,'全唐诗/poet.song.245000.json','["更闌炙燭繡簷遮，卸却金鈿與翠花。", "心似亂絲眠不得，江樓中夜咽悲笳。"]'),
('a6d96f23-0915-494a-8590-6e31672dad2c','湖州歌九十八首  其三六','汪元量','宋','宋诗','song-poetry','','[]','兩淮極目草芊芊，野渡灰餘屋數椽。',32,'全唐诗/poet.song.245000.json','["兩淮極目草芊芊，野渡灰餘屋數椽。", "兵馬渡江人走盡，民船拘斂作官船。"]'),
('155c743c-7d6d-4714-8a0c-19c9425cbd51','湖州歌九十八首  其三七','汪元量','宋','宋诗','song-poetry','','[]','宮人清夜按瑶琴，不識明妃出塞心。',32,'全唐诗/poet.song.245000.json','["宮人清夜按瑶琴，不識明妃出塞心。", "十八拍中無限恨，轉絃又奏廣陵音。"]'),
('5e9125e7-a0dc-48b5-8ea0-dc98f6193039','湖州歌九十八首  其三八','汪元量','宋','宋诗','song-poetry','','[]','青天澹澹月荒荒，兩岸淮田盡戰場。',32,'全唐诗/poet.song.245000.json','["青天澹澹月荒荒，兩岸淮田盡戰場。", "宮女不眠開眼坐，更聽人唱哭襄陽。"]'),
('6042b479-b402-462b-83bf-6ba444cbf07a','湖州歌九十八首  其三九','汪元量','宋','宋诗','song-poetry','','[]','翠鬟半嚲倦梳粧，楊柳風前陣陣凉。',32,'全唐诗/poet.song.245000.json','["翠鬟半嚲倦梳粧，楊柳風前陣陣凉。", "絃索懶拈縮纖手，龍涎猶嚼口脂香。"]'),
('8071b89c-ae7b-4fa1-b671-d3e1a85bf6bc','湖州歌九十八首  其四○','汪元量','宋','宋诗','song-poetry','','[]','鳳管龍笙處處吹，都民欣樂太平時。',32,'全唐诗/poet.song.245000.json','["鳳管龍笙處處吹，都民欣樂太平時。", "宮娥不識興亡事，猶唱宣和御製詞。"]'),
('f1b12887-d1fb-4ac4-9077-047ccf49bb9f','湖州歌九十八首  其四一','汪元量','宋','宋诗','song-poetry','','[]','可憐河畔草青青，錦纜牽江且緩行。',32,'全唐诗/poet.song.245000.json','["可憐河畔草青青，錦纜牽江且緩行。", "愛此淮南山水好，問天乞得片時晴。"]'),
('06b97b5b-7459-4c50-9089-861f00df5cd3','湖州歌九十八首  其四二','汪元量','宋','宋诗','song-poetry','','[]','丞相催人急放舟，舟中兒女淚交流。',32,'全唐诗/poet.song.245000.json','["丞相催人急放舟，舟中兒女淚交流。", "淮南漸遠波聲小，猶見揚州望火樓。"]'),
('ece0b51c-451d-486d-8b26-34a2d8cdefd5','湖州歌九十八首  其四三','汪元量','宋','宋诗','song-poetry','','[]','撥盡琵琶意欲悲，新愁舊夢兩依依。',32,'全唐诗/poet.song.245000.json','["撥盡琵琶意欲悲，新愁舊夢兩依依。", "江樓吹笛三更後，細雨燈前醉玉妃。"]'),
('a9ba462d-647c-491c-85fe-91eb183cc2fc','湖州歌九十八首  其四四','汪元量','宋','宋诗','song-poetry','','[]','篷窗倚坐酒微酣，淮水無波似蔚藍。',32,'全唐诗/poet.song.245000.json','["篷窗倚坐酒微酣，淮水無波似蔚藍。", "雙櫓咿啞摇不住，望中猶自是江南。"]'),
('76f1112a-b6f1-4892-92bb-f5a6cf2949fb','湖州歌九十八首  其四五','汪元量','宋','宋诗','song-poetry','','[]','銷金帳下忽天明，夢裏無情亦有情。',32,'全唐诗/poet.song.245000.json','["銷金帳下忽天明，夢裏無情亦有情。", "何處亂山可埋骨，暫時相對坐調笙。"]'),
('eb2c02fb-b30e-4392-bbd7-51a54ad4b707','湖州歌九十八首  其四六','汪元量','宋','宋诗','song-poetry','','[]','宮人夜泊近人家，瞥見紅榴三四丫。',32,'全唐诗/poet.song.245000.json','["宮人夜泊近人家，瞥見紅榴三四丫。", "猶說初離行在所，玉闌無數牡丹花。"]'),
